-- Poems batch 351
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c31b018f-3e68-4f1f-abe5-70874f0b8219','展畫亭','鄒浩','宋','宋诗','song-poetry','','[]','丹青一筆妙難窺，萬古長如初畫時。',64,'全唐诗/poet.song.70000.json','["丹青一筆妙難窺，萬古長如初畫時。", "濃淡乾坤偏掩映，卷舒雲霧巧追隨。", "深藏塵表天元愛，不到炎方世豈知。", "展出高亭快人目，捨君風韻更誰爲。"]'),
('6ba0fd16-7a96-491e-9a24-526077cb025b','小舟枕上','鄒浩','宋','宋诗','song-poetry','','[]','船頭鑚入北來風，繼日連宵閉短篷。',32,'全唐诗/poet.song.70000.json','["船頭鑚入北來風，繼日連宵閉短篷。", "多少峰巒多少意，一齊收在枕屏中。"]'),
('a1f2fb5d-e253-4f11-a035-527c4a3dbf31','登碧巖寺盧舍那瑞像閣  其一','鄒浩','宋','宋诗','song-poetry','','[]','樓閣門開處處通，毗盧出現眼光中。',32,'全唐诗/poet.song.70000.json','["樓閣門開處處通，毗盧出現眼光中。", "爲人重說二愚品，巖下灘聲西北風。"]'),
('d18468f2-3cad-4a11-be7b-04207025ba30','登碧巖寺盧舍那瑞像閣  其二','鄒浩','宋','宋诗','song-poetry','','[]','我自南方稽首回，大千經卷出塵埃。',32,'全唐诗/poet.song.70000.json','["我自南方稽首回，大千經卷出塵埃。", "十方三世都圓了，盧舍那尊金色開。"]'),
('ad71fc99-de46-47cf-ac69-7360c2805f28','登碧巖寺盧舍那瑞像閣  其三','鄒浩','宋','宋诗','song-poetry','','[]','我住蓮華法界中，塵塵刹刹本來同。',32,'全唐诗/poet.song.70000.json','["我住蓮華法界中，塵塵刹刹本來同。", "旃檀一瓣聊興供，吹滿巖前萬竅風。"]'),
('8782b32e-dc9f-4f22-b90f-6020d3dbcbd8','與夢立行入長安虚  其一','鄒浩','宋','宋诗','song-poetry','','[]','恰到長安風色晴，一條石徑坦然平。',32,'全唐诗/poet.song.70000.json','["恰到長安風色晴，一條石徑坦然平。", "與君曳杖尋虚去，全似仙宮嶺下行。"]'),
('fcc9ca74-9bed-42fe-ba2b-dccdfd6de0ef','與夢立行入長安虚  其二','鄒浩','宋','宋诗','song-poetry','','[]','久不上船思上船，偶然縱步是長安。',32,'全唐诗/poet.song.70000.json','["久不上船思上船，偶然縱步是長安。", "何須更望君平卜，但把虚名子細看。"]'),
('81fb5491-71ac-4ac0-aaf8-1bcf3b455448','斗米灘','鄒浩','宋','宋诗','song-poetry','','[]','粥飯都來一斗糧，灘前喫了倍蒼黄。',32,'全唐诗/poet.song.70000.json','["粥飯都來一斗糧，灘前喫了倍蒼黄。", "把如立作山頭石，何似急行歸故鄉。"]'),
('1e69fa77-63c1-493b-bcb0-fdec9769d0ef','捍門山','鄒浩','宋','宋诗','song-poetry','','[]','揚子江頭舟楫回，海門山對潤州開。',32,'全唐诗/poet.song.70000.json','["揚子江頭舟楫回，海門山對潤州開。", "故鄉歸去六千里，先入捍門山裏來。"]'),
('1e8101cc-2223-43fd-8911-2a540ae4fcad','過雉山  其一','鄒浩','宋','宋诗','song-poetry','','[]','客睡當年託雉山，杜鵑聲切枕難安。',32,'全唐诗/poet.song.70000.json','["客睡當年託雉山，杜鵑聲切枕難安。", "今朝歸向山頭過，不見杜鵑空夢殘。"]'),
('2ada2074-27d8-41c4-82cf-cfe45fbf6e04','過雉山  其二','鄒浩','宋','宋诗','song-poetry','','[]','苾蒭曾向定中觀，謂我南遷使可還。',32,'全唐诗/poet.song.70000.json','["苾蒭曾向定中觀，謂我南遷使可還。", "過了三年方語驗，聊將一笑謝禪關。"]'),
('7c6533c4-23e9-4def-b463-24456cb57475','示壽寧長老如曉  其一','鄒浩','宋','宋诗','song-poetry','','[]','十二年中獨自春，應緣還現壽寧身。',32,'全唐诗/poet.song.70000.json','["十二年中獨自春，應緣還現壽寧身。", "南方衲子聞知否，便是黄龍舊主人。"]'),
('6e8d5a9c-e326-47e1-8698-71b23550ab9f','示壽寧長老如曉  其二','鄒浩','宋','宋诗','song-poetry','','[]','三關誰復識黄龍，大施門開振祖風。',32,'全唐诗/poet.song.70000.json','["三關誰復識黄龍，大施門開振祖風。", "無限人天無限眼，一齊回向嶺雲中。"]'),
('7185c6ad-53d4-402f-9abf-0c748e913091','示壽寧長老如曉  其三','鄒浩','宋','宋诗','song-poetry','','[]','師在興安我在昭，幾年相望但雲霄。',32,'全唐诗/poet.song.70000.json','["師在興安我在昭，幾年相望但雲霄。", "誰知小出忽大遇，共折青柴带葉燒。"]'),
('3b0ec53b-b570-4fe0-ad86-f330298ce913','示崇寧長老善資  其一','鄒浩','宋','宋诗','song-poetry','','[]','五色雲中有和煙，天長地久祝斯年。',32,'全唐诗/poet.song.70000.json','["五色雲中有和煙，天長地久祝斯年。", "太平一曲憑師唱，響徹乾坤萬古傳。"]'),
('29a098a5-8c83-43ca-94c2-cf9b6117b680','示崇寧長老善資  其二','鄒浩','宋','宋诗','song-poetry','','[]','獨秀峰前是寶坊，坐令熱惱變清凉。',32,'全唐诗/poet.song.70000.json','["獨秀峰前是寶坊，坐令熱惱變清凉。", "人人認得長安路，珍重旃檀一瓣香。"]'),
('683c5720-93e8-439f-bd66-7d89d0df5a4e','與葉適正資長老同宿覺華山安福寺','鄒浩','宋','宋诗','song-poetry','','[]','覺華山下古禪宮，鼎足蒲團午夜同。',64,'全唐诗/poet.song.70000.json','["覺華山下古禪宮，鼎足蒲團午夜同。", "但有鷄聲替鐘鼓，更無僧影到簾櫳。", "真情迥出忘情外，多語都歸妙語中。", "轉首是誰南與北，庭前檜柏亦生風。"]'),
('0c858885-222a-4600-bdc5-c1c81a0bf61e','夜登台光亭示主人莫亢','鄒浩','宋','宋诗','song-poetry','','[]','亭據炎方第一州，旌旗曾向此中留。',64,'全唐诗/poet.song.70000.json','["亭據炎方第一州，旌旗曾向此中留。", "台光不逐春光改，花影長隨桂影浮。", "誰謂嶺雲收白雨，偶然莎徑入青眸。", "它年南北遙相望，應記匆匆秉燭遊。"]'),
('38d33995-64c4-4158-9db7-3ab1254fd7fd','留别興安唐叟元老推官  其一','鄒浩','宋','宋诗','song-poetry','','[]','天繪亭邊三載夢，石灰鋪裏一時情。',32,'全唐诗/poet.song.70000.json','["天繪亭邊三載夢，石灰鋪裏一時情。", "箇中不是同參得，胸次峥嶸何日平。"]'),
('2441d214-cd00-49e3-9df6-e433c0a1d83d','留别興安唐叟元老推官  其二','鄒浩','宋','宋诗','song-poetry','','[]','風前火烈逢真玉，雪後大寒見老松。',32,'全唐诗/poet.song.70000.json','["風前火烈逢真玉，雪後大寒見老松。", "携得此心歸北去，與君無處不相逢。"]'),
('92ce5500-b9e6-4efd-b8d1-46e872e56228','留别興安唐叟元老推官  其三','鄒浩','宋','宋诗','song-poetry','','[]','幽居不許穿雲到，寶閣仍忘破曉登。',32,'全唐诗/poet.song.70000.json','["幽居不許穿雲到，寶閣仍忘破曉登。", "多少從來疑着處，一齊分付打包僧。"]'),
('e52552d7-bb93-40c8-bcd5-4c739706652c','留别龍城山主懷義  其一','鄒浩','宋','宋诗','song-poetry','','[]','陽朔千山復萬山，最深山處是松關。',32,'全唐诗/poet.song.70000.json','["陽朔千山復萬山，最深山處是松關。", "新詩吟罷無餘事，一片真心雲共閒。"]'),
('706ff0f2-3cf7-4392-b798-b34d30f40fcf','留别龍城山主懷義  其二','鄒浩','宋','宋诗','song-poetry','','[]','仙閣龍城一望間，每來過我不如還。',32,'全唐诗/poet.song.70000.json','["仙閣龍城一望間，每來過我不如還。", "汀鷗猶集欄干外，應怪從今氣象閒。"]'),
('43c9455c-258e-43c2-a057-f16b5e5d260b','留别龍城山主懷義  其三','鄒浩','宋','宋诗','song-poetry','','[]','好事如師豈易逢，不辭趼足訪行蹤。',32,'全唐诗/poet.song.70000.json','["好事如師豈易逢，不辭趼足訪行蹤。", "揮殘麈尾知難再，目斷碧蓮峰外峰。"]'),
('c2e50777-9709-4310-b540-4f6b43407f1e','留别龍城山主懷義  其四','鄒浩','宋','宋诗','song-poetry','','[]','青天無礙本來同，休向江邊動别容。',32,'全唐诗/poet.song.70000.json','["青天無礙本來同，休向江邊動别容。", "師似碧潭吾似月，東西南北總相逢。"]'),
('911f62d9-f1e2-421e-924f-782aaa769c06','留别龍城山主懷義  其五','鄒浩','宋','宋诗','song-poetry','','[]','三車黄葉止兒啼，一句何人妙得知。',32,'全唐诗/poet.song.70000.json','["三車黄葉止兒啼，一句何人妙得知。", "今日爲師重說破，滿軒風静月明時。"]'),
('4bba25f1-5adf-4e5d-b707-0fa650b63eee','寄巡鋪温{是爲}侍禁乃杲之弟也','鄒浩','宋','宋诗','song-poetry','','[]','幾日長亭復短亭，霜梅夾路喜相迎。',64,'全唐诗/poet.song.70000.json','["幾日長亭復短亭，霜梅夾路喜相迎。", "風光總屬君家管，霽色偏隨馬足生。", "老酒盈杯誰款曲，少陵佳句謾分明。", "回頭安福前山曉，八桂蒼蒼無限情。"]'),
('db45ea22-8831-4770-96c9-ce6cdf46df2d','山行示同遊','鄒浩','宋','宋诗','song-poetry','','[]','碧雲堆裏共徜徉，莫厭捫天带夕陽。',32,'全唐诗/poet.song.70000.json','["碧雲堆裏共徜徉，莫厭捫天带夕陽。", "遊徧桂州巖穴後，更無閒夢到南方。"]'),
('6c743ad4-b7a9-4740-9664-a7da9e2eabda','東山  其一','鄒浩','宋','宋诗','song-poetry','','[]','我是來仙閣上仙，天教飛鶴過山顛。',32,'全唐诗/poet.song.70000.json','["我是來仙閣上仙，天教飛鶴過山顛。", "松篁爲我生清韻，一似薫風初入絃。"]'),
('dd48be94-6591-4f3b-ab64-246e1fcc17f5','東山  其二','鄒浩','宋','宋诗','song-poetry','','[]','七星峰頂絕纖埃，不負烟霞雙眼開。',32,'全唐诗/poet.song.70000.json','["七星峰頂絕纖埃，不負烟霞雙眼開。", "昨日湘南遙指處，飛騰今向此中來。"]'),
('440e3556-3e5d-45b4-93df-32a22d188741','寄題妙峰閣慧照堂','鄒浩','宋','宋诗','song-poetry','','[]','妙峰閣外雲收翳，慧照堂中日放光。',32,'全唐诗/poet.song.70000.json','["妙峰閣外雲收翳，慧照堂中日放光。", "大地山河都見了，此心聊寄一罏香。"]'),
('e6c49013-2ce6-4593-8845-a9f4f8a10c06','葉筠元禮留飲  其一','鄒浩','宋','宋诗','song-poetry','','[]','天造移居漢水湄，嶺邊欣與故人期。',32,'全唐诗/poet.song.70000.json','["天造移居漢水湄，嶺邊欣與故人期。", "紅燈暖照金波動，全勝來仙閣上時。"]'),
('5f9bd456-1d36-41c1-a110-473c093adf04','葉筠元禮留飲  其二','鄒浩','宋','宋诗','song-poetry','','[]','殷勤留我共清樽，無限情懷子細論。',32,'全唐诗/poet.song.70000.json','["殷勤留我共清樽，無限情懷子細論。", "天色亦如人意好，晚來星斗滿前軒。"]'),
('89c05bd3-34e4-4e81-931d-85780d32483c','寓壽寧方丈州人求識面繼來焚香作禮戲呈曉老','鄒浩','宋','宋诗','song-poetry','','[]','維摩丈室一張床，暫寄清宵夢幾場。',32,'全唐诗/poet.song.70000.json','["維摩丈室一張床，暫寄清宵夢幾場。", "却被閒人作禪看，競來合掌要焚香。"]'),
('6239eab3-2c0e-4250-ad93-fc5f53780564','戲靈川令王洵仁仲','鄒浩','宋','宋诗','song-poetry','','[]','長官貪着祖師禪，有甚心情問我船。',32,'全唐诗/poet.song.70000.json','["長官貪着祖師禪，有甚心情問我船。", "一隻逃歸兩隻破，謾凭江檻望靈川。"]'),
('1fbab60c-b72a-476b-952e-845922153f97','示仁仲  其一','鄒浩','宋','宋诗','song-poetry','','[]','槎頭一别十經年，月照黄茅夢不圓。',32,'全唐诗/poet.song.70000.json','["槎頭一别十經年，月照黄茅夢不圓。", "今日北歸恩賜與，相逢如在四禪天。"]'),
('7e84f3a9-29d3-41ba-b8b5-6505bb6088c6','示仁仲  其二','鄒浩','宋','宋诗','song-poetry','','[]','一根燒筍共分甘，彷彿當年漢水南。',32,'全唐诗/poet.song.70000.json','["一根燒筍共分甘，彷彿當年漢水南。", "紅柿鳥殘無此意，前三三與後三三。"]'),
('fdcb6bf6-9833-48a2-b546-e93a58cd0c44','次韻和仁仲滑石鋪泉軒','鄒浩','宋','宋诗','song-poetry','','[]','長官心事古人前，碧玉峰巒碧玉泉。',32,'全唐诗/poet.song.70000.json','["長官心事古人前，碧玉峰巒碧玉泉。", "洗出北歸烟瘴眼，光明欣睹太平年。"]'),
('49536f5b-6874-49d9-9172-43779022adf7','假寐靈川報恩寺','鄒浩','宋','宋诗','song-poetry','','[]','故人猶在驛亭邊，暫向雲房借榻眠。',32,'全唐诗/poet.song.70000.json','["故人猶在驛亭邊，暫向雲房借榻眠。", "漏泄祖師多少意，松聲都到小窗前。"]'),
('742572c3-cc28-497e-9ac5-eedaa260a9d7','示舂陵顧林宗','鄒浩','宋','宋诗','song-poetry','','[]','宼公樓下釣魚船，横絕晴波已七年。',32,'全唐诗/poet.song.70000.json','["宼公樓下釣魚船，横絕晴波已七年。", "邂逅蓮宮論往事，恍疑同在夜摩天。"]'),
('52a2e94a-8a2c-4d35-b789-41c8c6a7d785','見魯直題陶商翁碑後有感','鄒浩','宋','宋诗','song-poetry','','[]','石上猶新墨，忘情亦嘆嗟。',48,'全唐诗/poet.song.70000.json','["石上猶新墨，忘情亦嘆嗟。", "殊恩但歸骨，冷迹尚平沙。", "願力消塵垢，瞻依盛寶花。", "人間幾行淚，空洒玉川家。"]'),
('dcf28d2e-9d3c-40ec-b672-2935a470bfce','入湖南界  其一','鄒浩','宋','宋诗','song-poetry','','[]','踏着湖南境界新，展開天宇浄無塵。',32,'全唐诗/poet.song.70000.json','["踏着湖南境界新，展開天宇浄無塵。", "增添喜色知多少，滿眼雪峰如故人。"]'),
('ee113357-e8ef-459f-b20a-60da82efa70e','入湖南界  其二','鄒浩','宋','宋诗','song-poetry','','[]','北風吹滿亂山雲，山頂皚皚色尚新。',32,'全唐诗/poet.song.70000.json','["北風吹滿亂山雲，山頂皚皚色尚新。", "怪得幾朝寒暝日，元來留雪迓歸輪。"]'),
('ea3829a1-35ae-4077-ab4a-64b83f604572','入湖南界  其三','鄒浩','宋','宋诗','song-poetry','','[]','一自瀟湘見雪飛，炎氛遮眼暗漁磯。',32,'全唐诗/poet.song.70000.json','["一自瀟湘見雪飛，炎氛遮眼暗漁磯。", "今朝纔入湖南界，便睹玉光生翠微。"]'),
('c5898d0a-6678-4094-89cc-b50eeb0bb6b0','入湖南界  其四','鄒浩','宋','宋诗','song-poetry','','[]','北風吹面過如冰，也勝南風瘴水濱。',32,'全唐诗/poet.song.70000.json','["北風吹面過如冰，也勝南風瘴水濱。", "莫向知亭嫌太冷，主人元是鐵心人。"]'),
('28dc55cf-0e5a-419c-a287-cbd0e6af08db','入湖南界  其五','鄒浩','宋','宋诗','song-poetry','','[]','薄薄陰雲淡淡天，北風迎路徹重綿。',32,'全唐诗/poet.song.70000.json','["薄薄陰雲淡淡天，北風迎路徹重綿。", "從教捲起轎簾子，吹盡幾年嵐瘴烟。"]'),
('7078e33b-ec45-4da1-bd82-aab33bf5f0e3','入湖南界  其六','鄒浩','宋','宋诗','song-poetry','','[]','重重叠叠擁遙峰，總在輕烟薄霧中。',32,'全唐诗/poet.song.70000.json','["重重叠叠擁遙峰，總在輕烟薄霧中。", "疑是李成初畫了，生綃千幅掛晴空。"]'),
('e6dc4a2c-b24b-4a0d-adf8-c67bcf77abb6','入湖南界  其七','鄒浩','宋','宋诗','song-poetry','','[]','淡描深拂百千般，終日擡頭不厭觀。',32,'全唐诗/poet.song.70000.json','["淡描深拂百千般，終日擡頭不厭觀。", "造物始初誰與様，定應曾得古圖看。"]'),
('372c7a72-b47e-4f8a-b08c-f6965fdaa5eb','入湖南界  其八','鄒浩','宋','宋诗','song-poetry','','[]','一等乾坤一等山，纔分湖嶺便多般。',32,'全唐诗/poet.song.70000.json','["一等乾坤一等山，纔分湖嶺便多般。", "何如洗盡昏昏瘴，都作晴天萬仞寒。"]'),
('045249ce-0361-4efa-86ff-62fe6fa353a9','入湖南界  其九','鄒浩','宋','宋诗','song-poetry','','[]','折得梅枝插轎簾，路人驚怪簇巉巖。',32,'全唐诗/poet.song.70000.json','["折得梅枝插轎簾，路人驚怪簇巉巖。", "從教大擔擔將去，深入三家村裏談。"]'),
('ad021fc3-428a-43e8-8cd4-a3a03b90beca','入湖南界  其一○','鄒浩','宋','宋诗','song-poetry','','[]','短簫長笛鼓鼕鼕，簇紙爲船棹晚風。',32,'全唐诗/poet.song.70000.json','["短簫長笛鼓鼕鼕，簇紙爲船棹晚風。", "送了鬼神無一事，大家贏得醉顔紅。"]'),
('6ba239be-2201-4e18-99a8-6881b6af53b0','入湖南界  其一一','鄒浩','宋','宋诗','song-poetry','','[]','雞未鳴時整客衣，行行只恐日斜暉。',32,'全唐诗/poet.song.70000.json','["雞未鳴時整客衣，行行只恐日斜暉。", "米塘過了全州近，恰遇村人趁市歸。"]'),
('3c88bdf1-d18b-4d38-b1ea-e05335fefeff','入湖南界  其一二','鄒浩','宋','宋诗','song-poetry','','[]','赤脚蠻中新出來，湖南逢着盡銀釵。',32,'全唐诗/poet.song.70000.json','["赤脚蠻中新出來，湖南逢着盡銀釵。", "雖然未得凌波様，已會人人着草鞋。"]'),
('feaf55a3-439f-4d06-9cc0-64a973cef604','示崇寧長老允和','鄒浩','宋','宋诗','song-poetry','','[]','安心得髓遇昇平，不似雲門不解行。',32,'全唐诗/poet.song.70000.json','["安心得髓遇昇平，不似雲門不解行。", "聊與祖師分半座，湘山頂上放光明。"]'),
('0f62e37b-21cd-43ce-bd2e-23dd98b006a5','示澄庵庵主炳著  其一','鄒浩','宋','宋诗','song-poetry','','[]','又向全州現此身，澄庵猶是舊時人。',32,'全唐诗/poet.song.70000.json','["又向全州現此身，澄庵猶是舊時人。", "相逢休說途中事，且點茶來吃一巡。"]'),
('947e7e35-393d-412b-82dc-ceec0cd54143','示澄庵庵主炳著  其二','鄒浩','宋','宋诗','song-poetry','','[]','澄來澄去不知年，一片澄光月様圓。',32,'全唐诗/poet.song.70000.json','["澄來澄去不知年，一片澄光月様圓。", "照破十方三世黑，大家同集世尊前。"]'),
('80409735-a357-48cb-b4cb-9340dc9ce9d8','示澄庵庵主炳著  其三','鄒浩','宋','宋诗','song-poetry','','[]','不肯南來伴我閒，若來何法可心安。',32,'全唐诗/poet.song.70000.json','["不肯南來伴我閒，若來何法可心安。", "直饒參得齡鐵觜，也被昭州烟瘴漫。"]'),
('31bfb6d4-86a1-4bde-b92b-80b36e0a6749','示張道人','鄒浩','宋','宋诗','song-poetry','','[]','幾年龍虎自相隨，南斗延生恩賜歸。',32,'全唐诗/poet.song.70000.json','["幾年龍虎自相隨，南斗延生恩賜歸。", "霄漢路通鸞鶴在，不妨高躡紫雲飛。"]'),
('bf86240b-acbd-4b81-9eaf-710fdf9b4c0a','妙高亭','鄒浩','宋','宋诗','song-poetry','','[]','四望山頭老比丘，笑他思大浪經由。',64,'全唐诗/poet.song.70000.json','["四望山頭老比丘，笑他思大浪經由。", "巧將三十三天好，都向青雲青處收。", "金翅遠投雲際歇，銀河低遶砌邊流。", "高高更有堪行路，騎取溈山水牯牛。"]'),
('d7f98a48-42dc-479b-a382-f32b8d1fbad1','六一巖','鄒浩','宋','宋诗','song-poetry','','[]','造物有所待，巉巖從此通。',48,'全唐诗/poet.song.70000.json','["造物有所待，巉巖從此通。", "千峰豁前障，萬象欻來同。", "滌覽進江水，嘯晴生虎風。", "誰知不朽事，成在笑談中。"]'),
('f6b14b3f-87c5-4863-83b1-dbce60f3456a','喜長老永文方自外歸','鄒浩','宋','宋诗','song-poetry','','[]','荆棘叢中自在人，不知何處是埃塵。',32,'全唐诗/poet.song.70000.json','["荆棘叢中自在人，不知何處是埃塵。", "巖前逢着笑絕倒，也似炎荒金色身。"]'),
('f415f9ac-ed1a-4bcc-907b-90a79007a120','文長老云山有訓狐鳴即客至夜來鳴更異常','鄒浩','宋','宋诗','song-poetry','','[]','我入山來亦偶然，初無消息與人傳。',32,'全唐诗/poet.song.70000.json','["我入山來亦偶然，初無消息與人傳。", "訓狐緣底潛知得，隔夜飛鳴報老禪。"]'),
('4dad07fe-dcb0-4206-a74d-680902af2b23','自淡山過暗巖','鄒浩','宋','宋诗','song-poetry','','[]','淡中有味味真味，暗裏有明明更明。',32,'全唐诗/poet.song.70000.json','["淡中有味味真味，暗裏有明明更明。", "不是同來三大士，有誰能識此時情。"]'),
('0639c19e-580e-4496-adcc-77272d1934d1','觀真珠花留戲陳瑩中','鄒浩','宋','宋诗','song-poetry','','[]','古觀無人花自開，真珠顆顆映莓苔。',32,'全唐诗/poet.song.70000.json','["古觀無人花自開，真珠顆顆映莓苔。", "留教合浦居士看，何似海邊新蚌胎。"]'),
('e2745dd2-15e2-4afe-a8b5-b5b8ee070425','示法輪長老景齊','鄒浩','宋','宋诗','song-poetry','','[]','問碑碑已化爲塵，却得同生庚子人。',64,'全唐诗/poet.song.70000.json','["問碑碑已化爲塵，却得同生庚子人。", "聊把此心論此事，頗疑前日是前身。", "雲間岣嶁峰回禮，庭下娑羅花獻春。", "更欲縱横見端的，夜來飛雨洗金輪。"]'),
('35f250a2-563a-4eab-bc2c-09b60cf64f5f','示雲谿長老文慶','鄒浩','宋','宋诗','song-poetry','','[]','與師應有緣，相見便欣然。',48,'全唐诗/poet.song.70000.json','["與師應有緣，相見便欣然。", "徑出牧牛室，共捫垂雨天。", "一真誰境界，萬物自山川。", "放手無餘事，歸來汨碖眠。"]'),
('c79ee796-1f3e-4ba9-a414-80fc5bd72f06','示方廣長老從譽','鄒浩','宋','宋诗','song-poetry','','[]','五百阿師何處來，天堂初不隔天台。',64,'全唐诗/poet.song.70000.json','["五百阿師何處來，天堂初不隔天台。", "靈泉飛作人間雨，法鼓騰爲山下雷。", "對現此身誰彷彿，上方重閣正崔嵬。", "只應永刦觀空眼，總向峰前歡喜開。"]'),
('6bedf9b1-4b98-4da4-b06a-45f798f16a4a','題譽老無住閣','鄒浩','宋','宋诗','song-poetry','','[]','不二門開刹海中，十方世界本來同。',64,'全唐诗/poet.song.70000.json','["不二門開刹海中，十方世界本來同。", "四威儀竟無所着，千手眼應如是通。", "彌勒當年曾示現，善才於此悉參同。", "而今我亦逢師處，聊擊欄杆問祖風。"]'),
('6bef6e7b-1271-41a5-b582-a77a872a92d4','自方廣冒雨過高臺示德瀾長老','鄒浩','宋','宋诗','song-poetry','','[]','雲烟猶暝曉，杖屨已高臺。',48,'全唐诗/poet.song.70000.json','["雲烟猶暝曉，杖屨已高臺。", "眼向不危去，景從無外來。", "巧將新水墨，洒出舊塵埃。", "携得還天北，晴時闊展開。"]'),
('82c07fdd-a5f0-4f28-b89b-2c47faff753a','定林長老首座自合浦來以此示之','鄒浩','宋','宋诗','song-poetry','','[]','已入高樓見彌勒，却尋舊路禮文殊。',32,'全唐诗/poet.song.70000.json','["已入高樓見彌勒，却尋舊路禮文殊。", "誰知垢膩衲衣內，總是摩尼無價珠。"]'),
('1994b07d-0bab-42db-8b90-4255c641cab7','示萬壽長老道琮','鄒浩','宋','宋诗','song-poetry','','[]','萬壽閣中逢故人，萬年松下偶穿雲。',32,'全唐诗/poet.song.70000.json','["萬壽閣中逢故人，萬年松下偶穿雲。", "憑將五分真香爇，長對南山祝聖君。"]'),
('13e07e56-3528-4920-8d1f-099b708e06da','示衡嶽寺善果庵道成庵主','鄒浩','宋','宋诗','song-poetry','','[]','遊了諸山問了禪，却來庵裏坐安然。',32,'全唐诗/poet.song.70000.json','["遊了諸山問了禪，却來庵裏坐安然。", "何如一瓣焚香去，飛作祥雲徧九天。"]'),
('e159effc-ab38-4ac7-9ea6-4d76548a379b','示勝業寺長老有餘  其一','鄒浩','宋','宋诗','song-poetry','','[]','韶陽一曲有誰知，拍手相逢笑幾時。',32,'全唐诗/poet.song.70000.json','["韶陽一曲有誰知，拍手相逢笑幾時。", "偶向悅亭杉外立，元來傳在最高枝。"]'),
('2af70a45-691d-4a18-b19f-3f3378ce749b','示勝業寺長老有餘  其二','鄒浩','宋','宋诗','song-poetry','','[]','八桂蒼蒼湘水南，師鄉我客飽曾諳。',32,'全唐诗/poet.song.70000.json','["八桂蒼蒼湘水南，師鄉我客飽曾諳。", "五年不見今年見，猶得寒爐一夜談。"]'),
('7fbbbc41-e1c3-4599-ac74-412149c1f1d6','過洞庭風作','鄒浩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭波面忽如雷，萬斛樓船舞一桮。',32,'全唐诗/poet.song.70000.json','["洞庭波面忽如雷，萬斛樓船舞一桮。", "爲報馮夷莫相嚇，儘曾經着暴風來。"]'),
('f49c8207-d55a-4b60-8a39-98f8c7a93cd9','次韻答八十三外翁見招','鄒浩','宋','宋诗','song-poetry','','[]','乃翁心事别，璧月到寒塘。',48,'全唐诗/poet.song.70000.json','["乃翁心事别，璧月到寒塘。", "欹枕三竿日，横經一炷香。", "尚思同燕麈，還欲對胡床。", "行矣拏舟去，金鐘亦自將。"]'),
('81d9fe91-9d39-4045-852c-4c51eefb74b0','招俞清老并簡康遠禪師  其一','鄒浩','宋','宋诗','song-poetry','','[]','腰錢騎鶴上揚州，妄想空來事事休。',32,'全唐诗/poet.song.70000.json','["腰錢騎鶴上揚州，妄想空來事事休。", "惟有三竿風月在，待君同理釣魚舟。"]'),
('8821a984-0b8f-4cf3-bbca-3209d39fc13d','招俞清老并簡康遠禪師  其二','鄒浩','宋','宋诗','song-poetry','','[]','欲知何處是生緣，問取維摩室內天。',32,'全唐诗/poet.song.70000.json','["欲知何處是生緣，問取維摩室內天。", "渠若口鉗無答語，竹西堅卧許安全。"]'),
('76699170-bb7c-4d04-ba87-b41ae8dcd0ad','招俞清老并簡康遠禪師  其三','鄒浩','宋','宋诗','song-poetry','','[]','石塔迢迢兩閏餘，潛知骨痩奪松枯。',32,'全唐诗/poet.song.70000.json','["石塔迢迢兩閏餘，潛知骨痩奪松枯。", "煩君爲把公憑判，同過江來伴老夫。"]'),
('e7d0159b-778b-4cae-b74e-103c1766eb83','詩送晦叔先生  其一','鄒浩','宋','宋诗','song-poetry','','[]','先生带花六十年，青春不老花長妍。',32,'全唐诗/poet.song.70000.json','["先生带花六十年，青春不老花長妍。", "金盃停手便索去，一片閒雲飛上天。"]'),
('5b7cbd72-8aa5-4639-ac0d-032c14fa9beb','詩送晦叔先生  其二','鄒浩','宋','宋诗','song-poetry','','[]','知是初平幾代孫，雙携日月弄乾坤。',32,'全唐诗/poet.song.70000.json','["知是初平幾代孫，雙携日月弄乾坤。", "人間有眼誰窺得，笑出常州西郭門。"]'),
('7b12f25d-5ca4-40a8-bc02-1ccc5a1e3844','詩送晦叔先生  其三','鄒浩','宋','宋诗','song-poetry','','[]','疾卧幾爲萬鬼鄰，金丹一粒遇高真。',32,'全唐诗/poet.song.70000.json','["疾卧幾爲萬鬼鄰，金丹一粒遇高真。", "此身從此無他事，長作昇平擊壤人。"]'),
('94c73431-ce98-44d2-bdf0-69b35b88f36d','詩送晦叔先生  其四','鄒浩','宋','宋诗','song-poetry','','[]','一别相逢復幾時，東西南北酒盈巵。',32,'全唐诗/poet.song.70000.json','["一别相逢復幾時，東西南北酒盈巵。", "天機深遠猶須决，莫便飛騰不我期。"]'),
('0dee25f9-b5db-49a5-9072-ff8a21083a9a','詩送晦叔先生  其五','鄒浩','宋','宋诗','song-poetry','','[]','萬里來歸荷聖恩，焚香趺坐欲無言。',32,'全唐诗/poet.song.70000.json','["萬里來歸荷聖恩，焚香趺坐欲無言。", "羣仙若問誰堪度，爲說冥心到本元。"]'),
('9730017f-47a2-4dca-a662-808d0c886b20','寄和庵主','鄒浩','宋','宋诗','song-poetry','','[]','自從衡嶽得高風，南北東西久未逢。',32,'全唐诗/poet.song.70000.json','["自從衡嶽得高風，南北東西久未逢。", "惟有旃檀知此意，爲傳消息到中峰。"]'),
('7e2811b4-5e56-41aa-a21e-ecc6a9e65dbe','簡俞子恭','鄒浩','宋','宋诗','song-poetry','','[]','東郭名園步可過，病餘猶以路爲多。',32,'全唐诗/poet.song.70000.json','["東郭名園步可過，病餘猶以路爲多。", "何當略彴通新徑，日日從君擊壤歌。"]'),
('bc775a69-f7ee-42e3-963b-998b2e6930be','戲簡錢濟明  其一','鄒浩','宋','宋诗','song-poetry','','[]','雨雪相仍勢未休，禦寒惟酒勝重裘。',32,'全唐诗/poet.song.70000.json','["雨雪相仍勢未休，禦寒惟酒勝重裘。", "誰知旱久猶乾涸，不見玉泉東向流。"]'),
('b3f2aeb7-e29e-4381-838f-40f662ee33f4','戲簡錢濟明  其二','鄒浩','宋','宋诗','song-poetry','','[]','載酒無如君最頻，年來緣底斷音塵。',32,'全唐诗/poet.song.70000.json','["載酒無如君最頻，年來緣底斷音塵。", "只應咫尺譙門住，也學兵厨不送人。"]'),
('e68f8a10-d07b-420d-b14e-6c4bfe9f923c','就舜諧覓石','鄒浩','宋','宋诗','song-poetry','','[]','數峰寂寂卧蒼苔，醉眼何曾略爲開。',32,'全唐诗/poet.song.70000.json','["數峰寂寂卧蒼苔，醉眼何曾略爲開。", "乞與茅簷淡相對，要令雲雨出山來。"]'),
('769cc5e2-425c-4061-9fdf-f7410f644e54','智岸將往錢塘索妙樂庵詩勉此爲句','鄒浩','宋','宋诗','song-poetry','','[]','向來楊處士，今作岸禪師。',48,'全唐诗/poet.song.70000.json','["向來楊處士，今作岸禪師。", "懶散元非我，熙怡竟有誰。", "長應心似水，不復口如碑。", "此處真安穩，何人妙得知。"]'),
('7aa0010c-135d-4253-9064-3053762cea9d','呈明遠','鄒浩','宋','宋诗','song-poetry','','[]','爾來無酒可沾唇，只恐傍人怪獨醒。',32,'全唐诗/poet.song.70000.json','["爾來無酒可沾唇，只恐傍人怪獨醒。", "自笑金龜已當了，惠然誰復遣銀瓶。"]'),
('2fd8445c-9e70-4b2c-bb33-ec6913b52962','樞姪以詩來次韻示之','鄒浩','宋','宋诗','song-poetry','','[]','酷愛日長螢可聚，幾人如古惜分陰。',32,'全唐诗/poet.song.70000.json','["酷愛日長螢可聚，幾人如古惜分陰。", "胸中萬頃清涼地，莫遣俗塵乘間侵。"]'),
('e247288a-ca78-4573-9e13-2923264e482a','讀書','鄒浩','宋','宋诗','song-poetry','','[]','誰能也學讀書痴，園圃三年忘了窺。',32,'全唐诗/poet.song.70000.json','["誰能也學讀書痴，園圃三年忘了窺。", "却恐主人如泄柳，謾攜藜杖去何之。"]'),
('ebb5547b-a03b-457d-8eaf-d861634bc641','崇仁縣君魏氏挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','出自高明盛，歸從望族賢。',48,'全唐诗/poet.song.70000.json','["出自高明盛，歸從望族賢。", "崇仁膺帝命，積善信家傳。", "翌翌纔三世，冥冥忽九泉。", "空餘可銘事，追繼采蘩篇。"]'),
('95ddae39-8a6d-4165-859b-a6308b85a5dc','崇仁縣君魏氏挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','獵獵霜郊路，銘旌捲朔風。',48,'全唐诗/poet.song.70000.json','["獵獵霜郊路，銘旌捲朔風。", "堂前萱尚北，門外水猶東。", "貌入丹青冷，恩留祭享豐。", "鄉人仰閨範，方看子孫隆。"]'),
('d007b219-4201-4ad2-8b2d-a40f80c6a1b1','故通直强君挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','白髮將年往，青衫甫宦遊。',48,'全唐诗/poet.song.70000.json','["白髮將年往，青衫甫宦遊。", "從來四方志，曾未一分酬。", "幕府殘機畫，閭門失好修。", "惟餘舊秦月，寂寂照新丘。"]'),
('aa0e3616-a1a4-430c-9a80-1d18a578cdd4','故通直强君挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','金丹猶在鼎，馬鬛已成封。',48,'全唐诗/poet.song.70000.json','["金丹猶在鼎，馬鬛已成封。", "夢斷飛雲鶴，春歸遶墓松。", "韋編元自若，藜杖竟誰從。", "賴有承家子，流光得所鍾。"]'),
('8b139c5b-bcc5-4688-8dc7-8e80a4129103','龍圖胡公挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','華屋初成後，安車未用時。',48,'全唐诗/poet.song.70000.json','["華屋初成後，安車未用時。", "誰知五朝舊，俄與九原期。", "德映文恭顯，名參修簡垂。", "淒涼獨心事，無復盡施爲。"]'),
('a99ac279-d708-4d75-be44-4cf6de8cf121','龍圖胡公挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','正爾逢千載，何爲不百年。',48,'全唐诗/poet.song.70000.json','["正爾逢千載，何爲不百年。", "龍圖虚舊閣，馬鬛啟新阡。", "方寸留天鑒，清規入世傳。", "韋平向來盛，端屬子孫賢。"]'),
('1fb1efb4-d576-4315-9203-5252d7197602','龍圖胡公挽詞  其三','鄒浩','宋','宋诗','song-poetry','','[]','知己如公少，還鄉特地親。',48,'全唐诗/poet.song.70000.json','["知己如公少，還鄉特地親。", "分攜能幾日，聞語歘驚人。", "永念恩常在，深慚報未伸。", "從横淚交下，空灑朔風頻。"]'),
('df030097-db37-448c-972d-e67472cb64dd','胡公郡君李氏挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','先别人間去，由來天意微。',48,'全唐诗/poet.song.70000.json','["先别人間去，由來天意微。", "初心在偕老，此日遽同歸。", "鏡掩孤鸞舞，津藏雙劍飛。", "空存錦囊誥，依舊照霞衣。"]'),
('180d654a-f7b4-425d-949e-5bc54e985f54','胡公郡君李氏挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','正是家肥日，香奩曉不開。',48,'全唐诗/poet.song.70000.json','["正是家肥日，香奩曉不開。", "侍兒猶扇枕，良藥已停盃。", "蘋老殘初薦，萱閒冷舊栽。", "只應有餘慶，從此亘雲來。"]'),
('d3285536-4fee-4029-9f7d-b5b348999db1','故通仕孫公挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','少微星忽墜，疇昔夢初圓。',48,'全唐诗/poet.song.70000.json','["少微星忽墜，疇昔夢初圓。", "鄉社崇新祭，書帷掩舊編。", "亭依金斗固，兒戲彩衣偏。", "踵續誰爲傅，吁嗟高士賢。"]'),
('553aab12-b3d5-4831-b93f-4351e54e8ae8','故通仕孫公挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','君子不可見，先生無復遭。',48,'全唐诗/poet.song.70000.json','["君子不可見，先生無復遭。", "凶傳俄一旦，吉養謾三刀。", "德與諸郎遠，門將駟馬高。", "傷心獨南陌，松檜朔風號。"]'),
('d411165a-2e16-4d7a-991e-7b90c8728069','故成紀李季侔挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','命也端難詰，時乎竟莫來。',48,'全唐诗/poet.song.70000.json','["命也端難詰，時乎竟莫來。", "門庭方白晝，冠带掩黄埃。", "萬卷虚料理，千金廢剸裁。", "遵承子將顯，猶得慰泉臺。"]'),
('08d5ad95-2f2b-4358-b4e9-cbdbbc0dfa2f','故成紀李季侔挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','師門深往好，姻黨厚新情。',48,'全唐诗/poet.song.70000.json','["師門深往好，姻黨厚新情。", "正爾追談笑，那知隔死生。", "松風傳挽鐸，壟月照銘旌。", "莫預東郊送，悲凉空此誠。"]'),
('505be085-bc5e-42c5-b5d4-2c62512e06a0','故文安郡君劉氏挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','鷲峰成記别，聊現大家身。',48,'全唐诗/poet.song.70000.json','["鷲峰成記别，聊現大家身。", "瞬目超塵劫，隨方得本真。", "忘憂殘舊草，供祭冷初蘋。", "獨有閨門淚，澘然冬復春。"]'),
('6ef08bfd-dd62-4950-8b60-caf176034d85','故文安郡君劉氏挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','願力堅如母，翛然亦坐忘。',48,'全唐诗/poet.song.70000.json','["願力堅如母，翛然亦坐忘。", "羞蘭虚孝養，偕老誤榮光。", "浄域端何許，遺經只自香。", "它年盛追贈，猶得賁餘芳。"]'),
('1d264fb1-cc3b-4e84-83b2-656dbca38036','故承議李公挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','犖犖豪英內，如公迥不羣。',48,'全唐诗/poet.song.70000.json','["犖犖豪英內，如公迥不羣。", "胸中妙莊老，筆下藹機雲。", "勳業知誰睹，聲名只自聞。", "空餘柏莊柏，彌望拱高墳。"]'),
('cc7edd5d-cd51-4ab6-a85d-f724ed7f63a3','故承議李公挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','甫畢榮親願，歸休不計年。',48,'全唐诗/poet.song.70000.json','["甫畢榮親願，歸休不計年。", "心冥塵竟遠，善積子皆賢。", "萬事殘初夢，千齡掩逝川。", "登門獨無路，追感倍悽然。"]'),
('8ca0a3c2-0496-489c-9251-c807f932fd74','亡原作忘，據四庫本改友皇甫民望挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','八行宜高選，胡爲不享年。',48,'全唐诗/poet.song.70000.json','["八行宜高選，胡爲不享年。", "鄉閭推往躅，几席積遺編。", "俛仰成千古，凄凉到九原。", "須知天報在，有子共稱賢。"]'),
('cccb4da8-0823-4803-92c7-d2a286887ce0','亡原作忘，據四庫本改友皇甫民望挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','超然遺象數，非古亦非今。',48,'全唐诗/poet.song.70000.json','["超然遺象數，非古亦非今。", "過我每終日，惟君同此心。", "絕編猶可續，折角竟難尋。", "已矣無由作，高山空自琴。"]'),
('b9ca3e9e-cfd2-46d0-a4da-92a6d20f1eb3','閻求仁太博挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','東國論交處，于今馬鬛歸。',48,'全唐诗/poet.song.70000.json','["東國論交處，于今馬鬛歸。", "江山愁欲變，冠劍歘成非。", "事業知誰睹，聲名只自飛。", "蒼蒼不容問，落日掩晴暉。"]'),
('af0c0b33-bf1d-4c76-8a69-b9c8f5d6b045','閻求仁太博挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','踵門寒日後，留語竟黄昏。',48,'全唐诗/poet.song.70000.json','["踵門寒日後，留語竟黄昏。", "能得幾日别，遽爲千古魂。", "根塵元自了，生死更何言。", "獨有人間淚，隨風落九原。"]'),
('2960899c-cb30-45e2-a2cb-91e27e5e0162','强評事挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','池亭春未改，宰木已鳴風。',48,'全唐诗/poet.song.70000.json','["池亭春未改，宰木已鳴風。", "夙負三吳望，今鄰萬鬼中。", "潛光雖不輝，遺澤定難窮。", "它日高門淚，猶知駟馬通。"]'),
('9f7db469-8a77-45b0-ac1a-e29d0a8cec18','强評事挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','不爲明世得，已矣舊山川。',48,'全唐诗/poet.song.70000.json','["不爲明世得，已矣舊山川。", "青眼誰樽俎，黄金自簡編。", "鄉閭今昔異，門戶子孫賢。", "我獨從君晚，追惟更慘然。"]'),
('24a43151-5936-48c3-996f-45aab97b556e','閭丘大夫挽詞  其一','鄒浩','宋','宋诗','song-poetry','','[]','鴛鸞紛集日，松檜掩新塋。',48,'全唐诗/poet.song.70000.json','["鴛鸞紛集日，松檜掩新塋。", "持節空諸路，分符謾列城。", "閩山餘舊峻，淮水漾前清。", "地下雖難作，功名凜似生。"]'),
('5b55e938-a523-4cb2-a6b3-8933260218ab','閭丘大夫挽詞  其二','鄒浩','宋','宋诗','song-poetry','','[]','營邱何處是，不復問歸期。',48,'全唐诗/poet.song.70000.json','["營邱何處是，不復問歸期。", "世事三吳冷，風霜八月悲。", "生平雖爵禄，身後只書詩。", "恩報嗟無及，初心折涕洟。"]'),
('2a1f91f5-0cd9-40fb-a799-e848f12c8e71','跋漳浦李大忠微叔所藏書畫尾','鄒浩','宋','宋诗','song-poetry','','[]','嶺表歸来飯不足，負郭有田多未贖。',32,'全唐诗/poet.song.70000.json','["嶺表歸来飯不足，負郭有田多未贖。", "何當賣劍成此謀，耕遍雨餘春雨綠。"]'),
('478500b8-a37a-40f5-9b6d-493051655f9b','澹山尹文老畫像贊','鄒浩','宋','宋诗','song-poetry','','[]','有時皺聚雙眉，有時笑開雙臉。',28,'全唐诗/poet.song.70000.json','["有時皺聚雙眉，有時笑開雙臉。", "澹山不解謾人，一任諸方點檢。"]'),
('b3d1bfd9-a7e4-4c4a-9293-71797d9254b8','道鄉贊二首  其一','鄒浩','宋','宋诗','song-poetry','','[]','青草黄茅夢破，東阡西陌年豐。',28,'全唐诗/poet.song.70000.json','["青草黄茅夢破，東阡西陌年豐。", "長與老農撃壌，不知身世窮通。"]'),
('65f28fac-5ed9-4998-854d-3f226a0065cd','道鄉贊二首  其二','鄒浩','宋','宋诗','song-poetry','','[]','昔時吏部侍郎，今日道鄉居士。',28,'全唐诗/poet.song.70000.json','["昔時吏部侍郎，今日道鄉居士。", "畢竟這箇是誰，一任更安名字。"]'),
('f2d55943-d9d5-4ddf-81b4-9a074e7aaa0a','普融閣','鄒浩','宋','宋诗','song-poetry','','[]','前身善財後老平，善知識處靡不到。',240,'全唐诗/poet.song.70000.json','["前身善財後老平，善知識處靡不到。", "十信生行回向地，等覺妙覺諸法門。", "一法門中義一句，須彌聚筆海量墨。", "亘未來際力書寫，未來可盡寫不盡。", "何况六位一切法，一一筭諭莫能及。", "老平於此不思議，第三手把龜手筆。", "一刹那間能事竟，一一微塵出經卷。", "三千世界微塵偈，一四天下微塵品。", "龍樹傳持所未會，悉在而今輪字裏。", "字字無增亦無減，四十二字誰舉偈。", "大寶蓮花忽開敷，帝網重重清浄土。", "十方三世佛菩薩，一時會集作證明。", "彌勒辨說巧稱揚，文殊師利欣按頂。", "日用縱横日日新，此身普賢身內現。", "若人欲識老平身，即是毗盧無盡藏。"]'),
('ecba2a0f-a20d-46b8-bc91-78c66025d3c2','蓮華經贊','鄒浩','宋','宋诗','song-poetry','','[]','心爲工師筆斤斧，巧取蓮花以爲材。',240,'全唐诗/poet.song.70000.json','["心爲工師筆斤斧，巧取蓮花以爲材。", "願力基構次第崇，一刹那間能事畢。", "菩薩衆星佛孤月，歘然出現此土中。", "種種說法利羣生，一一慈悲大方便。", "如父誘子出火宅，如主導商移寶城。", "如雨灌溉藥品殊，花實根莖同一長。", "獲普門通靡不應，道與非道對病藥。", "過現未來佛所說，不增不減悉如是。", "寶積如來爲證明，嶪岌巍峩分半座。", "此塔彼塔兩現前，非一非二叵思議。", "誰將手擎至感慈，八萬四千真塔様。", "無礙光從無縱出，徧非非想無間處。", "疑情照脱罪垢空，同證一乘無上覺。", "有如不信視龍女，八歲何知頓成佛。", "時不待人勿後悔，速向塔前勤懴禮。"]'),
('61dec6ba-f73a-40c2-8b7b-9623adaf8970','書合論後','鄒浩','宋','宋诗','song-poetry','','[]','華嚴佛菩薩，悲智咸徧周。',120,'全唐诗/poet.song.70000.json','["華嚴佛菩薩，悲智咸徧周。", "廣開方便門，主伴互酬請。", "於無言說中，說法無數量。", "我讀誦思惟，獲從信根入。", "闇逢照世燈，病遇雪山藥。", "無價大寶珠，衣內忽然得。", "願盡未來際，滿足普賢行。", "一切導師前，一一興供養。", "一切衆生前，一一作利益。", "持經繼有人，悉冀同我願。"]'),
('36c6ece9-cd65-46a1-9d4d-05fd51351b61','書楞伽經後','鄒浩','宋','宋诗','song-poetry','','[]','牟尼净虚空，大慧舒光明。',72,'全唐诗/poet.song.70000.json','["牟尼净虚空，大慧舒光明。", "森然萬象形，有目咸欣睹。", "疑解二俱脱，一切本如如。", "一一楞伽山，演說修多羅。", "稽首方便慈，功德無窮盡。", "我今如是了，是爲報佛恩。"]'),
('83b96589-ea52-4698-b0cd-44e8d68d1bfd','陳瑩中畫像贊  其一','鄒浩','宋','宋诗','song-poetry','','[]','鳳閣鸞臺何許，天涯地角周遊。',28,'全唐诗/poet.song.70000.json','["鳳閣鸞臺何許，天涯地角周遊。", "此老老而益壯，超然一段風流。"]'),
('3926316f-45c3-4219-8b12-6a1fd1aa90a8','陳瑩中畫像贊  其二','鄒浩','宋','宋诗','song-poetry','','[]','了了了時非了，非非非處何非。',28,'全唐诗/poet.song.70000.json','["了了了時非了，非非非處何非。", "要識此翁端的，試看筆下形儀。"]'),
('30c19dd5-3282-41c1-84f6-d945dc7e4753','東坡横策像贊','鄒浩','宋','宋诗','song-poetry','','[]','東坡未作儋耳行，此相已入龍眠筆。',32,'全唐诗/poet.song.70000.json','["東坡未作儋耳行，此相已入龍眠筆。", "大海中央誰與鄰，萬事一條横榔栗。"]'),
('98516196-09d2-4cfb-87bb-c2de216a557b','雲溪文慶長老畫像贊','鄒浩','宋','宋诗','song-poetry','','[]','不選在在處處，長是哆哆啝啝。',58,'全唐诗/poet.song.70000.json','["不選在在處處，長是哆哆啝啝。", "飯了要睡便睡，睡了要歌便歌。", "呵呵呵呵呵呵，且道一把茅下。", "翁子三家村裏，老婆相去幾何。", "咦。"]'),
('26d989a1-3fdd-416e-b056-3026f73a80f2','集經文爲要訣','鄒浩','宋','宋诗','song-poetry','','[]','黄童妙音難可聞，若得三宮存玄丹。',160,'全唐诗/poet.song.70000.json','["黄童妙音難可聞，若得三宮存玄丹。", "中有童子冥上玄，回紫抱黄入丹田。", "閉塞三關握固停，三氣右回九道明。", "恍惚之間至清靈，散化五形變萬神。", "千千百百自相連，共入太室璇璣門。", "三老同坐各有朋，高拱無爲魂魄安。", "玉笢金籥常完堅，內守堅固真之真。", "真人既至使六丁，內挾列月列宿陳。", "物物不干泰而平，百二十年猶可還。", "使人長生昇九天，上清紫霞虚皇前。"]'),
('bfcd0357-c9d3-495a-92d0-d3725918a2d0','嘲龔彥和','鄒浩','宋','宋诗','song-poetry','','[]','衣領從教蝨了緣，夜深拜得蓆兒穿。',32,'全唐诗/poet.song.70000.json','["衣領從教蝨了緣，夜深拜得蓆兒穿。", "道鄉活計君知否，饑即須餐困即眠。"]'),
('d886663d-2890-4ed4-8aa4-8ccf732b2efc','贈廣陵馬推官','鄒浩','宋','宋诗','song-poetry','','[]','有才何事青衫，十載低徊北斗南。',63,'全唐诗/poet.song.70000.json','["有才何事青衫，十載低徊北斗南。", "肯伴雪髯千日醉，此心真與古人參。", "今見故人今幾年，年來風物尚依然。", "遙知閑望登臨處，極目江山萬里天。"]'),
('654ddae7-6880-4aea-a5ce-7c19d7b84587','滑石泉','鄒浩','宋','宋诗','song-poetry','','[]','馬頭今日度嚴關，十九年前去復還。',32,'全唐诗/poet.song.70000.json','["馬頭今日度嚴關，十九年前去復還。", "惟有流泉聲似舊，憑欄重聽響潺潺。"]'),
('0431d32c-eaf5-4ff8-b19e-9e0dce53876c','綠珠井','鄒浩','宋','宋诗','song-poetry','','[]','玉容捐委畫樓塵，一死甘酬石氏恩。',64,'全唐诗/poet.song.70000.json','["玉容捐委畫樓塵，一死甘酬石氏恩。", "古廟有碑旌節義，西風無主逐香魂。", "孤村夜靜鳴歸鶴，雙嶺雲寒唳斷猿。", "試向綠蘿尋舊迹，斷碑遺井見清源。"]'),
('828b2ace-d754-4c36-8b16-61033d034e11','梅詩','冥漠子','宋','宋诗','song-poetry','','[]','紅苞紫萼曾欺雪，素艷清香解動人。',32,'全唐诗/poet.song.70000.json','["紅苞紫萼曾欺雪，素艷清香解動人。", "自有風傳枝上意，肯教蝶兒蘂中真。"]'),
('e45f3831-8d87-4b01-93c8-7284659b642c','送徐天隱判官','毛滂','宋','宋诗','song-poetry','','[]','齊王未知瑟，吳犬終怪雪。',84,'全唐诗/poet.song.70000.json','["齊王未知瑟，吳犬終怪雪。", "越游售章甫，念子當折閲。", "一鳴豈無年，百計但有舌。", "西風吹曉波，晨景散文纈。", "嘈嘈雙櫓鳴，萬里欲俄瞥。", "江山真可人，得酒慰愁絕。", "咄咄無足云，與子男兒别。"]'),
('7c17841d-01c5-4169-8714-4050bc1688c0','贈陳進士','毛滂','宋','宋诗','song-poetry','','[]','民生委所窮，出仕增轗軻。',156,'全唐诗/poet.song.70000.json','["民生委所窮，出仕增轗軻。", "家山有蕨薇，歸足瘳饑餓。", "功名我豈敢，動若手足縛。", "太官五斗粟，飽食慚且頗。", "老胥抱文書，俾我供吏課。", "厭此將毋觀，法在恐深坐。", "舊書不得讀，掩帙充枕卧。", "朋游久益落，蹭蹬自老大。", "近乃得吾子，聽語百憂破。", "顔郎見清賞，今子傾一座。", "新詩已出人，珠玉落欬唾。", "諸生正業儒，風雅久不作。", "子意有是哉，吾道便可賀。"]'),
('c13d8fc7-e5f0-426c-b6af-0dcfbd4a3e9f','生日','毛滂','宋','宋诗','song-poetry','','["\u534e\u5c71"]','夜光昭清泠，璇源載圓折。',240,'全唐诗/poet.song.70000.json','["夜光昭清泠，璇源載圓折。", "朝陽未羽儀，五色先丹穴。", "松柏出澗壑，衆木皆禿屑。", "方其一寸青，意已傲冰雪。", "東家嬉戲時，俎豆輙羅列。", "未應須兒啼，英標固驚絕。", "公爲三朝老，氣壓萬人傑。", "經綸本帝賚，遇合非力結。", "舟成無長川，雲族有旱霓。", "東風吹扶桑，曉色開寥泬。", "平生回天手，獨佇昆吾轍。", "停鞭急節緩，揮臂層陰决。", "圖回掌中春，摩拂厚土熱。", "一身等大地，萬物小靖蛚。", "華嶽載不重，河海振不洩。", "黔黎託回命，草木恃以茁。", "造物相始終，流年難老耋。", "側聞宋鼎就，未可羽力挈。", "是乃爲公象，何但紀相烈。", "坐觀滿不溢，玉鉉無變滅。"]'),
('a8a82c7e-8981-48ce-8ab6-c695482c9703','寄曹子方使君','毛滂','宋','宋诗','song-poetry','','[]','使君未知我，得自吞氈翁。',288,'全唐诗/poet.song.70000.json','["使君未知我，得自吞氈翁。", "我未識使君，已聞伯夷風。", "十年詩卷裏，未面先從容。", "頃我客東都，寄聲謝老農。", "繡衣南州來，是爾使君公。", "爲爾掃菜色，無襦當夜縫。", "東都逆旅人，零落如霜蓬。", "一廛願爲氓，歸勢鳥脱籠。", "既登君子堂，倒戈避詩鋒。", "紫芝秀眉宇，東野凛長松。", "憐我骨硉兀，槽櫪駢兒童。", "秣以玉山禾，不置凡馬中。", "去年溪城月，使君馬如龍。", "呼我載後車，詩月相朣朧。", "朅來桑麻間，午夢回村舂。", "使君亦留犢，往聽長安鐘。", "相望渺雲海，烟雪迷西東。", "遙傳摛彩筆，秀句爭考功。", "那知古槐畔，苦語如秋蛩。", "一笑答雲山，萬事付瘖聾。", "吞舟亦失水，蚍蜉登背胸。", "拂鐘雖不錚，綴履豈所工。", "天高白虎殿，日永明光宮。", "去参鵷鷺羣，勿羡高飛鴻。"]'),
('de4e8d77-5d54-46aa-99fc-67a00d5c8ec8','累蒙周開祖使君貶示佳章才拙思荒愧不能報謹勉次韻一萹少叙敬避老匠之意','毛滂','宋','宋诗','song-poetry','','[]','居士稱陸蓮，香山本流亞。',120,'全唐诗/poet.song.70000.json','["居士稱陸蓮，香山本流亞。", "舌端元和風，吹倒兩鮑謝。", "游戲筆硯間，盤礴湖山下。", "過眼盡詩材，有欲天必借。", "句源發肝膈，輸瀉每不暇。", "欬唾生江河，奔放那可壩。", "我詩沮洳爾，欲過不足跨。", "數煩見波瀾，意作蹄涔嚇。", "平生望洋眼，癡膽不知怕。", "亦識明月珠，相投况非夜。"]'),
('c2142fee-28bc-443c-bd60-851941a25506','見雪明日與祝山人游東湖僧寺訪陳巨中教授留飲','毛滂','宋','宋诗','song-poetry','','[]','風吹飛雨乾，散作柳花毬。',144,'全唐诗/poet.song.70000.json','["風吹飛雨乾，散作柳花毬。", "危簷下舞鵠，老樹騰蟠虬。", "烟空夜色垂，膚寸凝酥柔。", "曉屨踏晶瑩，與君散清愁。", "湖東十頃玉，月落漫不收。", "照我肝肺皎，出語和鳴璆。", "將我平生客，步入青松幽。", "此客氣如霜，逼人作颼飀。", "嚼冰論世事，怒頰赤已浮。", "盤中水晶鹽，碧酒葡萄秋。", "飲酒豈憂寒，飲水猶不憂。", "手冷慎勿炙，置之鷫鸘裘。"]'),
('03623fd3-52c2-4744-94ee-fc2685036c11','過靜林寺與徑山老禪曳杖溪濱俯淺澗寒洌可照隨流而前即淵然清深爲作數句以告同遊','毛滂','宋','宋诗','song-poetry','','[]','寒溪數寸爾，下有萬里天。',108,'全唐诗/poet.song.70000.json','["寒溪數寸爾，下有萬里天。", "烟雲自變怪，寸碧殊湛然。", "蘋風亦可人，寧妨暫漪漣。", "終觀鏡面平，與君受媸妍。", "有苔綠蒙茸，孺子俯可搴。", "前窺漸難量，忽此清泠淵。", "魚鰕亦無蹤，但見空月圓。", "陶翁步屧處，獨俾支郎肩。", "倚策心自知，鷗鷺紛聯翩。"]'),
('b8f9323a-ca5a-458d-a463-d69d324362cf','次韻葉權之','毛滂','宋','宋诗','song-poetry','','[]','二年錦衣城，坐悵朋游落。',192,'全唐诗/poet.song.70000.json','["二年錦衣城，坐悵朋游落。", "雙瞳不敢白，但向湖山著。", "頃當舍之去，眼界垂落寞。", "忽逢昔所傾，人事豈容約。", "西行追畫鷁，北首望金雀。", "斯人玉樹明，映我蒹葭惡。", "平生函牛鼎，顧可作雞臛。", "干將久在冶，宜有當槖籥。", "大器不匆匆，一飛要寥廓。", "佳哉妙五言，珠琲相磊硌。", "長城矗金墉，銛鋒露霜鍔。", "向我寧可當，倒戈爲之却。", "我生已數奇，世味寒冰薄。", "兹行聊爾耳，外物矧可略。", "所喜得公游，昏愚煩發藥。", "不重千金裘，爲公了杯酌。"]'),
('d113a724-ee53-4635-b322-6ab2d31e9b8d','暑雨蒸溽奉王元規學士','毛滂','宋','宋诗','song-poetry','','[]','老火尚偃蹇，稚金殊踧踖。',108,'全唐诗/poet.song.70000.json','["老火尚偃蹇，稚金殊踧踖。", "雨如甑笠汗，但作氣蒸赫。", "思君屢欲往，露頂不可幘。", "坐懷屋漏下，蝸牛頗爭席。", "屋漏人自佳，泥沙卧圭璧。", "我衰了無營，飽睡夢書策。", "家貧苦無書，豈復有漂麥。", "不了湯餅事，可致萬錢客。", "正須裹飯來，濯足水三尺。"]'),
('7f4740c2-0e04-4e0d-816a-e243459eea1f','育闍黎房見秋蘭有花作','毛滂','宋','宋诗','song-poetry','','[]','南風吹露畦，苦菜日夜花。',156,'全唐诗/poet.song.70000.json','["南風吹露畦，苦菜日夜花。", "同榮有蔓草，託質多長蛇。", "邇來合蕭條，凄風寄蒹葭。", "禪房向幽寂，雲日曖庭沙。", "竹根逢小春，紫蘭茁其芽。", "造物惜鮮榮，寧肯及幽葩。", "偶出白帝恩，未必黄鍾家。", "芳馨半孤冷，蕭艾終横斜。", "譬如隱君子，悃愊初無華。", "深藏不自獻，清芬亦難遮。", "陶翁抱疏韻，對此心忻嘉。", "離騷久相從，濁酒不待賒。", "紉衣濯滄浪，援琴卧烟霞。"]'),
('95545caa-928f-4e84-8b3e-a7d1b1961d12','解武康縣印至垂虹亭作','毛滂','宋','宋诗','song-poetry','','[]','娟娟東堂月，瑟瑟北窗風。',96,'全唐诗/poet.song.70000.json','["娟娟東堂月，瑟瑟北窗風。", "半夜渡龍尾，隨我藕花中。", "徑邀此花香，追路溪城東。", "溪山久俯仰，臨别亦匆匆。", "三年虎落檻，一日鴰開籠。", "何須見似人，聊作逃虚空。", "今宵花亦遠，餘香歸故叢。", "殷勤此風月，隨我登長虹。"]'),
('5419e8a1-8aa8-4304-8b9a-fd9a37cd0fbe','歲寒而春遲閏正月猶有雪三日乃消今日方晴快','毛滂','宋','宋诗','song-poetry','','[]','東風果來否，雪意不肯消。',156,'全唐诗/poet.song.70000.json','["東風果來否，雪意不肯消。", "初疑寒作威，勢猛意反韶。", "玲瓏開瓊花，瑤草亦有苖。", "細觀如可人，玉立耿高標。", "華屋本無寒，錦帳裘狐貂。", "所憐小桃杏，凍蕾抱寒條。", "却看雨成花，祇憂身當樵。", "語花慎勿憂，春久屬雲翹。", "徐行意不淺，晚發必後凋。", "年年綠暗時，逮此紅芳夭。", "左提白玉壺，右把黄金蕉。", "往逐春未央，不但永今朝。", "曉來紅日暾，花信到柳橋。"]'),
('420c08c3-a80b-4173-9279-f34f2860a8fd','秋日書懷','毛滂','宋','宋诗','song-poetry','','[]','秋日吐微明，寒葉墮半碧。',192,'全唐诗/poet.song.70000.json','["秋日吐微明，寒葉墮半碧。", "娟娟竹弄影，冉冉香引脉。", "窗明棐几凈，水石涵虚白。", "茶開睡足眼，苔上懶行屐。", "屋寒無燕雀，豈獨少賓客。", "顧我警露鶴，佇此遼天翮。", "相對雖不言，孤高比三益。", "邇來世外心，漸覺眼界窄。", "兒時喜功名，今念真戲劇。", "平生翻羮手，欲爛誰能炙。", "豈待二頃田，初無一廛宅。", "第當營糟丘，努力期百尺。", "頹然寄疏慵，坐看駒過隙。", "韓郎食不足，苦心定誰惜。", "那知落英繁，吾食豈無夕。", "舉手謝飛鳶，一鼠何勞嚇。"]'),
('9ec2db0a-72c5-4b01-a01c-78966e8d71c7','次韻張臺卿桃花詩','毛滂','宋','宋诗','song-poetry','','[]','使君園中花，造物勤管領。',96,'全唐诗/poet.song.70000.json','["使君園中花，造物勤管領。", "佳人含朝酒，風軟吹莫省。", "正應武陵裔，或寫瑤池影。", "誰云六果下，實抱千歲永。", "得地倍穠華，無人亦妍整。", "舞困霞衣翩，粧早燕脂冷。", "玉堂摛藻筆，一顧長光景。", "誰識勸農心，殷勤待遺秉。"]'),
('87ff4f7b-8f5e-45af-b872-f098ac80728b','汪發彊中見遺佳篇筆勢高妙且從僕求詩以歸輙爲此數句','毛滂','宋','宋诗','song-poetry','','[]','落落湖邊松，瀏瀏松下風。',96,'全唐诗/poet.song.70000.json','["落落湖邊松，瀏瀏松下風。", "泠然入君懷，蕭颯詩脾中。", "清露瀉筆端，一掃浮埃空。", "以遺愚参軍，僅免按劍凶。", "三年耳目昏，此語豈易逢。", "亦豈務炳烺，邂逅乃自工。", "歸囊一錢盡，足用仍三冬。", "他年太羮熟，寧俟鹽酪供。"]'),
('fae3931c-9b76-4664-bb36-e5d9d46fb1aa','送僧覺歸上饒','毛滂','宋','宋诗','song-poetry','','[]','上士垂暮年，不受煩惱攻。',144,'全唐诗/poet.song.70000.json','["上士垂暮年，不受煩惱攻。", "欲修沙門果，坐怪鬚髪空。", "言有摩尼珠，自照迷妄蹤。", "當來滯礙心，如以巨物摏。", "妻子昔所愛，今斷如潰癰。", "欲作大醫王，徧救瘖與聾。", "長安坐寂寞，饑腹聽午鐘。", "行歸洗黄塵，誓將掃青松。", "一蠡渡長淮，東望迦葉峰。", "我走名利塲，未可談從容。", "軟語感屢發，爲我清心胸。", "上士無住著，此别何由逢。"]'),
('874dafbc-fba2-423c-8304-1d5a3fb70e50','贈别講僧若水','毛滂','宋','宋诗','song-poetry','','[]','道人永嘉老，口作智者語。',168,'全唐诗/poet.song.70000.json','["道人永嘉老，口作智者語。", "坐揮鐵如意，寶藏發深貯。", "行住自如如，當亦無住所。", "踏雪來東山，了不憚修阻。", "孤雲亦何心，東風復吹去。", "索詩讚行色，我敢靳不與。", "道人已得道，逢魔猶齟齬。", "古氣生面目，清流見幽嶼。", "泠泠微妙音，松風雜寒雨。", "九旬談妙用，况乃超佛祖。", "東歸花木繁，啾唧鳥雀聚。", "道人具眼目，要當反聾瞽。", "萬事付一笑，鉢飯飽亭午。", "聊以答道人，缾巾過水滸。"]'),
('ad949590-f830-4b47-a451-6b5429fe1281','留别邵公言','毛滂','宋','宋诗','song-poetry','','[]','公言雅知我，良勝我自知。',252,'全唐诗/poet.song.70000.json','["公言雅知我，良勝我自知。", "往年得爲僚，税駕清江湄。", "覺君有勝致，真率仍天資。", "定交傾盖間，快語明肝脾。", "我生七不堪，百謫將安之。", "官長笑不罵，兒童容遨嬉。", "掾舍等禪房，竹樹含幽姿。", "其間有閒味，共此非君誰。", "駕言寫予憂，欲致車已脂。", "往披五老雲，下採蒼山芝。", "翛然送日月，萬慮忽若遺。", "朅來兩溪上，邂逅寛所思。", "微風送白蘋，藻荇搖寒漪。", "水清不受釣，魚細安可騎。", "亦復可憐人，鷗鷺相委蛇。", "君豈鷗鷺羣，鵷鸞往追隨。", "所遭即定分，固有何庸麾。", "我生儻可用，豈惜山英移。", "榮華如食薺，貧賤亦嘗飴。", "顧今適當還，捃拾聊充饑。", "從君借蓑笠，破雨收江蘺。"]'),
('526b85da-7770-439c-bc36-a8528b6abbf3','贈禧上人','毛滂','宋','宋诗','song-poetry','','[]','此寺昔荒寒，蠧黑相撐支。',144,'全唐诗/poet.song.70000.json','["此寺昔荒寒，蠧黑相撐支。", "世尊窘風雨，鐘磬出茅茨。", "吾祖過而慨，開槖爲營之。", "一旦黄金宮，突兀清江湄。", "其徒則以安，其道猶遠而。", "吾游童且白，僅乃見此禧。", "譬如蒿艾中，蔚然得江蘺。", "昻藏老鶴骨，勁瘦寒松枝。", "宴坐了無營，孤香對逶迤。", "海濤走窗檻，江雲翔屋楣。", "全收眼界勝，闃與人境辭。", "吾方迫遠游，未可分清怡。"]'),
('4627b8c5-51de-4961-805a-5b6bf46fcc44','廣鑑大師觀上人爲靈芝數百衆故乞從檀施乞米求予詩送行爲作一首予昔爲武康縣令觀師吾邑人也','毛滂','宋','宋诗','song-poetry','','[]','靈芝有良田，歲比萬戶侯。',192,'全唐诗/poet.song.70000.json','["靈芝有良田，歲比萬戶侯。", "平生不力耕，以德作耡耰。", "不許倉箱豐，但知鉢盂秋。", "木魚一呼飯，千屐如水流。", "靈芝道亦然，飽汝即罷休。", "但憂汝易飽，未飽非所憂。", "後生真可畏，見此觀比邱。", "昔常爲我民，今乃從我游。", "得道於靈芝，胸中羅珍羞。", "豈特求自飽，將副餒者求。", "裹鉢忽何之，西風送輕舟。", "處處靈芝田，多稼如雲浮。", "初以非種種，今當不收收。", "誰施復誰乞，大塊同一漚。", "姑且置是事，吾言亦謬悠。", "羨觀一身輕，翛然逐飛鷗。"]'),
('611e896e-706d-4754-a078-ffc7ab8f08ce','盛暑謁劉公達','毛滂','宋','宋诗','song-poetry','','[]','伏金避老火，遁日乾商霖。',204,'全唐诗/poet.song.70000.json','["伏金避老火，遁日乾商霖。", "天地豈不寛，八荒一釡鬵。", "此身沍寒鄉，骨冷勢陸沉。", "忽疑同然灰，終得空汗襟。", "聞有不熱符，莫致癸與壬。", "平生習雲水，兩足便幽尋。", "佩紳接軫處，念往汗益浸。", "乃獨款公關，熱行犯訶吟。", "忘公鼎軸家，謂是緇帷林。", "有風静險躁，無愠煩鳴琴。", "置我弟子間，豈不容魯参。", "公如天下雨，焦卷聽雷音。", "謦欬走旱魃，噫欠停流金。", "胸中三絕編，寧獨自洗心。", "坐使人意消，煩促變清深。", "南山當朝隮，暫卷乃至今。", "萬物抱暍意，油然徯層陰。"]'),
('31db8037-3379-4144-ad36-bf5d92c6f4cf','昨夜陪諸公飲今尚委頓未能起坐聞孫守出送陳祠部供帳溪上見招不果往戲作小詩寄之','毛滂','宋','宋诗','song-poetry','','[]','孫公金作骨，何獨無燥濕。',132,'全唐诗/poet.song.70000.json','["孫公金作骨，何獨無燥濕。", "雄姿逼龍虎，風雨坐嶪岌。", "黄堂爛繡筵，春甕融玉汁。", "銀臺三見跋，醉眼夢欲入。", "公張兩瞳電，照我毛髪立。", "平明郭西門，鐘鼓仍盛集。", "我方擁黄紬，勢作蚯蚓蟄。", "乃知千里姿，追趁何翅十。", "春溪葡萄碧，飲渴誰當吸。", "願君苦留客，墮翠應可拾。", "未用奏伊凉，舞紅催玉粒。"]'),
('67c3ef4c-41ce-48f5-8ee6-614d294e36b6','琳老所居植竹發筍而草茁其傍作詩見寄爲賦一首','毛滂','宋','宋诗','song-poetry','','[]','春風吹琅玕，夏長蒼龍孫。',72,'全唐诗/poet.song.70000.json','["春風吹琅玕，夏長蒼龍孫。", "未見拂雲梢，已引鞭驥根。", "包藏霜雪姿，隱忍苔蘚痕。", "其傍茁小草，同出東帝恩。", "恩深草先高，抱籜殊末掀。", "歲寒兩何如，一笑凝詩魂。"]'),
('07976674-dc88-4ac1-80a8-29d782adc5dc','猗猗亭夜月','毛滂','宋','宋诗','song-poetry','','[]','猗猗亭下竹，娥娥竹上月。',48,'全唐诗/poet.song.70000.json','["猗猗亭下竹，娥娥竹上月。", "微風静蘭路，水石相映發。", "盈前嬋娟子，秀色粲玉骨。", "褰衣往從之，露泣苔侵襪。"]'),
('3f212f76-8d33-4380-82a6-3edd68f78324','溪上','毛滂','宋','宋诗','song-poetry','','[]','溪光照秋房，娟然卧流萍。',48,'全唐诗/poet.song.70000.json','["溪光照秋房，娟然卧流萍。", "水仙弄幽姿，寄余汀洲情。", "眷懷玉色子，弄波濯塵纓。", "夜寒有佳意，屬此泠然清。"]'),
('049d7841-5dc4-4e51-973d-58a09f75ce28','十二月十二日雪晴成允蔡君扁舟携詩見臨次韻奉答','毛滂','宋','宋诗','song-poetry','','[]','蔡子下筆生濤瀾，少時往往思湧泉。',320,'全唐诗/poet.song.70000.json','["蔡子下筆生濤瀾，少時往往思湧泉。", "便當自作五鳯樓，畫楹刻桷皆蠻牋。", "昨日千秋橋畔雪，楊花蝴蝶相聯翩。", "徑喚紅粧弄春色，千壺快倒萬錦纒。", "那知蔡子足踐地，柳車送客已復延。", "搖竿孤唱頗自得，閉門高卧初誰賢。", "幸來餉子小樓日，共看簷影移殘年。", "東堂夜寒劍有氣，北窗晝静琴無弦。", "高門懸薄固疏矣，所憂餓虎猶須鞭。", "齒搖目眵懶自薦，豈復珠貝如懸編。", "仙人玉樹儻相待，只擬醉拍洪崖肩。", "堯舜之事不足驚，肯爲兒女癡自憐。", "故山鶴帳久不往，白雲封戶端應全。", "吏卒無令守叔夜，弟子何妨嘲孝先。", "伯倫天地席幕爾，何處六翮猶爭前。", "平生小吏輕子美，未害故人疏浩然。", "子今風霰動短褐，豈乏錦繡裁長篇。", "東堂那記城旦語，唯有詩律曾家傳。", "墨香紙滑霜兔勁，明窗妙意常空圓。", "客來指似寧信此，自知食蜜甜中邊。"]'),
('93a443b8-1269-471d-b6a1-3760cfbc1fd7','李白於宣州謝朓樓餞别校書叔雲一首十二月初六日夜獨坐松齋懷抱良不佳飲少輙醉庭下梅兩株月色皎然倚樹微吟偶誦李白此詩有會予意者次其韻追和一首','毛滂','宋','宋诗','song-poetry','','[]','棄我去者昨日之日不可留，醉我心者今日之日多煩憂。',104,'全唐诗/poet.song.70000.json','["棄我去者昨日之日不可留，醉我心者今日之日多煩憂。", "秋風吹鴈渡汾水，斜陽隨客下西樓。", "苑邊麒麟守白骨，半夜安能保明發。", "小蠻爲酌流霞春，醉倚梅花滿懷月。", "暗香吹遠月欲流，松聲百尺喚清愁。", "早掛銅章老槐下，短蓑獨速上漁舟。"]'),
('4ed512ac-60df-4c69-a3e6-188af70ce36e','孫使君見招以不茹葷得醉因過南禪老飯小休庵中作此詩寄之','毛滂','宋','宋诗','song-poetry','','[]','城南病客食不足，日與天隨爭把菊。',208,'全唐诗/poet.song.70000.json','["城南病客食不足，日與天隨爭把菊。", "饑腸昨作細泉響，豈識韭虀并豆粥。", "五州自有定遠侯，虎頭燕頷飛食肉。", "門前麴封何足道，酒出兵厨瀉春瀑。", "康成温偉秀兩眉，何啻五斛當一斛。", "席中珍句出半酣，但驚墨逕通羣玉。", "不知清風静掃脾，徒見秋電寒搖目。", "相君脱粟好名爾，何用留侯歸辟穀。", "我今枯槁固其分，尚有閒氣蟠空腹。", "侯當下士屈體貎，屢喚不來仍不逐。", "羊臑魚尾癡不食，却覓山僧煮寒蔌。", "敢煩龐生要栗里，欲謝楊公向疏屬。", "午庵聊拂偃月牀，卧聽春飇過修竹。"]'),
('eb3b14de-368d-4b13-9f86-c6911cbb87bc','秋雨杜門久之比晴一出前村歸聞陸令見過奉寄一首','毛滂','宋','宋诗','song-poetry','','[]','子桑閉門十日雨，何人裹飯相勞苦。',96,'全唐诗/poet.song.70000.json','["子桑閉門十日雨，何人裹飯相勞苦。", "忽窺晴色入疏簾，徑向孤村尋老圃。", "不知雙鳬念雲水，欲下雀羅風送起。", "未容倒屣見王孫，豈是揚鎚嫚公子。", "長安秋雨乃復來，山陰夜雪仍空回。", "他時乘興幸告我，請掃門前紅葉堆。"]'),
('90207f4f-450a-40a6-b4ba-319922985f9f','新酒熟奉懷曹使君','毛滂','宋','宋诗','song-poetry','','[]','水沙卧甕青綀羃，浮蛆欲上真珠泣。',160,'全唐诗/poet.song.70000.json','["水沙卧甕青綀羃，浮蛆欲上真珠泣。", "濛漫崑山清露零，洗下雲腴和玉汁。", "小槽决决秋泉語，老盆艶艶春光濕。", "不妨力飲薦寒英，只憂秋老金膚澀。", "先生何翅七不堪，袍鞾裹縛肩骭急。", "醉鄉禮法稍寛閒，倒著接䍦猶許入。", "南樓老子冰雪腸，咳唾珠璣紛可拾。", "未許王郎見短歌，已容趙壹唯長揖。", "邇來鈴齋作禪觀，錦瑟間多山玉立。", "欲留一斗向吳興，何日南樓和月吸。"]'),
('88923d6c-d0b1-4cdc-9f41-c95d75d886ce','立秋日破曉入山携枕簟睡於禪静庵中作詩一首','毛滂','宋','宋诗','song-poetry','','[]','西風初起無人鄉，雲深萬籟含清商。',176,'全唐诗/poet.song.70000.json','["西風初起無人鄉，雲深萬籟含清商。", "山容便與新秋凈，稻花已作豐年香。", "斷蟬抱柳咽殘月，卧霞排霧通朝陽。", "過橋寺影出疏木，入戶竹色來低墻。", "蒲團紙帳兩寂寞，獨有老檜磨風霜。", "東堂老子喜睡人，來借一榻樂未央。", "含風漣漪開玉脊，小屏晚綠横瀟湘。", "夢寒支枕風入髪，過眼冉冉茶烟蒼。", "紅薇花陰煮玉醴，滿甌飛雪置我旁。", "平生世味總如水，老大縱健肝膈凉。", "翛然此意不可道，卧看石竹凝孤芳。"]'),
('6ad82dd5-2ecc-4407-88c9-af8d28ecc5a9','出都寄二蘇','毛滂','宋','宋诗','song-poetry','','[]','近年好語開蹙額，廊廟主人還稷契。',384,'全唐诗/poet.song.70000.json','["近年好語開蹙額，廊廟主人還稷契。", "諸公彙進民所懷，左必提之右乃挈。", "善隨類舉皆可觀，野無遺賢静巖穴。", "石梁有客少讀書，神接前人望風烈。", "志與時違可奈何，居賤好高謀已拙。", "此身悠悠日江海，弔影行吟事酸噎。", "揣摩胸臆作西游，不成興起慚豪傑。", "賈生慟哭初亦疑，十年自覺流清血。", "三書不用即山林，將前復却何從决。", "無因名姓累吳公，咫尺天光阻羅列。", "志士惜日誠可憐，每恨平津當老節。", "子雲年少行所爲，今出秦關獨疲苶。", "郭門囓臂良感人，仲卿蓄縮翻傷别。", "叩關自鬻雖矜張，掃門願見猶摧折。", "炙手門前車馬多，排肩屢進不得徹。", "近來索米却求田，結綬彈冠非所觖。", "更令胸臆從誰開，一刺懷歸定漫滅。", "檻虎饑饞尾漫搖，水盡海鯨當蟻垤。", "誰能忍恥寄我顔，妻笑嫂欺安用舌。", "北山記憶破臘來，遠水扁舟兩愁絕。", "雲重山寒暝不開，孤帆夜落嚴陵雪。", "雷山老桐凍弦斷，不作南風相煖熱。", "一劍星昏共形影，每恐龍寒呵古鐵。", "孟嘗無炭暖置身，杜雖有指不得結。"]'),
('3b7c1945-bb22-4ae0-9627-a971cc98a909','呈蔡內翰','毛滂','宋','宋诗','song-poetry','','[]','鄙夫十年江海客，岸草汀鷗隨步屧。',208,'全唐诗/poet.song.70000.json','["鄙夫十年江海客，岸草汀鷗隨步屧。", "稍收晚景付長竿，河伯供魚慰彈鋏。", "烟雲不鎻北闕心，飛出亂山青萬疊。", "束書却入國東門，觚稜瑞日明書笈。", "蹇驢破曉踏春泥，誰家暖氣生牙頰。", "門前賓客鄙可憐，紛如寒蠶饑望葉。", "主人看屋客看地，士氣蕭條無一捻。", "邇年恰得玉堂家，名在執鞭猶煒燁。", "玉堂丈人廊廟資，寶帯垂魚光遶脅。", "棣萼青春自一門，璇題白日常三接。", "側聞好士禮作羅，纖鱗弱翮歸漁獵。", "蹉跎歲晚曳裾人，半彫鬢綠仍隨牒。", "澗溪幽菜儻可羞，試雜萬錢聊一筴。"]'),
('128aea73-1fa7-48e6-9237-e06b89c48af3','病中獨坐','毛滂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','千秋橋畔桑麻村，槐陰覆砌綠映門。',224,'全唐诗/poet.song.70000.json','["千秋橋畔桑麻村，槐陰覆砌綠映門。", "關門誰覓病居士，掩書不讀愔不言。", "明窗養石作幽伴，蒼骨孤痩棲秋痕。", "瀟湘洞庭入眼界，念隨魚鳥蘆花根。", "端知此想無是處，聊遣幻變驅昏煩。", "請言居士往少壯，烹羊炰羔酒拍盆。", "離騷百過亦徑醉，萬事形影如空尊。", "襄陽老孟識此意，數憑楚些招其魂。", "秖今流落口吻燥，病乃乘間排吾閽。", "病多諸念反衰冷，念冷却覺丹田温。", "此田不應供喜怒，外物稂莠那可存。", "誅稂去莠要及早，俗慮可吐不可吞。", "鷄犬相聞太古末，居士中有五畝園。", "舒遲不稱子男服，要須結佩紉芳蓀。"]'),
('9734a99c-589c-4628-978b-53b7de01ffc4','友龍姪來别留詩次韻','毛滂','宋','宋诗','song-poetry','','[]','樵青煎茶青竹裏，汝欲過門鵲先喜。',96,'全唐诗/poet.song.70000.json','["樵青煎茶青竹裏，汝欲過門鵲先喜。", "我家千里凌風駒，豈比虺隤鞭不起。", "我亦西游倦始歸，久闊相望老白眉。", "歸家且與阿戎語，長吟未覺長康癡。", "雨急烟寒波渺茫，念汝束書辭故鄉。", "歸時先驅煩蜀令，却過竹間尋漫郎。"]'),
('e7b2f5f7-f84a-413b-b863-387fe9837af4','登聞鼓詩','毛滂','宋','宋诗','song-poetry','','[]','九重赤塗高如天，四海黔首紛於蝝。',352,'全唐诗/poet.song.70000.json','["九重赤塗高如天，四海黔首紛於蝝。", "衆蝝望天若無路，區區有意常能宣。", "乃知聽卑四聰達，萬里呻笑如郵傳。", "朝陽門外登聞鼓，鼓下章飛如急雨。", "一聲直墮勾陳中，誰言天門嚴九虎。", "江南小吏無技能，鼓間餬口何云補。", "僕饑馬瘦曉徐行，官曹下馬初無營。", "解衣小睡須臾散，鼓亦十日無一聲。", "疑非官家設鼓意，細問乃復知人情。", "文昌相公眼如月，坐見萬里分毫髪。", "蒼生痛癢吾一身，與汝一家無楚越。", "有求徑投家丈人，鼓面蛛塵寄蕭兀。", "亦何道業冠臯夔，民得由之初不知。", "平生胸中醫國法，盡變黄馘爲秀眉。", "力進唐虞作元氣，酲醲病酒何勞治。", "端知聽訟破癥爾，洞見五藏聊决之。", "造化昇平唯一筆，弼成堯舜垂衣日。", "墨客詩人慕響來，朱草嘉禾時一出。", "登聞終日何所聞，但聽清風頌聲溢。", "江南小吏未歸山，乞與居山相似閒。", "半饑終未免索米，飽飯亦復勝抱關。", "鼓稀有聲吏竊食，愧此無用毛髪斑。"]'),
('23f55e91-c79c-422e-aaf9-861ff2a98176','隋隄寫懷寄上右丞','毛滂','宋','宋诗','song-poetry','','[]','前年買符入函谷，歸來柴車仍露宿。',384,'全唐诗/poet.song.70000.json','["前年買符入函谷，歸來柴車仍露宿。", "似聞石室陳圗書，敢累山公爲題目。", "蒼梧祗覺波浪高，尺澤那知鱗尾禿。", "已將倦翮謝風雲，便擬閒身寄松竹。", "何庸復來良自嗤，聊當爾耳誰能卜。", "生長寒鄉非挾炭，老去剛膓徒仰屋。", "此日可惜那敢輕，流年已徂無計逐。", "淮山可人長好色，隨潮入落裁瞬息。", "隋堤官柳今許長，前年雪裏曾相識。", "尚有寒蜩抱殘葉，晚風凄瑟真相逼。", "斜陽更在柁樓明，孤烟已轉榆灣黑。", "濁流奔猛似欺人，前去高桅萬牛力。", "但令寸進殊不惡，行或止之那可測。", "朝廷無階亦何往，想見夔龍在君側。", "取士端須拔十五，除吏何妨論八百。", "爲郎二世疑有命，自著一生能幾屐。", "定知此意不在多，久從筆研安能擲。", "太常掌故本下才，未怪間關難射策。", "仲翁陸陸元先售，却令小苑東門後。", "人生有志將毋同，異時善舞輸長袖。", "此去誰家借蹇驢，偪仄終看飯山瘦。", "平生讀書過百紙，本是烟波釣徒爾。", "筆牀茶竈輕鼎鐘，雨笠烟蓑傲朱紫。", "如今却著從事衫，猶喜無材堪鼓吏。"]'),
('2b7a0ba3-460b-46b3-84db-e1bef1ab7644','比得貍一枚所過輙馥然有香時時翳蘭叢下而引其鼻若能自擇其所處貍之族最多獨牛尾食之可口江西亦呼爲玉面然彼以甘肥遭烹而此獨以能香爲人所貴非衆貍可望也爲作此詩一首','毛滂','宋','宋诗','song-poetry','','[]','春山得貍軀脅細，蒼頭抱携香着袂。',176,'全唐诗/poet.song.70000.json','["春山得貍軀脅細，蒼頭抱携香着袂。", "叢蘭密處曲庇身，狐鼠何疑相睥睨。", "定非青丘阿紫家，恐是中臺餐柏裔。", "太真妃子紫繡囊，一生長伴瑞龍香。", "石竹花開浴殿暖，何時馨郁棲珠璫。", "秖今弭耳空山內，時下山腰出雲背。", "弄香淺草已襲人，試雜江蘺爲君佩。", "兒童手摩初不惡，狐貍貎似安能輩。", "糟中玉面甘人頤，何食而肥蒸不悔。", "東堂老子有香緣，百和烟間回盻睞。", "相從真亦得所哉，便呼銅鴨爲爾配。"]'),
('ef3b30e8-8953-4a35-9a9f-ceb8e1b373cf','和郭倅見寄','毛滂','宋','宋诗','song-poetry','','[]','折節何須萬夫後，蟹螯居左杯居右。',176,'全唐诗/poet.song.70000.json','["折節何須萬夫後，蟹螯居左杯居右。", "先生老醜誰使然，天孫安能司唾嘔。", "尚無一字得三縑，何如賣之不龜手。", "與公正自一家人，公家日月余扃牖。", "每得新詩如見公，風流好在靈和柳。", "題輿那聽仲舉辭，宣室應懷賈生久。", "當年竹馬定不乏，舊雨墊巾無恙否。", "我今信手任翻羮，誰解苦心杯置肘。", "看公雋翮當在前，笑我勞驅空晚朽。", "東山掩鼻直可人，庸肯囁嚅論不偶。", "檻中搖尾未必然，試看於莵薄欄吼。"]'),
('5c895fb8-ef98-4edd-9c79-c2692ea13ef8','次韻奉酬蔡成允','毛滂','宋','宋诗','song-poetry','','[]','蔡子詩鋒新發硎，曉壓吾境横長城。',64,'全唐诗/poet.song.70000.json','["蔡子詩鋒新發硎，曉壓吾境横長城。", "玉關食肉何足計，飯山日午吟膚清。", "叩門念子憂吻燥，銀瓶急燎蒼蠅聲。", "雲龍爲子起風腋，要使飛將身趫輕。"]'),
('dcff2b83-6548-40ff-a1ba-83cab41def73','對雪作詩未竟曹使君寄聲招飲因成篇以寄','毛滂','宋','宋诗','song-poetry','','[]','東風欲辭閶闔殿，未向百花枝上見。',112,'全唐诗/poet.song.70000.json','["東風欲辭閶闔殿，未向百花枝上見。", "先拂瑤臺玉蘂叢，聯翩時落玲瓏片。", "水晶宮中清曉寒，蝴蝶窺簾輕暝旋。", "素光冷逼翠雲裘，玄冰暗結青光研。", "詩成玉屑帯冰書，興隨月繞清溪徧。", "兔園老筆生陽春，墨葩不待微和扇。", "明朝當見郢中吟，雕樽快覆鵝黄面。"]'),
('9199a0d6-d9ac-41d4-b00e-4c3c215eac96','劉秀才明仲當赴禮部試從縣令毛某乞詩聊作一首','毛滂','宋','宋诗','song-poetry','','[]','君不見廣文博士老鄭虔，才名四十寒無氈。',102,'全唐诗/poet.song.70000.json','["君不見廣文博士老鄭虔，才名四十寒無氈。", "又不見漢陽計吏趙明叔，文章不如一囊錢。", "胸中道腴五味足，外雖枯槁中芳鮮。", "不妨止有書一束，索米未肯侏儒賢。", "平生固用筆耕爾，行發墨頴收豐年。", "會當少見會稽綬，勿嗟已賣瑯琊田。"]'),
('1bc9033b-461b-4d83-a8dc-4c6971351d6a','次韻曹子方對雪以詩見招觀燈','毛滂','宋','宋诗','song-poetry','','[]','柳外東風旗影轉，身遠鳴珂心想見。',112,'全唐诗/poet.song.70000.json','["柳外東風旗影轉，身遠鳴珂心想見。", "碧瓦朱樓不夜城，走馬插花春一片。", "錦靴玉帯簇金鞍，回雪驚鴻都轉旋。", "我書細字對短檠，油盡燈昏月窺研。", "那知研節有七盤，但課舊書須百徧。", "病骨煩招愧後車，新詩乞與書團扇。", "明年相望隱侯鄉，猶共碧霄端正面。"]'),
('6f1f3d55-b0e6-4233-8948-87e3a4d6e9c9','對巖桂一首寄曹使君','毛滂','宋','宋诗','song-poetry','','[]','玉階桂影秋綽約，天風爲捲浮雲幕。',128,'全唐诗/poet.song.70000.json','["玉階桂影秋綽約，天風爲捲浮雲幕。", "嬋娟醉眠水晶殿，老蟾不守餘花落。", "蒼巖忽生雲月裔，仙芬凄冷真珠萼。", "娟娟石畔爲誰妍，香露著人清入膜。", "夜深碎月寒相就，酴醾却作傷春瘦。", "弄雪仙人淡紵衣，烟裙不著鴛鴦繡。", "眼中寒香同誰惜，冷吟徑召梅花魄。", "小蠻爲洗玻瓈船，晚來秋甕葡萄碧。"]'),
('24e620d5-b6b7-44c8-ae4c-f445153895f2','久客','毛滂','宋','宋诗','song-poetry','','[]','平生故人同偪仄，近者不見雲泥隔。',176,'全唐诗/poet.song.70000.json','["平生故人同偪仄，近者不見雲泥隔。", "男兒命好百不憂，封侯起第如戲劇。", "我癡正亦坐命窮，眼暗頭童守書策。", "風吹破屋雪入懷，獨與蝸牛夜爭席。", "舊雨人來今不來，唯有五窮充上客。", "人生覊旅誰過我，欲歸豈惜還鄉幘。", "腹中鬱勃不耐事，何用使人輕跛瘠。", "登山未厭日月流，掩關但恐功名迫。", "讀書豈從升斗計，勞生却爲精神惜。", "不能與君爭上車，主人未必如車澤。", "但煩東風送帆脚，搖竿鼓枻三江碧。"]'),
('eb0c6961-f59c-453a-8a2e-2f362a0e9438','僕性懶慢喜睡而吏事亦早休因得遂其欲琳老數語僕曰當屈伸步趨以散欎滯乃以詩送白术或云餌术能長生絕穀致神仙苟未至尚能耐寒暑其骨健輕難老儻然則僕異時芒屨布裘步尋此老於徑山之上爾','毛滂','宋','宋诗','song-poetry','','[]','先生曉開城旦書，坐與老農相囁嚅。',288,'全唐诗/poet.song.70000.json','["先生曉開城旦書，坐與老農相囁嚅。", "槐陰翠圓吏已散，歸來下簾手撚鬚。", "胸中百紙無處使，静看窮達如呼盧。", "身閒睡飽亦不惡，何用一躍驚駘駑。", "去年鑿池築潛玉，清夜明月掛碧蘆。", "先生獨吟亦徑醉，誰見露鶴寒相呼。", "徑山老人笑疏懶，云當運動如戶樞。", "朝來此老意不已，溪寺破雨遺天蘇。", "紫房鴈觜擢烟縷，細根蚯蚓蟠苔膚。", "茯苓雖老避芳液，團參已貴慚雲珠。", "先生領意手自植，衣袂馥馥侵蘼蕪。", "從今抱甕十日往，欲將後健酬前劬。", "何時一飽翳鳯凰，緱山月夜聽笙竽。", "長吟往覓五色麟，翩然那復煩雙鳬。", "坐看白駒變古今，浮漚流電皆須臾。", "此語險怪儻未然，引年聊與昌陽俱。", "不須仙人九節杖，他年要與猱爭途。", "凌霄峰頭覓此老，登山過水安用扶。"]'),
('008e18d2-c162-4a19-8812-cf4034442bf4','陪曹使君飲郭别乘舍夜歸奉寄','毛滂','宋','宋诗','song-poetry','','[]','金波灔灔梨花玉，春色兩枝嬌映肉。',176,'全唐诗/poet.song.70000.json','["金波灔灔梨花玉，春色兩枝嬌映肉。", "夜堂鶯燕落梁塵，秋簾風露昏銀燭。", "倦客歸來半白頭，舊約參差兩黄菊。", "新年斗酒亦徑醉，道舊驩然能五六。", "御史家兒反温克，風前玉樹何由俗。", "上客凛凛八尺身，秀在兩眉詩在腹。", "醒狂司隸醉奈何，猛雨瀾翻無軟熱。", "不嫌呼酒反勸君，要看春空雲郁郁。", "明朝寧辭一日病，清時未可三閭獨。", "倒冠落佩郭南門，長庚晱晱山簇簇。", "回頭一笑墮渺茫，卧聽桐魚喚僧粥。"]'),
('f23fb317-1d2a-4658-99d3-22d573a5fb18','曹使君置酒石橋山用肉字韻作詩見招不果往復用前韻奉寄','毛滂','宋','宋诗','song-poetry','','[]','玻璃瓶中新壓玉，趨膾腥脣脯麟肉。',176,'全唐诗/poet.song.70000.json','["玻璃瓶中新壓玉，趨膾腥脣脯麟肉。", "紫絲步障破烟霏，飴鼎灼炊千蠟燭。", "山英餼公却薄相，木蘭墜露和秋菊。", "此公骨秀氣欲仙，石室名深三十六。", "端知仁祖有勝致，豈比彦倫徙雋俗。", "速收熊軾屏旌牙，細步雲梯上巖腹。", "局畔雖無斧柯爛，林間恐有蟠桃熟。", "素書自愧無因緣，蕙路難陪踏芬郁。", "南山食蕨得我専，東山攜妓唯公獨。", "他年丘壑定參差，小留莫遣歸心簇。", "相對行厨洗玉盤，松花自煮顔家粥。"]'),
('048ed323-6a44-428e-ab91-d058f10a0ead','謝人分寄密雲大小團','毛滂','宋','宋诗','song-poetry','','[]','密雲不雨西郊黑，小龍蜿蜒出朝夕。',336,'全唐诗/poet.song.70000.json','["密雲不雨西郊黑，小龍蜿蜒出朝夕。", "中有濯枝三日霖，可洗流金千里赤。", "大龍雨足意貎閒，萬里澤流纔一息。", "無心自爲百穀仰，變化風雲聊戲劇。", "一杯洗心未足言，看瀁滄溟太空濕。", "大月已圓當久照，小月未滿哉生魄。", "雨龍出此雲月間，背負青天擁霄碧。", "豈惟大旱有雲霓，解作豐年雪花白。", "黄綾袋子天上來，本是閩山早春色。", "金盤珠露猶浥封，瓊房玉芝記相識。", "朱門日上三槐梢，大官初頒萬錢食。", "松風忽響第一泉，乳花徐開練波立。", "我公胸中冰雪明，不受一塵乘間入。", "寧煩多飲氣自清，乞餘賤客猶能及。", "此客覊賤亦喜茶，老葉唯知煎若澀。", "藜羮粟飯每稱是，九天雲腴詎應得。", "舊聞作匙用黄金，擊拂要須金有力。", "家貧點茶秪匕筯，可是鬬茶還鬬墨。", "東歸得此希世珍，真同被褐而懷璧。", "筆牀茶竈下三江，欲寄殘年向泉石。", "砂缾煮湯青竹林，會有玉川來作客。"]'),
('2114b3d0-e316-4de4-bbc8-e0c8231a2eaf','東風辭','毛滂','宋','宋诗','song-poetry','','[]','凍雲不凝層冰活，阿香推車上空闊。',352,'全唐诗/poet.song.70000.json','["凍雲不凝層冰活，阿香推車上空闊。", "龍蛇夢驚鱗甲暖，霰雪影斷清光奪。", "玉帝手持發生機，馳召東風俾迴斡。", "東風駕言正月頭，先驅持律吹九州。", "勞苦萬物抱憔悴，嘘呵太和如汗流。", "草根暖回土膏動，僵冷盡起寒威收。", "習習熙熙遠相屬，原隰龍鱗吹小綠。", "韶光漸深人不知，但見新新自相續。", "珠璣零露日繽紛，要助東風力作春。", "向使不來慰枯槁，正應合抱皆樵薪。", "眼明初破玄冥黑，咄嗟萬物回顔色。", "何但桃李著榮華，未遺兔葵并燕麥。", "萬物之命懸東風，誰云蘭臺敢爭雄。", "披襟受之不容易，羣公不有歸我公。", "我公人英國尚父，代天與天通肺腑。", "夔龍土苴直唾棄，有作自令物鼓舞。", "爲時生公豈非天，身任重大寧偶然。", "氣壓千官山不動，德行四海春無邊。", "東風功成看萬彙，雨露涵濡寧惜費。", "我公經綸亦如春，惠養元元作元氣。", "萬口祝公如一辭，願公顔朱髪常黟。", "那知東風共無邊，年年會與青春期。"]'),
('8b4179fd-3e5f-4465-ad1e-970f58afa51d','上曾樞密','毛滂','宋','宋诗','song-poetry','','[]','燕齊日暮客不歸，新豐主人豈相知。',224,'全唐诗/poet.song.70000.json','["燕齊日暮客不歸，新豐主人豈相知。", "不須買絲繡平原，不用黄金鑄子期。", "會當酸鹹有同好，主簿且須歸祭竈。", "請見臨川太尉公，此語難爲俗人道。", "我公悅士甘如肉，萬錢供客飯脱粟。", "讀書始堪屬大事，誰論少文織薄曲。", "眼看齊相不六尺，太史猶忻事鞭策。", "胸中端正在眸子，巖電兩瞳秋漢碧。", "致君堯舜不足驚，升平本付公輩人。", "西郊濃雲含雨色，可勝枯槁懷陽春。", "門前賓客馬如蟻，誰是我公天下士。", "趦趄欲進仍厚顔，紛紛無乃遼東豕。", "蹇驢破帽棲塵坌，曳裾最晚空餘恨。", "草奏猶堪試傔人，無令歸作潛夫論。"]'),
('07e04d6a-fce0-46c8-a72c-5d25906ca939','元度生日','毛滂','宋','宋诗','song-poetry','','[]','臨安有山插圓紫，公家松楸當峻峙。',256,'全唐诗/poet.song.70000.json','["臨安有山插圓紫，公家松楸當峻峙。", "子胥濤江相向流，秦望横前爲案几。", "衆言北山絕雄勝，世當公相貴莫比。", "那知上帝賚良弼，嶽靈孕秀初萌此。", "有山如是固有人，兹雖人爲亦天理。", "公生尚少抱經綸，前無夔龍何獨似。", "胸中五經通聖人，筆端三代尊天子。", "富貴相尋蚤厭餘，功名自會非所喜。", "惟天五福不可求，與公俱生亦久矣。", "生日壽公寧免俗，强復囁嚅空可鄙。", "矧我何物可厚公，世味都如一杯水。", "古人白髪痛掃除，强飯黄精力能爾。", "公餐道腴睟在面，何待草木堅髪齒。", "願公廊廟等山林，安樂百年無此彼。", "非公自壽盖壽人，坐看同老陶唐氏。", "端如八柱屹青蒼，共承峻極何時已。"]'),
('cd8cd547-7b3d-463a-8a75-405679220bbb','隋堤採蕈','毛滂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老夫少時性豪侈，頗復慨想諸公子。',352,'全唐诗/poet.song.70000.json','["老夫少時性豪侈，頗復慨想諸公子。", "家徒四壁不自憐，客來笑呼客且止。", "牧羊幸得時擊鮮，種秫足救缾罍恥。", "萍虀豆粥何足數，紅粱雀黍屢登匕。", "老來百呼無一諾，空瓢但酌三江水。", "侍祠何功費太倉，月賜萬錢良過矣。", "秋採菊英春採薺，歲月無憂三百指。", "西湖兩年相慰藉，東風爲長蓴絲紫。", "年來吏滿官有程，退無可耕那得已。", "曉猿夜鶴謝游從，筆牀茶竈供行李。", "異時浮家淮海上，魚鰕舟量賤無比。", "白魚截玉數尺長，本不論錢數魴鯉。", "祇今寸鱗乃許價，無魚自應相貴爾。", "謂當此行且空飯，彈鋏而歌遶淮市。", "誰知一飽不足慮，造物尚得相料理。", "榆堤雨潤風力和，老楊出菌鶵駢觜。", "輪囷長芽長雲葉，磊落小叢攅玉蘂。", "呼兒採掇歸自烹，不遣辛酸亂清美。", "五芝風味均茵憑，八珍品目當奴婢。", "不貪俎豆逐駑馬，肯同腥羶怒螻蟻。", "君看五鼎或殺身，未如老楊饑足恃。", "後逢枯朽慎勿薪，太和蒸之有如此。"]'),
('14554730-4249-4769-b03c-75cf02a6629d','早春','毛滂','宋','宋诗','song-poetry','','[]','女夷爭名亦早計，凌寒破臘回春意。',144,'全唐诗/poet.song.70000.json','["女夷爭名亦早計，凌寒破臘回春意。", "不待梅花送消息，細風平日先妍媚。", "野塘冰魚翻暖綠，官橋烟柳搖寒翠。", "佳人青鬢耐時節，彩幡初貼宜春字。", "唯有朱顔不我留，歲月翩翩定容易。", "柳車載窮安肯行，若華翳日何當試。", "憶昨狂心逐蝴蝶，踏月追春藉花睡。", "如今佩犢老東岡，杏花菖葉催田事。", "眼看風光搔白頭，斜陽抱來空多思。"]'),
('9f1e8414-920d-4a07-9a27-5b0fef5dc6f7','師文莫君以詩從僕求字顧非所長聊作一篇姑慰其厚意而已','毛滂','宋','宋诗','song-poetry','','[]','廣文無氈風撼頰，凍坐慈恩書柿葉。',160,'全唐诗/poet.song.70000.json','["廣文無氈風撼頰，凍坐慈恩書柿葉。", "乞米珍題矯龍鳯，望粥嬌兒鬧鵝鴨。", "不須歐家管城子，鏤象雕犀作袍帢。", "娥眉曼睩初丰容，一笑自粲非寶靨。", "當時臨池亦苦矣，烟蒼雨暗漫襟袷。", "幾何白骨變黄泥，安用玉軸留華篋。", "要當約略記姓名，作底碑傍坐疲苶。", "我今姓名亦懶記，几硯塵埃卧羊鬛。", "君詩求字得我驚，索金懸磬真所乏。", "歸田當賦覓桃詩，豈有來禽青李帖。"]'),
('83ededf0-9c42-4abc-baa5-909813c6e775','上湖守余行老','毛滂','宋','宋诗','song-poetry','','[]','先生吟文煩頰舌，未免諸生笑於列。',240,'全唐诗/poet.song.70000.json','["先生吟文煩頰舌，未免諸生笑於列。", "跋前疐後誰使然，只有名多磨不滅。", "燕公策高思精壯，筆下辭華爛文纈。", "岳陽少屈何足云，自喜江山助清絕。", "墨畦筆逕久榛蕪，道山初識今文伯。", "鳯凰池畔未歸身，水晶宮裏重遊客。", "讀書不知已幾世，汲古長餘綆千尺。", "莫貪雲水供醉吟，尚有典章須粉澤。", "防風山前癡病吏，自笑著書玄尚白。", "蓬頭承甖十年事，過眼法書今霧隔。", "那知流落得依憑，天與虺隤寛轡策。", "汀洲白蘋春幾許，江南日落汀洲古。", "風光無恙似當時，猶與溪山相媚嫵。", "昔人苦吟終不盡，秪今餘秀當勤取。", "阿房賦客舊主人，試數文章猶第五。"]'),
('cfcbb98d-96fe-465b-ae8a-9d23dbe59999','題雷峰塔南山小景','毛滂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','錢塘門外西湖西，萬松深處古招提。',128,'全唐诗/poet.song.70000.json','["錢塘門外西湖西，萬松深處古招提。", "孤塔昻昻據要會，湖光灔灔明巖扉。", "道人安禪日卓午，寺外湖船沸簫鼓。", "静者習静厭紛喧，游者趨歡窮旦暮。", "非喧非寂彼何人，孤山詩朋良獨清。", "世間名利不到耳，長與梅花作主盟。", "嗟我於此無一得，曾向峰前留行跡。", "天涯暮景盍歸來，坐對此圖三太息。"]'),
('3db7814e-a8e9-47cc-ad62-f95be7d54a01','寄程漕','毛滂','宋','宋诗','song-poetry','','[]','風流三老今無有，明珠雙璧公其後。',128,'全唐诗/poet.song.70000.json','["風流三老今無有，明珠雙璧公其後。", "長安初見紫微人，山陽途識生風手。", "同時蜀秀共差遲，今日吳餓付忠厚。", "吳餓欲飽談笑了，要使嘉禾出稂莠。", "紫薇賓客多雲霄，誰數諸侯牛馬走。", "黄金單盡會屠龍，白髪鬅鬙成畫狗。", "絳衣玉具無處覓，將軍縱在大夫取。", "公歸願作水衡丞，敢厭督郵辭五斗。"]'),
('717a4bdd-1eef-499d-8dc6-55db9572e8d1','寄曹使君','毛滂','宋','宋诗','song-poetry','','[]','幕中墨客隨車後，架上牙籤遮坐右。',176,'全唐诗/poet.song.70000.json','["幕中墨客隨車後，架上牙籤遮坐右。", "唯留筆研乃自鐍，豈惜車茵容吏嘔。", "青霞老去雲海深，舊遊尚見翻濤手。", "寄聲秀句風入懷，坐念清標月當牖。", "天公厚我過穆生，何止饜韓仍飫柳。", "請同韶濩公勿疑，老馬由來識途久。", "近緣嗜酒識聖賢，已付長酣無可否。", "公當紫綬日垂腰，我已秃襟時見肘。", "慕公澄撓等清濁，歎我雕污終糞朽。", "詩從子建豈易親，句語懷英那肯偶。", "清風自已入公脾，我如惡木何勞吼。"]'),
('35f6771d-c571-4574-8ec1-8f7830233438','代人和御製上巳錫宴詩  其一','毛滂','宋','宋诗','song-poetry','','[]','賜禊追三日，聞鶯囀萬年。',48,'全唐诗/poet.song.70000.json','["賜禊追三日，聞鶯囀萬年。", "恩深重湛露，氣暖入非煙。", "睿作端知聖，清尊不翅賢。", "眼明驚既醉，奎彩下雲天。"]'),
('68d7ebc2-51ac-4584-9bee-97188dfd1d04','代人和御製上巳錫宴詩  其二','毛滂','宋','宋诗','song-poetry','','[]','曲水傳觴盛，皇祇布德初。',48,'全唐诗/poet.song.70000.json','["曲水傳觴盛，皇祇布德初。", "海波翻雅奏，雲露濕華裾。", "晴送君恩暖，寒收物意舒。", "春耕無歎息，庶不負于胥。"]'),
('029b4b0f-e0ce-4cbf-a7d8-37f5c919fe35','送夏辟疆解官','毛滂','宋','宋诗','song-poetry','','[]','北風吹勁翮，凌厲欲雲奔。',48,'全唐诗/poet.song.70000.json','["北風吹勁翮，凌厲欲雲奔。", "門棒斂行色，縣花消别魂。", "進舟寒瀨澀，回首亂山昏。", "珍重操刀事，余言淡可吞。"]'),
('1b0cc68a-3b69-4225-bf9e-434c9b9604ea','趙宣德生日','毛滂','宋','宋诗','song-poetry','','[]','仁飇扇佳氣，暐暐自門廬。',48,'全唐诗/poet.song.70000.json','["仁飇扇佳氣，暐暐自門廬。", "閒日風波外，長年霜雪餘。", "凍醪含鑿落，春意動篨䈝。", "定有升仙骨，黄精易掃除。"]'),
('fc0e816f-a4b4-4178-a740-7a3257624c2d','送徐次山督郵之官','毛滂','宋','宋诗','song-poetry','','[]','外臺綱紀掾，先辟漢名人。',48,'全唐诗/poet.song.70000.json','["外臺綱紀掾，先辟漢名人。", "霜隼九秋氣，風駒千里塵。", "鄉評元自好，府望復名新。", "竹箭黄金鏃，送君江水濱。"]'),
('c67c3aa0-cb09-473d-90be-1ed0f1a0ebf0','訪琳老題溪上小軒','毛滂','宋','宋诗','song-poetry','','[]','小檻閒風物，高僧秀肺腸。',48,'全唐诗/poet.song.70000.json','["小檻閒風物，高僧秀肺腸。", "隔溪通竹色，開戶納山光。", "撥雪晨蔬瘦，燒松午茗香。", "淵明歸賦急，聊復此徜徉。"]'),
('21b4175d-8871-41f0-9cca-ca25f833eb4f','登普寧寺歲寒庵面江山之勝令人欲賦而長老因公出詩集相示作此詩謝之','毛滂','宋','宋诗','song-poetry','','[]','此老諸緣薄，詩情忽漫深。',48,'全唐诗/poet.song.70000.json','["此老諸緣薄，詩情忽漫深。", "敲門移穩字，彈指得真心。", "松竹藏幽討，溪山助苦吟。", "解鞍聊爲賦，去不負登臨。"]'),
('ff438f7a-cb3c-479e-b4c1-f4d6ff508232','八月二十八日挈家泛舟游上渚詩','毛滂','宋','宋诗','song-poetry','','[]','秋色向幽處，浮家聊遠尋。',48,'全唐诗/poet.song.70000.json','["秋色向幽處，浮家聊遠尋。", "醉来蓬鬢亂，臥入蓼花深。", "雲壑封詩物，煙波留客心。", "未應兒輩覺，餘醁且勤斟。"]'),
('4792d7c8-1638-4d53-a393-09017bcc66b8','和王宣義買菊栽二首  其一','毛滂','宋','宋诗','song-poetry','','[]','秋風有好色，寄在菊花團。',48,'全唐诗/poet.song.70000.json','["秋風有好色，寄在菊花團。", "弛擔知新主，臨池得細看。", "金房迎日秀，玉露作香寒。", "獨負東籬意，年来漉酒乾。"]'),
('1d042054-bb72-4da9-9c1e-bf0d02dad1ce','和王宣義買菊栽二首  其二','毛滂','宋','宋诗','song-poetry','','[]','未見花盈把，先教蜂作團。',48,'全唐诗/poet.song.70000.json','["未見花盈把，先教蜂作團。", "孤根聊得售，秀色後當看。", "莫訝全開晚，須知獨耐寒。", "雲含墮簷日，天恐露香乾。"]'),
('8be1f466-ef05-414c-a9da-451749f613d4','闍黎從上人予往年香火院學徒也去之天竺益求其師之說歸爲邑人言之予自江東歸見於昭慶寺喜其進學不已爲作此詩','毛滂','宋','宋诗','song-poetry','','[]','世外忘家子，歸来誰與游。',48,'全唐诗/poet.song.70000.json','["世外忘家子，歸来誰與游。", "燒香如意夜，茹菊鉢盂秋。", "獨節已蕭冷，諸緣應罷休。", "渡江聞道日，少爲故山留。"]'),
('95711289-14d5-4935-b977-a49bb3454105','去國呈蔡元度','毛滂','宋','宋诗','song-poetry','','[]','去國黄流急，搔頭白髮新。',48,'全唐诗/poet.song.70000.json','["去國黄流急，搔頭白髮新。", "牛衣還卒歲，狗監定何人。", "奏傔寧妨跛，爲郎正礙貧。", "鄙文無恙否，醤瓿盍相親。"]'),
('c7c0239a-64ab-47d4-a4df-3c7a1ac46795','書禪静寺集翠堂示堂中老人琳徑山詩','毛滂','宋','宋诗','song-poetry','','[]','煙岫供寒翠，風簾舞小晴。',48,'全唐诗/poet.song.70000.json','["煙岫供寒翠，風簾舞小晴。", "短墻分竹色，虚戶納松聲。", "弄筆雲窗暖，煎茶玉醴輕。", "端知孤檜月，獨伴夜禪清。"]'),
('4c9f959a-ecca-4c03-a6e4-71475a0f8b81','次沈會宗韵','毛滂','宋','宋诗','song-poetry','','[]','故人老蕭散，久客寡諧同。',48,'全唐诗/poet.song.70000.json','["故人老蕭散，久客寡諧同。", "病骨侵山雨，孤帆落渚風。", "水清應弔影，坐闃想書空。", "我亦青州闊，經年不一中。"]'),
('4e3ebd8c-a936-4c48-a74b-899bdaf5509d','謝陳進士見示詩賦并以爲别','毛滂','宋','宋诗','song-poetry','','[]','陳子賦可喜，十詩仍好辭。',48,'全唐诗/poet.song.70000.json','["陳子賦可喜，十詩仍好辭。", "亦云餘事爾，何累壯夫爲。", "語浸初已漫，筆峰時出奇。", "息肩當益學，葵圃未應窺。"]'),
('13052aaa-a488-45ce-8cb1-1cdb2d375552','趙樂道輓詩二首  其一','毛滂','宋','宋诗','song-poetry','','[]','耆舊彫零盡，歸来悲故鄉。',48,'全唐诗/poet.song.70000.json','["耆舊彫零盡，歸来悲故鄉。", "雲山横爽氣，杖履屬空牀。", "蚤發名難没，終榮德未央。", "芝蘭日夜長，遺範在諸郎。"]'),
('630f475d-110c-4d69-96d5-e3ce30a9fee1','趙樂道輓詩二首  其二','毛滂','宋','宋诗','song-poetry','','[]','貧賤通姻好，凄凉累賞音。',48,'全唐诗/poet.song.70000.json','["貧賤通姻好，凄凉累賞音。", "空知典刑在，誰聽短長吟。", "飛鶴窺塘水，眠牛傍柏林。", "龜魚迎拄杖，猶出畫橋陰。"]'),
('157685e9-dd99-4717-bc79-5114ccf17570','徐守生辰','毛滂','宋','宋诗','song-poetry','','[]','徐卿二子後，吉夢亦羆熊。',48,'全唐诗/poet.song.70000.json','["徐卿二子後，吉夢亦羆熊。", "骨氣本英物，文華今鉅翁。", "聊因頷燕出，已覺額犀豐。", "誰伴歲寒色，冰霜十八公。"]'),
('47706910-1102-468b-a77f-3a3ba2e1bf51','宿蓮花寺頃從清獻公游今十年矣','毛滂','宋','宋诗','song-poetry','','[]','一徑通松竹，入門聞夜香。',48,'全唐诗/poet.song.70000.json','["一徑通松竹，入門聞夜香。", "青燈孤照佛，斜月静歸廊。", "未厭逢僧拙，終慚涉世忙。", "十年猶彷彿，一夢自凄凉。"]'),
('2a2bcd54-e085-46c7-a21f-739829764d53','去國','毛滂','宋','宋诗','song-poetry','','[]','馬劍何妨壯，琴書半不輕。',48,'全唐诗/poet.song.70000.json','["馬劍何妨壯，琴書半不輕。", "心通平野闊，眼接衆山明。", "老大空行李，疏慵豈利名。", "夏侯知苦學，殊未勸歸耕。"]'),
('dd973d60-f6bc-408c-ad4d-6fb3b424bc81','林進士數見過又遺一詩輒以奉報','毛滂','宋','宋诗','song-poetry','','[]','夫子胡爲者，行吟頗自奇。',48,'全唐诗/poet.song.70000.json','["夫子胡爲者，行吟頗自奇。", "少年應苦學，今日定何之。", "天地空羸馬，肝膓飽舊詩。", "江邊餬口掾，風雨共凄凄。"]'),
('cd764c6a-0b1d-4a03-87c1-9d0452d87f51','束裝','毛滂','宋','宋诗','song-poetry','','[]','束裝親匣劍，撥火唤勞饙。',48,'全唐诗/poet.song.70000.json','["束裝親匣劍，撥火唤勞饙。", "鴉散鷄聲斷，煙低野色分。", "徘徊半樹月，拍塞一山雲。", "叫助日車上，扶桑猶未聞。"]'),
('89de623e-ab26-4efc-9392-74b14dc38dfc','逢故人','毛滂','宋','宋诗','song-poetry','','[]','落日仍江縣，相逢下馬鞍。',48,'全唐诗/poet.song.70000.json','["落日仍江縣，相逢下馬鞍。", "頻憂從者病，可奈故人寒。", "老大囊書脱，平生匣劍乾。", "長年祇少睡，忽漫語盤桓。"]'),
('3f3165f6-fc6f-4151-9025-bb5118a404f1','欲入山訪參寥預令探梅','毛滂','宋','宋诗','song-poetry','','[]','誰作東州客，支公合往還。',48,'全唐诗/poet.song.70000.json','["誰作東州客，支公合往還。", "想無詩外事，聊輟定中閒。", "拂石須相憩，留雲欲共攀。", "爲尋梅發處，先過向南山。"]'),
('f0436f1c-6084-4a62-b6c3-ac480321a5e2','仲夏月夜懷陳西安','毛滂','宋','宋诗','song-poetry','','[]','飛蓋西園夜，抽毫失謝君。',48,'全唐诗/poet.song.70000.json','["飛蓋西園夜，抽毫失謝君。", "徘徊下修竹，暗澹入浮雲。", "素彩漫仍見，微芒細可分。", "徒知此紈扇，離畢未前聞。"]'),
('294ad572-879c-441c-b2f2-89db8cc0df0d','十月十日訪琳道人於禪静寺與之徘徊泉石間甚久道人云有大龍團藏亦數年食且幾盡因出刀圭許而龍軀僅餘一爪色理極蒼古又云趙清獻公嘗得須菩提畫像乃張畫壁間煎所謂龍爪以餉僕迫夜來歸坐縣之東堂見月奉寄一首','毛滂','宋','宋诗','song-poetry','','[]','道人泉石畔，餉我欲盤桓。',48,'全唐诗/poet.song.70000.json','["道人泉石畔，餉我欲盤桓。", "見爪蒼龍古，顰眉古佛寒。", "家風真草草，詩句自珊珊。", "今夜東堂夢，雲披月萬竿。"]'),
('93567adc-d5f0-4c7d-9443-d757274b4d19','崇福宮雨中種柏','毛滂','宋','宋诗','song-poetry','','[]','未障侵簷日，先留出殿煙。',48,'全唐诗/poet.song.70000.json','["未障侵簷日，先留出殿煙。", "雨根蚯蚓活，風葉鳳凰翩。", "直節從孤瘦，寒姿定老堅。", "君王千萬壽，合作酒如泉。"]'),
('6035bc6a-93b7-46c7-9932-02e906969548','和賈耘老  其一','毛滂','宋','宋诗','song-poetry','','[]','渴令平生病，年來病更多。',48,'全唐诗/poet.song.70000.json','["渴令平生病，年來病更多。", "腰仍難老折，膓亦舊無他。", "知子眠三逕，逢秋欲七歌。", "勳名郵傳爾，唯日飲無何。"]'),
('8ea26ea2-ecc8-4c87-ab3e-43c3bd776ba4','和賈耘老  其二','毛滂','宋','宋诗','song-poetry','','[]','河陽春在否，柳外小朱扉。',48,'全唐诗/poet.song.70000.json','["河陽春在否，柳外小朱扉。", "曲徑虵應鬬，危簷鳥欲飛。", "主人同燕幕，歸意屬漁磯。", "莫待羣花笑，秋風鬢綠稀。"]'),
('77b7fc3b-1718-48a2-8543-58e3ceb96df8','熊侍郎挽詞','毛滂','宋','宋诗','song-poetry','','[]','蚤見聲華就，終違勳業尋。',48,'全唐诗/poet.song.70000.json','["蚤見聲華就，終違勳業尋。", "餘忠朝露泣，遺直夜臺深。", "威落諸蠻膽，恩留五嶺心。", "從今舍人様，萬柏覆蕭森。"]'),
('98d2564a-4609-49e1-884c-8a4a6d4c565f','題陳用中行藏樓','毛滂','宋','宋诗','song-poetry','','[]','此樓託蕭冷，莫會子登臨。',48,'全唐诗/poet.song.70000.json','["此樓託蕭冷，莫會子登臨。", "弔影漫愁獨，書空誰語深。", "簾開不盡眼，雲起未休心。", "咫尺顔淵坐，高風無古今。"]'),
('925133ec-16bb-4e9e-8214-24904559bf27','鄭君瑞示同諸公遊定空佳什僕亦久欲與君瑞尋春衰病方窘風雨以故未果聊次韻一首','毛滂','宋','宋诗','song-poetry','','[]','佳哉五英雋，並駕玉爲林。',48,'全唐诗/poet.song.70000.json','["佳哉五英雋，並駕玉爲林。", "傾蓋分不淺，好山情已深。", "春光不約略，晴意恰沉吟。", "老病未堪出，詩鋒遙見侵。"]'),
('9ef4834f-e466-4a89-a728-68e300ca56a8','送教長老入山','毛滂','宋','宋诗','song-poetry','','[]','秋容正搖落，山意恰淒清。',48,'全唐诗/poet.song.70000.json','["秋容正搖落，山意恰淒清。", "冰徹萬緣冷，雲隨兩屐輕。", "冥鴻那復下，膏火莫重明。", "天地郵亭爾，百年真倦生。"]'),
('f5b8baf3-94d4-4f96-8002-23df0de16da6','送僧常妙還永嘉','毛滂','宋','宋诗','song-poetry','','[]','杖策辭江寺，秋途誰與偕。',48,'全唐诗/poet.song.70000.json','["杖策辭江寺，秋途誰與偕。", "霜風侵布衲，草露濕芒鞋。", "收鉢無餘事，還鄉非俗懷。", "金剛真有力，魔避不須排。"]'),
('8d88ed85-d5d8-42a0-a5af-937473bd9e03','無畏道人居觀音院奉寄一首','毛滂','宋','宋诗','song-poetry','','[]','松石真佳伴，雲山得破顔。',48,'全唐诗/poet.song.70000.json','["松石真佳伴，雲山得破顔。", "高人本無住，倦翮自知還。", "詩外塵緣盡，齋餘齒頰閒。", "何消一句子，截斷碧溪灣。"]'),
('5c3b8dca-dc48-4d1b-9495-0777328653f9','曉出響應山過静林道中奉寄琳老','毛滂','宋','宋诗','song-poetry','','[]','曉色開霜坂，饑烏啄麥畦。',48,'全唐诗/poet.song.70000.json','["曉色開霜坂，饑烏啄麥畦。", "山腰餘雪瘦，天面冷雲低。", "寒意梅花北，禪心柏子西。", "窗前借殘月，照我度前溪。"]'),
('2975ffce-c554-46fe-aac6-1ee691625381','下渚湖','毛滂','宋','宋诗','song-poetry','','[]','春渚連天闊，春風夾岸香。',48,'全唐诗/poet.song.70000.json','["春渚連天闊，春風夾岸香。", "飛花渡水急，垂柳向人長。", "遠岫分蒼紫，澄波映渺茫。", "此身萍梗爾，泊處即吾鄉。"]'),
('49075d59-191d-4f80-9ef7-e065a58a6365','題餘英館','毛滂','宋','宋诗','song-poetry','','[]','故第園林改，遺亭壁戶新。',48,'全唐诗/poet.song.70000.json','["故第園林改，遺亭壁戶新。", "垂虹一橋月，夾繡兩隄春。", "花落俯流水，鳥啼懷故人。", "憑欄看翠竹，無意數游鱗。"]'),
('060f8a88-47e7-48fa-82ec-fc5d1bbe8cf6','上林內翰二首  其一','毛滂','宋','宋诗','song-poetry','','[]','內廷吳陸善文書，絕代如公可數渠。',64,'全唐诗/poet.song.70000.json','["內廷吳陸善文書，絕代如公可數渠。", "科斗他年載深厚，楞伽終日伴清虚。", "濟時即展經綸業，華國聊施采色餘。", "想爲君王話堯舜，玉堂對罷夜何如。"]'),
('cf6f262a-7026-4b82-995a-4842d3f5c9ee','上林內翰二首  其二','毛滂','宋','宋诗','song-poetry','','[]','短褐風霜可奈何，嬾求長袖舞陽阿。',64,'全唐诗/poet.song.70000.json','["短褐風霜可奈何，嬾求長袖舞陽阿。", "九遷行輩青雲滿，百謫形骸白髮多。", "束带壯懷渾齟齬，角巾閑約亦蹉跎。", "山公有意相題目，季緒無容獨詆訶。"]'),
('8d462b0d-4ddf-4294-8b6e-843213f42f21','次韻曹子方','毛滂','宋','宋诗','song-poetry','','[]','盾威正赫忽衰殘，人意渾如水面寛。',64,'全唐诗/poet.song.70000.json','["盾威正赫忽衰殘，人意渾如水面寛。", "觸石端来慰枯槁，隨車定見濕朱丹。", "初憂連畛秋無種，豈望如雲晚可觀。", "天遣商羊爲公舞，絕勝九仞見回鸞。"]'),
('47cfa6fb-301e-4db9-ae98-92805663ae3c','寄蔡學士','毛滂','宋','宋诗','song-poetry','','[]','陸陸微生不可論，半饑半飽過朝昏。',64,'全唐诗/poet.song.70000.json','["陸陸微生不可論，半饑半飽過朝昏。", "春来但見瞳花亂，寒退長餘鬢雪繁。", "老愧門墻忝賓客，歸来耒耜教兒孫。", "會應飛墮江湖去，定向離騷寄客魂。"]'),
('59081da2-50e7-45c3-9d31-08eeabf97792','師文莫君以僕治東園甚力官滿且去爲賦詩以道眷然之意次韻奉答','毛滂','宋','宋诗','song-poetry','','[]','小桃繁杏何須論，只要池邊竹半林。',64,'全唐诗/poet.song.70000.json','["小桃繁杏何須論，只要池邊竹半林。", "不養鳬鷖憐淥浄，苦留風月伴清深。", "後人来蔭十圍木，故老看移一畝陰。", "分付庭梅管春色，長官情味此花心。"]'),
('57b1d232-b917-424f-9565-c70bd4bcd6cb','次常山簡叔祥','毛滂','宋','宋诗','song-poetry','','[]','歸来久客鬢俱蒼，漸喜無人餽五漿。',64,'全唐诗/poet.song.70000.json','["歸来久客鬢俱蒼，漸喜無人餽五漿。", "未免高僧問勞苦，故應喬木慰凄凉。", "山中猿鶴人誰健，門外蒿莱想自長。", "爲謝邦人豈吾薄，要當六印遶腰黄。"]'),
('c83db071-9d9f-416e-a37f-17da45362fb7','柳軒雪夜','毛滂','宋','宋诗','song-poetry','','[]','曛黄飛雪已填門，獨夜人依老柳根。',64,'全唐诗/poet.song.70000.json','["曛黄飛雪已填門，獨夜人依老柳根。", "故遣捲簾從骨冷，不妨開卷自燈昏。", "餘英煮茗春雲動，潤氣留香宿霧繁。", "但覺詩脾兩清絕，可勞騷客賦招魂。"]'),
('7c928193-dbfa-4806-a018-b3bc3e7db39f','書懷寄贈曾公衮','毛滂','宋','宋诗','song-poetry','','[]','宦情光景半樵漁，病惰仍忘百紙書。',64,'全唐诗/poet.song.70000.json','["宦情光景半樵漁，病惰仍忘百紙書。", "賦就祇堪供醤瓿，齒殘未可釋鹽車。", "朱藍要使辭秋斷，芝菌猶當出腐餘。", "慚愧少翁能下士，馬曹知馬自應疏。"]'),
('70132aff-c23a-4c64-bb97-2ae0766c6328','仁義驛中','毛滂','宋','宋诗','song-poetry','','[]','騎驢何似賈司倉，行李唯餘古錦囊。',64,'全唐诗/poet.song.70000.json','["騎驢何似賈司倉，行李唯餘古錦囊。", "秋後恰容鷹脱架，春来會有燕投梁。", "清時無用材雖拙，白日能閒策亦長。", "慚愧平生負三尺，一成泉石欲膏盲。"]'),
('2f353fa1-2815-4634-aef7-c8a8f9376760','次韻許簿游響潭回','毛滂','宋','宋诗','song-poetry','','[]','一派飛泉濕嶺雲，巖花娟好尚餘春。',64,'全唐诗/poet.song.70000.json','["一派飛泉濕嶺雲，巖花娟好尚餘春。", "黄紬病惰誰如我，碧玉寒清自照人。", "山水窟中爲俗吏，簿書叢裏得詩鄰。", "一篇寵寄高難和，萬卷端知筆有神。"]'),
('45a7dcfd-734e-4f4d-a2af-bf3645f24844','東歸呈元度','毛滂','宋','宋诗','song-poetry','','[]','此生文字送分陰，羈旅無材發噤吟。',64,'全唐诗/poet.song.70000.json','["此生文字送分陰，羈旅無材發噤吟。", "鬢底星星侵晚色，胸中落落負初心。", "端知坐索長安米，那復能彈單父琴。", "投老襄陽真自棄，蹇驢東去亂雲深。"]'),
('ba9b7b04-0409-4ebb-8d18-fcc0c8d71577','哀程袁州','毛滂','宋','宋诗','song-poetry','','[]','坐令荆國得髦英，清獻先生語不輕。',64,'全唐诗/poet.song.70000.json','["坐令荆國得髦英，清獻先生語不輕。", "漢使曾觀楚風俗，蜀翁未識魯書生。", "楊林墜露隨沉魄，叢玉留詩負夙情。", "欲問典刑波浪闊，遙知蘭砌五經横。"]'),
('272baada-4967-4f56-8a8b-f0fbc72b4f75','郭别駕秋日行縣奉寄一首','毛滂','宋','宋诗','song-poetry','','[]','秋壑相迎故出奇，便應到處小遲遲。',64,'全唐诗/poet.song.70000.json','["秋壑相迎故出奇，便應到處小遲遲。", "不妨簿領紛遮眼，未礙嵐光秀入脾。", "小睡寧尋兒女夢，新詩定寫水雲姿。", "舊巾墊角風流在，何許杉篁暮雨時。"]'),
('487f01ca-9642-428d-96e5-48c0b1ec5563','從范使君求酒','毛滂','宋','宋诗','song-poetry','','[]','方寸陶陶事不根，但知力飲送朝昏。',64,'全唐诗/poet.song.70000.json','["方寸陶陶事不根，但知力飲送朝昏。", "無田種秫空爲吏，有麴成封即閉門。", "避暑此間真有意，悲秋今日得無言。", "孔公坐上多餘瀝，昜滿農家老瓦盆。"]'),
('e21606c7-5dfe-4e34-af50-54bc24b63a97','重來','毛滂','宋','宋诗','song-poetry','','[]','出門聊作書生詠，倚馬猶能梁父吟。',64,'全唐诗/poet.song.70000.json','["出門聊作書生詠，倚馬猶能梁父吟。", "汾水寧無注書地，秦關已老棄繻心。", "重來樵釣深相識，未遍湖山擬細尋。", "白眼何勞預人事，但知要得酒船深。"]'),
('3994afae-94fe-4360-94ca-c751c3339308','屬者觀池檻清明泉激石立蘆叢交碧文禽並絢翛然發湖山之遠態無輦轂之浮埃杜子美云朱門之泥塗士子不見其泥塗良非是也','毛滂','宋','宋诗','song-poetry','','[]','圖書多似道家山，池檻清虚不綺紈。',64,'全唐诗/poet.song.70000.json','["圖書多似道家山，池檻清虚不綺紈。", "萬壑春藏三石秀，五湖秋入兩蘆寒。", "冰泉噴激珠成貫，繡羽沉浮花作團。", "誰伴玉皇香案吏，光風霽月在闌干。"]'),
('785317f9-eef2-4a0d-922c-7465ee1cbc11','聞諸君不裹糧遊山暮歸清坐静林僧居相與樂以忘饑僕老病獨在見遺辱君瑞示詩盛道僧居梅竹之賞輙次韻奉答','毛滂','宋','宋诗','song-poetry','','[]','禪房何許最清深，庾嶺梅邊晉竹林。',64,'全唐诗/poet.song.70000.json','["禪房何許最清深，庾嶺梅邊晉竹林。", "餉客好山勝挈榼，遺予病骨任支琴。", "應餐秀色嚥溪茗，想待暗香來水沉。", "何似拍浮從我醉，夜船藉月碧千尋。"]'),
('f92b63a4-ef58-4142-95ed-074484061615','送巨中教授解官','毛滂','宋','宋诗','song-poetry','','[]','天公憐我欲無鄰，得近芝蘭久益芬。',64,'全唐诗/poet.song.70000.json','["天公憐我欲無鄰，得近芝蘭久益芬。", "定免幼安還割席，擬從東野若爲雲。", "歸鞭那有藍關雪，别夢應通魯水芹。", "强飯勉之書滿載，與君千里共斯文。"]'),
('b52ff95d-2062-4fe0-b16a-9b485a8caa7f','次韻琳老中秋月','毛滂','宋','宋诗','song-poetry','','[]','玉斧修輪滅玷痕，金精鑄魄凝寒清。',64,'全唐诗/poet.song.70000.json','["玉斧修輪滅玷痕，金精鑄魄凝寒清。", "綴雲都去秋心浄，囊露新添夜眼明。", "氣接瑤臺端可御，地漫銀漢定誰傾。", "何時天竺山前路，細聽煙崖墜子聲。"]'),
('5231b713-f96d-437f-946f-94dfe343a91f','仲夏月夜懷陳西安','毛滂','宋','宋诗','song-poetry','','[]','長悵浮雲點太清，祇今何許問天晴。',64,'全唐诗/poet.song.70000.json','["長悵浮雲點太清，祇今何許問天晴。", "渾憐短夜相催下，不放孤光自在明。", "幸與高樓通遠覽，未勞殘燭更前行。", "此心對酒蕭條在，咄咄置之聊自傾。"]'),
('95f6a614-8542-46cc-8661-2a6aaa64bff3','上執政','毛滂','宋','宋诗','song-poetry','','[]','廊廟無塵鑑色寒，私門誰啟手親關。',64,'全唐诗/poet.song.70000.json','["廊廟無塵鑑色寒，私門誰啟手親關。", "萬邦和氣君臣裏，一代文章伯仲間。", "多士揚眉詣東閤，真人拱手倚南山。", "青天白日才亭午，不遣雲隨霰雪還。"]'),
('4c87c4d6-bb0e-4d40-bc26-32d7243a5139','訪鄭叔詳回得花滿盤作短詩以寄','毛滂','宋','宋诗','song-poetry','','[]','參軍肯自笑蒼顔，花趁籃輿簇玉盤。',64,'全唐诗/poet.song.70000.json','["參軍肯自笑蒼顔，花趁籃輿簇玉盤。", "賸取必知叢蝶恨，欵行聊許路人看。", "娟娟静静春情好，淡淡濃濃粧色殘。", "已遣小蠻歌送酒，故教亂插竹皮冠。"]'),
('4a385758-2b77-4d1d-80b8-3c5abced72b2','東堂獨坐懷琳老二首  其一','毛滂','宋','宋诗','song-poetry','','[]','聞道年來多掩關，高情定滿渺瀰間。',64,'全唐诗/poet.song.70000.json','["聞道年來多掩關，高情定滿渺瀰間。", "秋風不怕清難忍，曉日應分暖伴閒。", "欲喚扁舟弄雲水，已疑小閣厭溪山。", "東堂枉把歸來賦，慚愧寒空倦翮還。"]'),
('153ae45e-448b-447f-b272-6db317ba0041','東堂獨坐懷琳老二首  其二','毛滂','宋','宋诗','song-poetry','','[]','柏爐煙冷尚餘薫，老去孤城愈不羣。',64,'全唐诗/poet.song.70000.json','["柏爐煙冷尚餘薫，老去孤城愈不羣。", "沙上晚晴知獨往，堂中秋思與誰分。", "隔溪有伴蕭蕭竹，對戶無情冉冉雲。", "南北東西均是寄，定回歸鴈不應聞。"]'),
('24d41e0e-a530-498c-84c9-78e5b12bd989','六月二十日舍賈耘老溪居旦起蔡成允見訪僕方蓬頭赤脚坐溪上乃用此見成允而君不以爲無禮反寄詩有褒借意甚愧過情戲作一首奉報','毛滂','宋','宋诗','song-poetry','','[]','寒溪破曉喜相過，不怪蓬頭尚養疴。',64,'全唐诗/poet.song.70000.json','["寒溪破曉喜相過，不怪蓬頭尚養疴。", "躍馬懷金君蚤晚，曆階歃血我蹉跎。", "詩人自與塵埃遠，病骨終慚粉澤多。", "别寄釣魚船上曲，要留風月伴煙蓑。"]'),
('1a611246-463b-4dc2-9d0f-b0ec71285bec','坤成節','毛滂','宋','宋诗','song-poetry','','[]','穆穆真人第幾天，九龍扶輦下非煙。',64,'全唐诗/poet.song.70000.json','["穆穆真人第幾天，九龍扶輦下非煙。", "定知蟾彩騰光夜，聊待蟠桃得熟年。", "國步無疆金柱健，官聲有道兔罝賢。", "大邦欲效封人請，珍重祇園妙相仙。"]'),
('4bd5f444-4837-423d-b0c5-7e63615f1a06','對月','毛滂','宋','宋诗','song-poetry','','[]','柳梢地面絕微風，一片寒光萬里同。',64,'全唐诗/poet.song.70000.json','["柳梢地面絕微風，一片寒光萬里同。", "冰骨直疑潛裏換，塵心都覺坐來空。", "蚌胎有露珠成顆，蟾窟無雲玉作宮。", "莫怪幽人吟到曉，不知清興自無窮。"]'),
('aab099db-0de7-4201-a0e6-68833720eccc','道上口占','毛滂','宋','宋诗','song-poetry','','[]','屹屹高山自兩邊，紛紛鷄鴨苦當前。',64,'全唐诗/poet.song.70000.json','["屹屹高山自兩邊，紛紛鷄鴨苦當前。", "敗垣過竹還當道，脱葉憑風欲半天。", "定恐黄茅藏伏兔，更呼青漢落飛鸇。", "一寒如此空形影，獨賴狐裘三十年。"]'),
('0c9135d3-e644-4bc2-bae0-6e84ba1ff856','謝郭倅見訪','毛滂','宋','宋诗','song-poetry','','[]','及榻青苔疊亂錢，端知骯髒倚門邊。',64,'全唐诗/poet.song.70000.json','["及榻青苔疊亂錢，端知骯髒倚門邊。", "蒿萊歲晚荒三徑，殽酒人疏問一廛。", "懶慢容教著帽進，傳呼驚起藉糟眠。", "分庭未覺題輿寵，下士徒知公子賢。"]'),
('3a7370f6-2bc9-4420-ad3a-02d962f29c50','建中上元以雨雪敗懸燈以國憂罷行樂僕又以老病連日在告辱師與成君見示佳章聊作一首','毛滂','宋','宋诗','song-poetry','','[]','老去追遊骨亦疲，黑甜唯覺睡如飴。',64,'全唐诗/poet.song.70000.json','["老去追遊骨亦疲，黑甜唯覺睡如飴。", "漸差素彩弄華髮，猶夢清妍侍曲眉。", "愧甚雕樽負珠履，獨餘殘雪照書帷。", "未妨管領東風在，官柳溪梅不用疑。"]'),
('3a0aa7a7-7321-4020-b720-9866a30a0ee6','充叟九兄以書問鄱陽官况因亦問訊','毛滂','宋','宋诗','song-poetry','','[]','信来頻慰别離魂，苦問官情却懶言。',64,'全唐诗/poet.song.70000.json','["信来頻慰别離魂，苦問官情却懶言。", "多睡正隨蝴蝶夢，相憐空愧鶺鴒原。", "幸無俗客于書戶，遙想青山對縣門。", "定是放衙能少事，悠哉岸幘步槐根。"]'),
('130d7fe5-4650-44b8-baf3-322a5c52fafa','去國','毛滂','宋','宋诗','song-poetry','','[]','年來去國故遲遲，坂上長鳴老益悲。',64,'全唐诗/poet.song.70000.json','["年來去國故遲遲，坂上長鳴老益悲。", "不作居山慚捷逕，彊須了事學癡兒。", "風霜冷面何能笑，藜藿空腸未厭饑。", "里巷定無楊得意，朝廷合有鄭當時。"]'),
('10a8e424-8ffa-4a93-999e-b8b83d40d989','紅梅','毛滂','宋','宋诗','song-poetry','','[]','何處曾臨阿母池，渾將絳雪點寒枝。',64,'全唐诗/poet.song.70000.json','["何處曾臨阿母池，渾將絳雪點寒枝。", "東墻羞頰逢誰笑，南國酡顔强自持。", "幾過風霜仍好色，半呼桃杏聽羣兒。", "青春獨養和羮味，不爲黄蜂飽蜜脾。"]'),
('f76c09d6-fa03-478e-96ac-7040873a188d','次韻成允寒秀亭','毛滂','宋','宋诗','song-poetry','','[]','伐蒿種竹作清深，洗石鋤垣出翠紋。',64,'全唐诗/poet.song.70000.json','["伐蒿種竹作清深，洗石鋤垣出翠紋。", "玉節露勻新带月，苔膚雨澀細留雲。", "四簷妍色開晴曉，一畝濃陰寄夕醺。", "陶令醉時煩客去，夢魂瀟灑與誰云。"]'),
('d70286e6-c849-492b-85a1-6e2b8569b459','十二月二十六日出郊訪無畏詩禪暮歸奉寄','毛滂','宋','宋诗','song-poetry','','[]','寒郊獨往興悠哉，問訊山翁破臘回。',64,'全唐诗/poet.song.70000.json','["寒郊獨往興悠哉，問訊山翁破臘回。", "犀軸冰寒苕水句，衲衣雪暗錦營埃。", "歸時煙樹鴉聲集，望處溪窗山色來。", "此意兒童終不覺，閉門脱屩拂莓苔。"]'),
('88b03815-b5fe-49eb-a701-3cd0c409cef4','次韻方明叔見贈','毛滂','宋','宋诗','song-poetry','','[]','法書亂眼極牛毛，卒業何時愧李翺。',64,'全唐诗/poet.song.70000.json','["法書亂眼極牛毛，卒業何時愧李翺。", "好在先生無燥濕，老來秀句絕孤高。", "不知蹭蹬沉鸞枳，却念疏慵似馬曹。", "誰薦薛公經行著，折腰江縣豈殊褒。"]'),
('b31014d7-0abd-4f1a-988c-cca4e196bbbc','曹使君舍夜飲歸步月出城山色如畫作詩一首寄曹','毛滂','宋','宋诗','song-poetry','','[]','西曹滿百第相聞，東閣招延氣自春。',64,'全唐诗/poet.song.70000.json','["西曹滿百第相聞，東閣招延氣自春。", "雞肋天教辭怒臂，牛心公與慰饞唇。", "酒紅欲去風吹頰，山碧來迎月滿身。", "步入柏陰清夜急，敲門惟有鶴譍人。"]'),
('47ac7e30-5f6a-43c9-ae02-aa3644a413f6','對雪二首  其一','毛滂','宋','宋诗','song-poetry','','[]','玉京咫尺不應疑，龍鳳交横舞屢僛。',64,'全唐诗/poet.song.70000.json','["玉京咫尺不應疑，龍鳳交横舞屢僛。", "素色可能粧粉並，真香直到齒牙知。", "珠樓先曉月未落，瑤草自春天亦私。", "千里一裘誰有様，鄒郎吹律爲薰之。"]'),
('07907428-aa33-4bf7-ad8b-53065c411668','對雪二首  其二','毛滂','宋','宋诗','song-poetry','','[]','空庭白鳳舞毰毸，撲帟窺簾去却回。',64,'全唐诗/poet.song.70000.json','["空庭白鳳舞毰毸，撲帟窺簾去却回。", "柳絮似将春色到，梅梢不認月華來。", "輕盈舞殿三千女，縹緲飛天十二臺。", "定有仙人來種玉，藍田歸計少徘徊。"]'),
('86ab2e84-3a32-4826-8ded-49d229523818','桐君山邑人呼爲小金山桐君所廬也','毛滂','宋','宋诗','song-poetry','','[]','塔廟新嚴跡半空，山前山後但孫桐。',64,'全唐诗/poet.song.70000.json','["塔廟新嚴跡半空，山前山後但孫桐。", "樓臺影壓浮天浪，鐘鼓聲隨過岸風。", "定有龍宮在深碧，初疑海市變青紅。", "衆醫不識人間病，遺籙誰知藥石功。"]'),
('6b4bc0af-12d9-4f1a-b564-09687cd76bb2','代人和孟羽','毛滂','宋','宋诗','song-poetry','','[]','東野多窮輙自鳴，半生雲水共将迎。',64,'全唐诗/poet.song.70000.json','["東野多窮輙自鳴，半生雲水共将迎。", "朝廷纖悉收遺老，筆勢巉巖壓後生。", "天上恩袍新草色，道傍詩句古鐘聲。", "出秦壯思磨鋒鍔，欲破劉郎五字城。"]'),
('e70da367-0cf5-4767-ac94-70f78c94fc10','生日','毛滂','宋','宋诗','song-poetry','','[]','要作人間浩蕩春，便應三日對東君。',64,'全唐诗/poet.song.70000.json','["要作人間浩蕩春，便應三日對東君。", "萬牛早汗十圍木，百穀終甘一寸雲。", "天下公侯端有種，日邊鴻雁不離羣。", "寶爐善頌區區爾，何似君陳德似薰。"]'),
('4a8ea68d-9f17-4b71-b88d-1b0bf45947d7','代館職應詔和元夕','毛滂','宋','宋诗','song-poetry','','[]','太平樂事及黎元，桂月蘭燈照有年。',64,'全唐诗/poet.song.70000.json','["太平樂事及黎元，桂月蘭燈照有年。", "景焰煌煌浮魏闕，清光穆穆抱堯天。", "皇明爥遠輝星斗，睿唱宣和勝管絃。", "十二明珠供照乘，夜光飛出九重淵。"]'),
('a0a6c839-a393-4823-9eee-3c6efe306c7d','送朱朝夫過江北','毛滂','宋','宋诗','song-poetry','','[]','愛君如竹可無君，君去吾歸麋鹿羣。',64,'全唐诗/poet.song.70000.json','["愛君如竹可無君，君去吾歸麋鹿羣。", "他日漫同千里月，明朝相望一江雲。", "餘尊尚得須臾語，新句那能欵曲聞。", "人到寄書應不識，花間但覓醉參軍。"]'),
('d26aa321-02ba-4bb5-bb31-d779fead5e64','送遐舉解德清縣章','毛滂','宋','宋诗','song-poetry','','[]','吏最年來三再書，野梅官柳映歸途。',64,'全唐诗/poet.song.70000.json','["吏最年來三再書，野梅官柳映歸途。", "不容車下牛將犢，猶說桑間雉領雛。", "萬里摩霄看鵠舉，一城臥轍作兒呱。", "東鄰病骨誰料理，十駕相追肯少須。"]'),
('47c81a16-84bb-4826-8810-21a7fd3241e1','和孫守三月二十七日開宴','毛滂','宋','宋诗','song-poetry','','[]','繡段遮簷玉刻樽，揚州春色最先醺。',64,'全唐诗/poet.song.70000.json','["繡段遮簷玉刻樽，揚州春色最先醺。", "落花風起舞茵捲，秀嶺烟生媚黛分。", "酥面錦靴輕轉雪，粉吭牙板細留雲。", "要他桃李長依舊，不借東君借冦君。"]'),
('28a2ba9b-2c0b-44aa-ba9f-15ae39d123a4','次韻曾公衮','毛滂','宋','宋诗','song-poetry','','[]','翩翩公子蚤知名，詩句年來特地清。',64,'全唐诗/poet.song.70000.json','["翩翩公子蚤知名，詩句年來特地清。", "客館可應堪倒屣，蕪編曾不累懸衡。", "南飛倦翮都無興，北道主人終有情。", "想見綠疏前夜雨，跳珠甃玉伴吟聲。"]'),
('702443ec-2d07-4cdb-9865-957818227489','縣境不雨數遣比丘禱佛於廟祀龍於社皆不雨聞龍居響潭水中往潭湄刑鵝而祀之初崖月微明有風颯然動衣袂祀竟雲物出雨態生已而遂雨然歲豐時和蓋造物者之力而龍之惠也至前此不雨乃令之無狀所召爾縣之諸儒反爲歌詩以雨歸令甚無謂聊作一詩奉報','毛滂','宋','宋诗','song-poetry','','[]','自酌椒漿酹紫淵，步虚聲徹羽衣翩。',64,'全唐诗/poet.song.70000.json','["自酌椒漿酹紫淵，步虚聲徹羽衣翩。", "壇心月冷刑鵝俎，雨脚風搖浴狶天。", "百里飽看紅䆉稏，一杯輕愧黑蜿蜒。", "韋編漫記經綸事，老對雲雷却惘然。"]'),
('394d54c8-724f-4350-bfff-b79cd84aec1e','縣境不雨禱響潭得之明日一龜出潭水上取以歸縣齋諸進士有詩因作一首','毛滂','宋','宋诗','song-poetry','','[]','崖雲送雨一村凉，千頃扶疏綠穎香。',64,'全唐诗/poet.song.70000.json','["崖雲送雨一村凉，千頃扶疏綠穎香。", "白馬誰将河伯命，緇車先趣大夫装。", "老來未覺巢蓮近，遠去惟知曳尾忙。", "趁我還山先辟穀，林間日月伴君長。"]'),
('4f25e838-142f-430b-88c4-9e0270a09093','孫使君約觀燈以病不果往以詩見强次韻和酬','毛滂','宋','宋诗','song-poetry','','[]','羅綺山前捲旆風，夜游車馬畫圖中。',64,'全唐诗/poet.song.70000.json','["羅綺山前捲旆風，夜游車馬畫圖中。", "落梅已恨青春減，投轄那憂碧酒空。", "座上精明唯定國，眼中耐久祇元同。", "勤呼爲惜蓮燈爛，多病猶貪芋火紅。"]'),
('15c6a47e-d171-4a82-8900-b7733315c337','燈夕當三日而罷今至四日五日國人尚紛然出遊勢不可禁天既雨仍作小晴老稚皆有閒暇不迫之色千兵所至驩呼隨之此前未有也聞使君復爲人强出聊作小詩記一時之事','毛滂','宋','宋诗','song-poetry','','[]','廉纖飛雨爲誰休，爛漫懸燈總未收。',64,'全唐诗/poet.song.70000.json','["廉纖飛雨爲誰休，爛漫懸燈總未收。", "自是一年無歎息，不妨五夕得嬉游。", "後車鶯燕春聲軟，前騎熊羆夜氣遒。", "兩行紅紗三百炬，插花攜酒趁遨頭。"]'),
('60cb5600-e99d-48b0-bd57-ec89c9495a07','定光梅開僕以病未能往觀亦緣此辭閭丘之約今辱示詩走答一首','毛滂','宋','宋诗','song-poetry','','[]','七里梅花自一村，縣樓目斷暮雲深。',64,'全唐诗/poet.song.70000.json','["七里梅花自一村，縣樓目斷暮雲深。", "玉人爲弄昆溪笛，塵榻空横單父琴。", "知有春心傳庾嶺，可無雪興在山陰。", "金鞍簇馬何時到，試聽東堂偪仄吟。"]'),
('5856aac9-980b-4047-b25b-048493aff70f','伯駿同官以僕禱雨龍湫屢效百里荐歲熙和官曹無事作詩見寵輙次韻奉酬一首','毛滂','宋','宋诗','song-poetry','','[]','荐歲熙和屬臥龍，得分閒暇與君同。',64,'全唐诗/poet.song.70000.json','["荐歲熙和屬臥龍，得分閒暇與君同。", "春筐縷雪衾裯足，午甑吹珠頰輔豐。", "蜥蜴興雲誰汝信，商羊舞雨自言功。", "州人欲識餘霙雪，寄與飛廉百里風。"]'),
('0ac43fff-122d-4b9f-b265-c03c109bf0c1','代張蘭送太守','毛滂','宋','宋诗','song-poetry','','[]','電轉雙旌雨結愁，水流行色過芳洲。',64,'全唐诗/poet.song.70000.json','["電轉雙旌雨結愁，水流行色過芳洲。", "賸風殘月誰交取，别酒離歌且駐留。", "千里溪山記詩伯，一年鶯燕識遨頭。", "朝天不作含香伴，爲想林間春意幽。"]'),
('e5e0906f-2d90-416f-8f88-a8dd60b7f731','代張菊','毛滂','宋','宋诗','song-poetry','','[]','去年出郭麥風秋，憶共兒童迓細侯。',64,'全唐诗/poet.song.70000.json','["去年出郭麥風秋，憶共兒童迓細侯。", "煙雨一溪行色動，管絃千里頌聲留。", "斷魂南浦横離恨，注目東山想舊遊。", "西檻露團春不管，抱叢寒蝶伴清愁。"]'),
('d3256b90-bcbd-4b2f-8c5d-9424d6d4ce15','王治中招余飲丹陽劉公雪苑英公在座主人俾余坐中席僧居左道居右衆賓列坐兩傍曰道之所在也余敢當此哉爲詩以謝之','毛滂','宋','宋诗','song-poetry','','[]','宇宙中間道最大，禪仙並立儒爲尊。',64,'全唐诗/poet.song.70000.json','["宇宙中間道最大，禪仙並立儒爲尊。", "誰將幻怪驚愚俗，總向虚空認法門。", "此土猶知名教重，昔人尚有典刑存。", "愧予晚陋羞前哲，願以鄉盟齒弟昆。"]'),
('6f70d5c5-cd48-4d1f-952c-bc9e05f618ff','和巨中游芝山','毛滂','宋','宋诗','song-poetry','','[]','俗狀塵容欲養成，猶慚岫幌不吾扃。',64,'全唐诗/poet.song.70000.json','["俗狀塵容欲養成，猶慚岫幌不吾扃。", "任慵讀律知難入，忍睡看山輙暫醒。", "蘭茁有時應吐秀，茗根無味强通靈。", "朝霞夕菊全堪飽，肯紿侏儒學歲星。"]'),
('a5dbe038-5192-4255-bd17-ce5a2cbe33c9','次韻答琳老','毛滂','宋','宋诗','song-poetry','','[]','雲水肝腸要掃除，筆頭費盡淡工夫。',64,'全唐诗/poet.song.70000.json','["雲水肝腸要掃除，筆頭費盡淡工夫。", "居山應免逢京兆，過我聊當見子虚。", "夜臥春蒲諸念冷，晚吟秋漢一峰孤。", "打包來作臨卭客，車騎雖無亦甚都。"]'),
('b69dfe0d-834c-478e-a484-16e0354c5102','奉送徑山無畏老人謁吳興蔣使君無畏能作詩寫字去徑山五年遨遊江南以歸遂過僕於此聊館之旁寺老屋三數間而已當坐名山勝刹大佛事而此非所宜安也','毛滂','宋','宋诗','song-poetry','','[]','一生凛凛伴龍湫，末後飄飄逐置郵。',64,'全唐诗/poet.song.70000.json','["一生凛凛伴龍湫，末後飄飄逐置郵。", "老屋相安真喣沫，扁舟獨往亦浮漚。", "晴沙照影支離晚，寒研磨煙骨董秋。", "八月驚潮翻口角，鈴齋說似古裴休。"]'),
('dba3f341-bb28-4327-9aec-74338ba00f31','送參寥遊京師','毛滂','宋','宋诗','song-poetry','','[]','青鞋布襪脚騰騰，行住湖山自滿膺。',64,'全唐诗/poet.song.70000.json','["青鞋布襪脚騰騰，行住湖山自滿膺。", "朝日已升天晧旰，秋風猶弄鬢鬅鬙。", "道逢京尹聊須避，坐列諸王儻可登。", "認取參寥泉上月，綠煙開處在觚稜。"]'),
('8aa161f3-21ed-4c66-952b-ae24c5b95c19','次韻琳老','毛滂','宋','宋诗','song-poetry','','[]','夢魂夜夜釣魚臺，懷抱何當亦好開。',64,'全唐诗/poet.song.70000.json','["夢魂夜夜釣魚臺，懷抱何當亦好開。", "竹日一窗窺我病，溪風三里送詩來。", "天花散滅雙瞳冷，香燼蕭寒萬相灰。", "欲與道人遊物外，故山情在首重回。"]'),
('3ebc59f4-1fdc-4b29-89a2-c3accf8496f0','徑山無畏老人從旁郡来解包武康觀音院昨日訪别云當走錢塘吳興二郡謁林豐二主人僕怪其枯槁淡薄士當無求於世反從事於王公門墻下老人知僕意因云二公有道士我佛所謂大長者輩今佛長城在彼我當歸之僕是其說作詩以餉其行老人常掛瘞鶴銘於座右自言得其行筆法又苦吟名於士大夫間屢過僕東堂飯每稱吾家飯美以故併載詩中','毛滂','宋','宋诗','song-poetry','','[]','海上仙人爲守關，杖頭風月冷金鐶。',64,'全唐诗/poet.song.70000.json','["海上仙人爲守關，杖頭風月冷金鐶。", "秖緣長者曾傾蓋，不爲諸侯故出山。", "瘞鶴字勤衫袖黑，敲門詩苦鬢毛斑。", "歸來一鉢東堂飯，自有溪雲作伴閒。"]'),
('03360b4c-3be6-435a-8209-4f9ae7c16847','僕罷官東歸過杭州寓六游堂而樓閣倚空江山在目僕甚樂之無畏老師自武康送客至此過僕於此堂之上留飯終日頃僕作武康令居縣之東堂每與師飯於堂上數稱東堂飯美每食輙兼人别十數年飯猶健也然師於世故泊然了無芥蔕獨於東堂故人若不能忘情者亦復可怪戲作詩一首其末併道所懷','毛滂','宋','宋诗','song-poetry','','[]','道人送客過林扃，先識穿雲拄杖聲。',64,'全唐诗/poet.song.70000.json','["道人送客過林扃，先識穿雲拄杖聲。", "內苑深居無一念，東堂久闊尚餘情。", "且欣能善将軍飯，未怪頻翻吏部羮。", "小住家風殊不惡，一江明月看潮生。"]'),
('17a2f509-949a-4e96-b7d2-908c51e2315e','僧惠澄從余學詩','毛滂','宋','宋诗','song-poetry','','[]','花開花落古東溪，賸馥殘膏今在誰。',64,'全唐诗/poet.song.70000.json','["花開花落古東溪，賸馥殘膏今在誰。", "後世那能接光焰，上人聊復問藩籬。", "散花高座真無事，乞食空腸僅不饑。", "急喚清風下佳樹，盡吹塵土出詩脾。"]'),
('470b24da-0377-4431-83bf-546f54154da5','上元夜','毛滂','宋','宋诗','song-poetry','','[]','翠輦遙窺日角豐，陽光浮喜散雲同。',64,'全唐诗/poet.song.70000.json','["翠輦遙窺日角豐，陽光浮喜散雲同。", "海山不動雙龍矯，天信頻頒一鶴通。", "胡越照臨清景內，唐虞消息笑聲中。", "六街鼓舞誰能强，三尺兒童識帝功。"]'),
('7f5c2b7b-4b43-4860-a8b4-ab6fa81c0d16','過静林寺用琳老韻作四絕句  其一','毛滂','宋','宋诗','song-poetry','','[]','空庭不見人，烏啄僧臺食。',24,'全唐诗/poet.song.70000.json','["空庭不見人，烏啄僧臺食。", "林深露未晞，微風漏花瀝。"]'),
('3c4e538f-49f7-4ac5-851d-d92cecf1336f','過静林寺用琳老韻作四絕句  其二','毛滂','宋','宋诗','song-poetry','','[]','且来東堂日，相值柳橋西。',24,'全唐诗/poet.song.70000.json','["且来東堂日，相值柳橋西。", "癡鶯弔落花，全學嬌兒啼。"]'),
('a5180eac-8e88-4eb9-81e5-e777b07737a9','過静林寺用琳老韻作四絕句  其三','毛滂','宋','宋诗','song-poetry','','[]','橙花亦娟娟，照水弄清白。',24,'全唐诗/poet.song.70000.json','["橙花亦娟娟，照水弄清白。", "孤香少人知，黄蜂自爲客。"]'),
('fd81344f-05a7-4537-aa87-9b4b026f772b','過静林寺用琳老韻作四絕句  其四','毛滂','宋','宋诗','song-poetry','','[]','寒溪祇數尺，炯炯涵晴空。',24,'全唐诗/poet.song.70000.json','["寒溪祇數尺，炯炯涵晴空。", "寄目誰與論，翠荇牽春風。"]'),
('ad188f0e-a189-4541-9e44-12dd67ac44f3','春詞  其一','毛滂','宋','宋诗','song-poetry','','[]','日催紅𩉾鞢，雪放綠蒙茸。',24,'全唐诗/poet.song.70000.json','["日催紅𩉾鞢，雪放綠蒙茸。", "莫向東郊去，王春在九重。"]'),
('a8063dca-9a70-4b49-8b3f-a1f6936217f7','春詞  其二','毛滂','宋','宋诗','song-poetry','','[]','雲母春冰薄，氍毺曉氣暾。',24,'全唐诗/poet.song.70000.json','["雲母春冰薄，氍毺曉氣暾。", "尚垂宵旰意，加惠及元元。"]'),
('f8f75f4b-076a-4694-bb49-482c894398bc','春詞  其三','毛滂','宋','宋诗','song-poetry','','[]','雪盡牙籤暖，芸生竹簡香。',24,'全唐诗/poet.song.70000.json','["雪盡牙籤暖，芸生竹簡香。", "夜分猶樂此，定喜日舒長。"]'),
('04dda586-67e6-458b-8fd6-fb7f1381c38a','春詞  其四','毛滂','宋','宋诗','song-poetry','','[]','精華初結紐，璧水再逢春。',24,'全唐诗/poet.song.70000.json','["精華初結紐，璧水再逢春。", "杞梓扶疏見，君王自作新。"]'),
('3243a06e-41fb-49fd-b69b-c398658b338f','春詞  其五','毛滂','宋','宋诗','song-poetry','','[]','雲避南山曉，天回北斗春。',24,'全唐诗/poet.song.70000.json','["雲避南山曉，天回北斗春。", "榮光生八彩，壽色兩嶙峋。"]'),
('d3e1d957-3d1e-4a08-bfb5-bea7c112a761','春詞  其六','毛滂','宋','宋诗','song-poetry','','[]','君恩破寒色，天笑覺春回。',24,'全唐诗/poet.song.70000.json','["君恩破寒色，天笑覺春回。", "先暖延和柳，曾無羯鼓催。"]'),
('514dcfff-56d7-46cf-ba8c-37a1287a2f67','春詞  其七','毛滂','宋','宋诗','song-poetry','','[]','瑞日暉暉上，非煙冉冉收。',24,'全唐诗/poet.song.70000.json','["瑞日暉暉上，非煙冉冉收。", "晴川蠶可浴，翠瀲荇初流。"]'),
('1eeae336-8aae-421a-8bc5-637a8dd34e6c','春詞  其八','毛滂','宋','宋诗','song-poetry','','[]','柏酒勤稱壽，椒塗蚤却寒。',24,'全唐诗/poet.song.70000.json','["柏酒勤稱壽，椒塗蚤却寒。", "静無遊樂事，殊闊濯龍歡。"]'),
('3d31cd09-d652-4b39-bc62-415811e82335','春詞  其九','毛滂','宋','宋诗','song-poetry','','[]','曉光開繡幄，晴色上金除。',24,'全唐诗/poet.song.70000.json','["曉光開繡幄，晴色上金除。", "初進春衣窄，猶應澣濯餘。"]'),
('a161aa3f-6e80-4b64-b188-3a9a1116b32a','春詞  其一○','毛滂','宋','宋诗','song-poetry','','[]','庶草將蕃廡，羣陰自退消。',24,'全唐诗/poet.song.70000.json','["庶草將蕃廡，羣陰自退消。", "遲遲杏梁日，長照紫宸朝。"]'),
('ea18113e-12e4-441b-a481-19bf380c3a9b','春詞  其一一','毛滂','宋','宋诗','song-poetry','','[]','八風調養力，九地發生深。',24,'全唐诗/poet.song.70000.json','["八風調養力，九地發生深。", "共被年豐賜，誰知日昃心。"]'),
('2d91dcc5-9237-4767-8bc8-0fcb368c8c7b','春詞  其一二','毛滂','宋','宋诗','song-poetry','','[]','睍睆黄鸝出，參差紫燕飛。',24,'全唐诗/poet.song.70000.json','["睍睆黄鸝出，參差紫燕飛。", "君仁罿罻闊，惠及羽毛微。"]'),
('1ce51acc-ee91-4c64-afc7-d4b2a4d6db3b','春詞  其一三','毛滂','宋','宋诗','song-poetry','','[]','粉壁椒花馥，瑤釵彩燕翩。',24,'全唐诗/poet.song.70000.json','["粉壁椒花馥，瑤釵彩燕翩。", "東風呼唤得，隨意作春妍。"]'),
('09ae7631-c071-4122-9393-34c3f4f0dcf4','春詞  其一四','毛滂','宋','宋诗','song-poetry','','[]','日養千花氣，風和百和香。',24,'全唐诗/poet.song.70000.json','["日養千花氣，風和百和香。", "君王自仁壽，柏葉更稱觴。"]'),
('8ec04512-69a1-423c-b4bf-17d183e53c52','春詞  其一五','毛滂','宋','宋诗','song-poetry','','[]','寶曆垂無極，璿璣轉未央。',24,'全唐诗/poet.song.70000.json','["寶曆垂無極，璿璣轉未央。", "繡楹膏露潤，玉殿紫芝香。"]'),
('32dda95b-2651-4e62-8c10-0405541d5984','春詞  其一六','毛滂','宋','宋诗','song-poetry','','[]','穆穆清光外，葱葱佳氣中。',24,'全唐诗/poet.song.70000.json','["穆穆清光外，葱葱佳氣中。", "雲天看斗柄，寰海受和風。"]'),
('4d1b43d8-919f-42ee-a14f-9b06e5d97f6a','春詞  其一七','毛滂','宋','宋诗','song-poetry','','[]','玉甃蘭封麝，瑤池柳養金。',24,'全唐诗/poet.song.70000.json','["玉甃蘭封麝，瑤池柳養金。", "宸章先造化，摛藻自春林。"]'),
('636f1b06-c3ea-4868-9035-e93d336ec35e','夏夜','毛滂','宋','宋诗','song-poetry','','[]','毒暑彌三伏，微凉起二更。',24,'全唐诗/poet.song.70000.json','["毒暑彌三伏，微凉起二更。", "月窗風竹亂，煙渚露荷傾。"]'),
('00584abd-65de-4f52-a06e-8e031baaf4e9','遊石橋寄郭庭晦','毛滂','宋','宋诗','song-poetry','','[]','亂峰攢劍護清幽，萬壑雲煙暮不收。',32,'全唐诗/poet.song.70000.json','["亂峰攢劍護清幽，萬壑雲煙暮不收。", "欲就詩壇借旗鼓，爲君争取一橋秋。"]'),
('3fbda855-fdc8-43ad-bf0b-f8628806e099','偶成二首  其一','毛滂','宋','宋诗','song-poetry','','[]','隨風出岫不知歸，身落黄塵夢翠微。',32,'全唐诗/poet.song.70000.json','["隨風出岫不知歸，身落黄塵夢翠微。", "本亦無心膚寸事，故山却合自由飛。"]'),
('162eb7d3-19e1-4941-a515-890203caac56','偶成二首  其二','毛滂','宋','宋诗','song-poetry','','[]','此生弱草寄輕塵，辜負南山笋蕨春。',32,'全唐诗/poet.song.70000.json','["此生弱草寄輕塵，辜負南山笋蕨春。", "好去桃花破浪暖，清風明月不辜人。"]'),
('2cd29762-8dc5-4654-a0d1-9764f6d418ad','琳老送瑤花數葉云作香燒氣甚清馥','毛滂','宋','宋诗','song-poetry','','[]','璀璨誰將玉作春，天魔故惱老詩人。',32,'全唐诗/poet.song.70000.json','["璀璨誰將玉作春，天魔故惱老詩人。", "金爐送在東堂手，便有清香通四鄰。"]'),
('c06ee835-2bcc-4924-866d-cc7c29b1b857','德清五兄寄清茶','毛滂','宋','宋诗','song-poetry','','[]','玉角蒼堅已照人，冰肝寒潔更無塵。',32,'全唐诗/poet.song.70000.json','["玉角蒼堅已照人，冰肝寒潔更無塵。", "鳳凰雨露生珍草，不比榛蕪亦漫春。"]'),
('79819177-8ce3-48ae-8653-5b4f21b98fe2','送茶琳老','毛滂','宋','宋诗','song-poetry','','[]','道人詩思前溪水，流出山來亦自清。',32,'全唐诗/poet.song.70000.json','["道人詩思前溪水，流出山來亦自清。", "謾寄鳳凰臺畔雪，不妨竹裏潤琴聲。"]'),
('991ad504-c49d-4708-95fb-fc1091118760','競渡','毛滂','宋','宋诗','song-poetry','','[]','風旆悠悠水薄船，浪花翻覆自搖天。',32,'全唐诗/poet.song.70000.json','["風旆悠悠水薄船，浪花翻覆自搖天。", "汨羅誰復追忠義，争快兒郎一棹先。"]'),
('2e15c1c2-6362-456b-ba63-95ea5bcff303','石校書','毛滂','宋','宋诗','song-poetry','','[]','按書使者過蕭閒，但恐韋編有蠧干。',32,'全唐诗/poet.song.70000.json','["按書使者過蕭閒，但恐韋編有蠧干。", "豈識郝公藏萬卷，平生檢校費心官。"]'),
('283b1674-a43b-484c-8238-5b73c15090a5','雨中採石菖蒲  其一','毛滂','宋','宋诗','song-poetry','','[]','皂蓋銅章久汙人，青鞋布襪亦生塵。',32,'全唐诗/poet.song.70000.json','["皂蓋銅章久汙人，青鞋布襪亦生塵。", "今朝獨向秋雲裏，幻出林泉自在身。"]'),
('5117a0a1-f104-4db4-b417-76217eae89c1','雨中採石菖蒲  其二','毛滂','宋','宋诗','song-poetry','','[]','濺濺小水碧逶迤，叢菊寒深蔓翠垂。',32,'全唐诗/poet.song.70000.json','["濺濺小水碧逶迤，叢菊寒深蔓翠垂。", "採得菖蒲未歸去，滿身煙雨立多時。"]'),
