('e635a1af-99dd-412b-b1fe-8b08432883a1','見戲','毛滂','宋','宋诗','song-poetry','','[]','薄命何須問大來，時時廢卷秖孤咍。',32,'全唐诗/poet.song.70000.json','["薄命何須問大來，時時廢卷秖孤咍。", "故園松竹空荒徑，可勝淵明一賦催。"]'),
('fff5ad66-88b4-41d0-843d-4b22c54da258','欲訪天柱山闍黎寄一絕句','毛滂','宋','宋诗','song-poetry','','[]','三年不到上人家，目斷晨煙與暮霞。',32,'全唐诗/poet.song.70000.json','["三年不到上人家，目斷晨煙與暮霞。", "急遣寄聲堂下水，便来洗眼看天花。"]'),
('074b1534-4393-4d9c-8e10-fd44b4991bec','琳老惠麩乾走筆奉寄','毛滂','宋','宋诗','song-poetry','','[]','何人彈鋏苦思魚，食肉而飛亦任渠。',32,'全唐诗/poet.song.70000.json','["何人彈鋏苦思魚，食肉而飛亦任渠。", "誰見東堂病居士，山僧乞食亦分餘。"]'),
('1f19b987-5cbd-4df8-89b5-c43def9369b2','汲水禪静琳老寄詩因次韻奉寄','毛滂','宋','宋诗','song-poetry','','[]','雲脚濤頭氣自寒，了無閒夢到蒲團。',32,'全唐诗/poet.song.70000.json','["雲脚濤頭氣自寒，了無閒夢到蒲團。", "翠庵只在東堂裏，底下揚眉直下看。"]'),
('399f8dd7-0ce5-4e28-924c-0625720601f4','跋李伯時醉僧圖','毛滂','宋','宋诗','song-poetry','','[]','道人三昧一壺中，筆下驚蛇怖小童。',32,'全唐诗/poet.song.70000.json','["道人三昧一壺中，筆下驚蛇怖小童。", "日日松間好消息，酒香先過野橋風。"]'),
('2b3c4b3b-a79d-445c-9387-d659bc4a5109','訪琳老聞出赴供','毛滂','宋','宋诗','song-poetry','','[]','賓頭應供未還家，聊借僧窗自點茶。',32,'全唐诗/poet.song.70000.json','["賓頭應供未還家，聊借僧窗自點茶。", "此意不須相見說，已知秋色付蘋花。"]'),
('70293645-9306-4695-847f-d16048cbcbe3','别歸雲庵端老','毛滂','宋','宋诗','song-poetry','','[]','何年敗衲裹虚空，雪雁煙鳬不受籠。',32,'全唐诗/poet.song.70000.json','["何年敗衲裹虚空，雪雁煙鳬不受籠。", "未信歸雲便端的，一船明月四邊風。"]'),
('d7d6b22c-3f64-4b99-95f8-164706ef0e0c','寒食日過翠峰塔院示法海道人','毛滂','宋','宋诗','song-poetry','','[]','雲煙七級赤旃檀，龍護金函佛骨寒。',32,'全唐诗/poet.song.70000.json','["雲煙七級赤旃檀，龍護金函佛骨寒。", "問訊道人春到否，瑞香花謝倚欄干。"]'),
('e01bfde4-6daf-4e93-837f-6b97b65c6be4','子溫以詩將菊本見遺數日適病伏枕今少間戲作三絕句以報  其一','毛滂','宋','宋诗','song-poetry','','[]','破煙涵雨得春叢，想見當年老范公。',32,'全唐诗/poet.song.70000.json','["破煙涵雨得春叢，想見當年老范公。", "多病未須求茗草，此詩渾欲愈頭風。"]'),
('22f020d0-c86b-4d4e-8d21-f2379e011f2c','子溫以詩將菊本見遺數日適病伏枕今少間戲作三絕句以報  其二','毛滂','宋','宋诗','song-poetry','','[]','盡鋤芳草春應怪，初種黄花秋未知。',32,'全唐诗/poet.song.70000.json','["盡鋤芳草春應怪，初種黄花秋未知。", "花外種松松外竹，漸無蝴蝶到東籬。"]'),
('34a74437-475b-4506-8b8d-b2acc259d0ea','子溫以詩將菊本見遺數日適病伏枕今少間戲作三絕句以報  其三','毛滂','宋','宋诗','song-poetry','','[]','更作天隨求枸杞，試從子美覓黄精。',32,'全唐诗/poet.song.70000.json','["更作天隨求枸杞，試從子美覓黄精。", "但知一飽輕方文，不爲秋毫要眼明。"]'),
('07bc235b-78eb-4a98-b045-b90ee3204722','春曉  其一','毛滂','宋','宋诗','song-poetry','','[]','東臯紛綺水潺潺，翠拂官橋柳欲眠。',32,'全唐诗/poet.song.70000.json','["東臯紛綺水潺潺，翠拂官橋柳欲眠。", "出谷黄鶯終好在，辭風紅樹稍蕭然。"]'),
('605baf0d-6356-4879-83b4-bc5a2551820b','春曉  其二','毛滂','宋','宋诗','song-poetry','','[]','酴醾春曉與誰芳，自是新來雨露香。',32,'全唐诗/poet.song.70000.json','["酴醾春曉與誰芳，自是新來雨露香。", "燕子覓巢終軟媚，楊花滿路尚顛忙。"]'),
('bad43d9a-f9dc-4380-a34b-a67405b7196a','春曉  其三','毛滂','宋','宋诗','song-poetry','','[]','爐香燼冷夾衣寒，雨過園林翠作團。',32,'全唐诗/poet.song.70000.json','["爐香燼冷夾衣寒，雨過園林翠作團。", "剩得風光何處著，紅薔薇搭小欄干。"]'),
('2f81047d-7c06-4236-927a-bd9b4d77029b','春曉  其四','毛滂','宋','宋诗','song-poetry','','[]','池塘綠浄了無塵，造化裁餘十日春。',32,'全唐诗/poet.song.70000.json','["池塘綠浄了無塵，造化裁餘十日春。", "月樹清深語鶗鴂，幾時歸去亦謾人。"]'),
('bf3fd4c5-5bc9-4b55-837d-ab1563f8a6c2','二月二十八日禱雨龍湫','毛滂','宋','宋诗','song-poetry','','[]','折腰五斗自難堪，每爲斯人食不甘。',32,'全唐诗/poet.song.70000.json','["折腰五斗自難堪，每爲斯人食不甘。", "赤地黄埃迷澤國，老龍飲血亦分甘。"]'),
('ce2cafc2-bebf-4a98-97e1-b93e2ba28ddc','過浄林杏花下微見曉色','毛滂','宋','宋诗','song-poetry','','[]','籃輿度水犯雲巢，拂面垂楊翠欲交。',32,'全唐诗/poet.song.70000.json','["籃輿度水犯雲巢，拂面垂楊翠欲交。", "春睡穩人殊未覺，半分曉色到花梢。"]'),
('764ed6d5-4a15-4539-b33c-956e32668ab9','過吳淞江','毛滂','宋','宋诗','song-poetry','','[]','參軍身外秖圖書，獨與吳江分不疏。',32,'全唐诗/poet.song.70000.json','["參軍身外秖圖書，獨與吳江分不疏。", "歸去他年當辟穀，嬾隨波浪覓鱸魚。"]'),
('49c49a88-45b9-447f-aed8-92967c169884','題琳老所攜二蘇書帖','毛滂','宋','宋诗','song-poetry','','[]','道人此書欲在眼，扁舟一宿亦隨身。',32,'全唐诗/poet.song.70000.json','["道人此書欲在眼，扁舟一宿亦隨身。", "霽月光風開玉軸，千年彷彿見斯人。"]'),
('10f5bef1-5624-4562-b2f2-4843c36096d8','和孫守','毛滂','宋','宋诗','song-poetry','','[]','回首長城臥落霞，雲開桂影過昏鴉。',32,'全唐诗/poet.song.70000.json','["回首長城臥落霞，雲開桂影過昏鴉。", "不須更要千紅翠，醉眼燈前已亂花。"]'),
('eec28010-a30c-4adc-a9aa-1c579bf04b70','散藥過東湖戲作絕句寄陳巨中','毛滂','宋','宋诗','song-poetry','','[]','誰爲蒼生起病癯，參軍藥裹欲何如。',32,'全唐诗/poet.song.70000.json','["誰爲蒼生起病癯，參軍藥裹欲何如。", "湖東道義爲鍼石，不用先生肘後書。"]'),
('4a34a629-957e-421e-ab94-560df87d0d7b','次韻王宣義見過夜飲四絕  其一','毛滂','宋','宋诗','song-poetry','','[]','空琴誰爲奏南風，坐看幽香走篆紅。',32,'全唐诗/poet.song.70000.json','["空琴誰爲奏南風，坐看幽香走篆紅。", "定卜糟丘度餘日，此生那復問蓍叢。"]'),
('f9e90c22-21fc-42e4-ae27-e09fa656fb19','次韻王宣義見過夜飲四絕  其二','毛滂','宋','宋诗','song-poetry','','[]','凄風落日酒家天，何事囊中長一錢。',32,'全唐诗/poet.song.70000.json','["凄風落日酒家天，何事囊中長一錢。", "快見渴虹横酒戶，歸須殘月上吟韉。"]'),
('c2fc5dc6-0247-4c0a-ad5d-71d666a9744e','次韻王宣義見過夜飲四絕  其三','毛滂','宋','宋诗','song-poetry','','[]','崔郎傲兀見孤羆，筆勢縱横欲發奇。',32,'全唐诗/poet.song.70000.json','["崔郎傲兀見孤羆，筆勢縱横欲發奇。", "賦就何人知犬子，杯深自喜對鵝兒。"]'),
('74abd18e-aed2-46b4-8739-e43481733796','次韻王宣義見過夜飲四絕  其四','毛滂','宋','宋诗','song-poetry','','[]','肯爲張卿貴作奴，不嫌喚客手攜壺。',32,'全唐诗/poet.song.70000.json','["肯爲張卿貴作奴，不嫌喚客手攜壺。", "全勝一葉唯茶竈，未負黄公賣酒壚。"]'),
('e86d8bbc-6543-4a89-b0f4-9a4f682b8aed','靈芝觀上人房植紫竹一本覆屋其上以庇朝日顧雨露所不及也疑其當憔悴枯槁反蔚然勁秀爲作一絕句','毛滂','宋','宋诗','song-poetry','','[]','階前紫玉似人長，可怪龍孫久未驤。',32,'全唐诗/poet.song.70000.json','["階前紫玉似人長，可怪龍孫久未驤。", "第放煙梢出簷去，此君初不畏風霜。"]'),
('8bd4f0a6-3891-42cf-956c-8c5f3b392933','訪孟令不遇','毛滂','宋','宋诗','song-poetry','','[]','扶病尋君君未歸，添香應惹踏門衣。',32,'全唐诗/poet.song.70000.json','["扶病尋君君未歸，添香應惹踏門衣。", "東風未破桃花萼，雪壓餘英蝶亂飛。"]'),
('be1b9b51-4624-442b-900f-a50bfc5826ea','常山孫令見過僕未起孫題壁而去作絕句寄之  其一','毛滂','宋','宋诗','song-poetry','','[]','醉鄉冉冉夢游閒，一夜凉風唤未還。',32,'全唐诗/poet.song.70000.json','["醉鄉冉冉夢游閒，一夜凉風唤未還。", "可是應門無稚子，雙鳬仙去定誰攀。"]'),
('74e3971c-382d-43ca-978c-deb0f68731ff','常山孫令見過僕未起孫題壁而去作絕句寄之  其二','毛滂','宋','宋诗','song-poetry','','[]','門外初爲羅雀地，壁間偶見換鵝書。',32,'全唐诗/poet.song.70000.json','["門外初爲羅雀地，壁間偶見換鵝書。", "忽然興盡何由揖，擬遣長鬚致鯉魚。"]'),
('7668e581-3881-4b77-9f7a-6af61448feed','常山孫令見過僕未起孫題壁而去作絕句寄之  其三','毛滂','宋','宋诗','song-poetry','','[]','夾道老槐分曉色，出樓寒鼓報衙聲。',32,'全唐诗/poet.song.70000.json','["夾道老槐分曉色，出樓寒鼓報衙聲。", "解牛敏手仍投暇，夢蝶閒身尚未驚。"]'),
('cba2b75a-2353-467f-acc1-42689022f0f9','送茶宋大監  其一','毛滂','宋','宋诗','song-poetry','','[]','鳳凰山畔雨前春，玉骨雲腴絕可人。',32,'全唐诗/poet.song.70000.json','["鳳凰山畔雨前春，玉骨雲腴絕可人。", "寄與青雲欲仙客，一甌相映兩無塵。"]'),
('7ef6c1e7-cd57-40c2-9ae9-9d8cb8da0895','送茶宋大監  其二','毛滂','宋','宋诗','song-poetry','','[]','玉兔甌中霜月色，照公問路廣寒宮。',32,'全唐诗/poet.song.70000.json','["玉兔甌中霜月色，照公問路廣寒宮。", "絕勝自酌寒窗下，睡減悲添愁事叢。"]'),
('167cae85-ee17-499f-b9bc-90116b4ca3ef','響潭','毛滂','宋','宋诗','song-poetry','','[]','水面平鋪映碧空，夜深明月照龍宮。',32,'全唐诗/poet.song.70000.json','["水面平鋪映碧空，夜深明月照龍宮。", "猿啼未響潭先響，一樹花開兩樹紅。"]'),
('d8f91bbd-6abe-4917-9551-7667c867f1f1','遊翠峰寺','毛滂','宋','宋诗','song-poetry','','[]','隔墻楊柳舞腰斜，傍砌鵝梨玉作花。',32,'全唐诗/poet.song.70000.json','["隔墻楊柳舞腰斜，傍砌鵝梨玉作花。", "此地風光誰管領，小詩收入長官家。"]'),
('c240c0e1-60f2-47e0-9585-cb4a2fd95998','晝寝石頤寺','毛滂','宋','宋诗','song-poetry','','[]','何人支枕古邯鄲，孤卧僧房四面山。',32,'全唐诗/poet.song.70000.json','["何人支枕古邯鄲，孤卧僧房四面山。", "故遣白雲遮谷口，不教幽夢落人間。"]'),
('a0799f27-042d-4787-a383-a4d3f8c144d7','曹彥約昌谷集同官約賦紅梅成五十六字','毛滂','宋','宋诗','song-poetry','','[]','淡中着色似狂顛，心與梅同迹不然。',64,'全唐诗/poet.song.70000.json','["淡中着色似狂顛，心與梅同迹不然。", "奪我焉支寧免俗，豈無膏沐獨爭先。", "辨桃認杏何人拙，壓雪欺霜政自妍。", "只恐東君招不得，好修猶在竹籬邊。"]'),
('d1c2cbc4-05cf-4256-969a-6ad6b3046c01','再賦四十字','毛滂','宋','宋诗','song-poetry','','[]','雪月個高寒，求多意未闌。',48,'全唐诗/poet.song.70000.json','["雪月個高寒，求多意未闌。", "林逋五品服，宋璟九還丹。", "老友松筠健，賢宗鼎鼐酸。", "任渠蜂蝶鬧，難作武陵看。"]'),
('df2e6dca-1595-46c1-b924-8d3bb3a60e05','比得寒疾用道士養生法治其內郡幕徐天隱遺以柴胡桔梗教作湯服之疾間作小詩以寄','毛滂','宋','宋诗','song-poetry','','[]','江南卑濕地，往往如長沙。',132,'全唐诗/poet.song.70000.json','["江南卑濕地，往往如長沙。", "薄寒能中人，毛立噤齒牙。", "初猶遭蒸炊，又似縛且檛。", "淫祠亂昏俗，禍福專羣鴉。", "參軍支病骨，抱案隨吏衙。", "鬼蓋乘其窮，屢以寒熱加。", "定知鬼非人，吾誰彼疵瑕。", "烏饑集屋梁，聊試彈以笯。", "手摩田中丹，三關氣成霞。", "房圖引芸蒿，相與排陰邪。", "此鬼不足施，霍然促脂車。"]'),
('fce1cb20-4c28-4f1b-ae3e-e55f13968fdc','響應禱雨寄蘇文忠公','毛滂','宋','宋诗','song-poetry','','[]','雪意不肯休，垂垂閣雲端。',240,'全唐诗/poet.song.70000.json','["雪意不肯休，垂垂閣雲端。", "餘煖蒸衣裘，勢作墮指寒。", "曛黄陰雨來，俄忽急雨𩆓。", "空階答簷語，跳珠上闌干。", "世尊儼無說，凍坐誰爲歡。", "蕭條僧舍影，癡兀依蒲團。", "相照憐短檠，坐恐膏油乾。", "勞生竟何如，歲月如走丸。", "七星在長劍，細事何足彈。", "尚想丘園人，慚頰時一丹。", "徘徊經屠門，飽意只自謾。", "顧惟淬牛刀，庶足厭一餐。", "不然學農圃，趁此筋力完。", "年豐得飽飯，日晏眠茅莞。", "咄嗟萬里空，俯仰百歲殫。", "行止信流坎，所遇隨足安。", "勳名片紙薄，天地如瓢簞。", "離騷幸相逢，濁酒聊自寬。", "誰與談此心，夜氣方漫漫。", "絕牆過饑鼠，翻倒爭餘殘。"]'),
('0bd97341-0f8a-467a-8f3a-7a0023a530b0','清明過下渚湖','毛滂','宋','宋诗','song-poetry','','[]','濕雲堆雨未全輕，啅鵲翻枝已喚晴。',64,'全唐诗/poet.song.70000.json','["濕雲堆雨未全輕，啅鵲翻枝已喚晴。", "含雨落花空淚眼，襲衣香草欲知名。", "細泉入竹通幽意，孤策侵苔記獨行。", "不醉河陽芳樹底，亂山攜酒過清明。"]'),
('995c0ed6-9620-484c-9865-ba9b96857300','銅山','毛滂','宋','宋诗','song-poetry','','[]','擬共孤雲結往還，更名居士小香山。',32,'全唐诗/poet.song.70000.json','["擬共孤雲結往還，更名居士小香山。", "他年誰復尋遺賞，爲到雲山杳靄間。"]'),
('67f6b9bc-f223-48ab-baf3-a65a936e499b','石頭寺','毛滂','宋','宋诗','song-poetry','','[]','碧瓦朱甍紫嶺東，昂雲松桂響寒風。',32,'全唐诗/poet.song.70000.json','["碧瓦朱甍紫嶺東，昂雲松桂響寒風。", "靈泉清映銀牀在，無復當年大小空。"]'),
('5fc58c82-5201-4bfb-a495-63ebcabbba96','仙居禪院','毛滂','宋','宋诗','song-poetry','','[]','瀟灑仙居院，樓臺煙靄中。',48,'全唐诗/poet.song.70000.json','["瀟灑仙居院，樓臺煙靄中。", "夜泉清浸月，午鐸冷搖風。", "轉目已成昨，累名俱是空。", "一尊林下醉，此興誰與同。"]'),
('7b7657f3-60a6-4783-a7f8-5c5af022c819','題仙居禪院懷舒閣','毛滂','宋','宋诗','song-poetry','','[]','織水聯珠未是奇，舒王留詠奪天機。',64,'全唐诗/poet.song.70000.json','["織水聯珠未是奇，舒王留詠奪天機。", "神光已比箕星立，文燄長依舜日暉。", "一沼蛟龍涎半積，兩檐鸞鶴勢雙飛。", "名山從此流傳永，自昔因人重發揮。"]'),
('fd9a257e-613b-4ffe-9f23-f39a6e1265f4','入石頤寺','毛滂','宋','宋诗','song-poetry','','[]','去年倚策憶春殘，芳草重尋翠屈盤。',64,'全唐诗/poet.song.70000.json','["去年倚策憶春殘，芳草重尋翠屈盤。", "苔磴漸高天咫尺，巖花未老露濛濛。", "鳴禽時託朝霞暖，煙澗猶分夜雨寒。", "俯看衆山皆迤邐，此心不盡四圍寬。"]'),
('982a3463-f67a-474a-87c9-e810e13a7636','訪無畏庵琳和尚','毛滂','宋','宋诗','song-poetry','','[]','踏遍武康境，銅山分外幽。',48,'全唐诗/poet.song.70000.json','["踏遍武康境，銅山分外幽。", "師今提奧恉，誰不仰風流。", "松老巢玄鶴，車閑臥白牛。", "一時冠蓋擁，欲去更遲留。"]'),
('1795e390-006f-4002-8af3-689137a6cb75','句  其一','毛滂','宋','宋诗','song-poetry','','[]','苕水相逢眼便青。',8,'全唐诗/poet.song.70000.json','["苕水相逢眼便青。"]'),
('b518c063-4ceb-4ad9-ae82-ff24d393335b','句  其二','毛滂','宋','宋诗','song-poetry','','[]','貪戀恩波未肯飛。',8,'全唐诗/poet.song.70000.json','["貪戀恩波未肯飛。"]'),
('7449ee78-c346-4b42-91ce-5273d0c8d1c6','存目','毛滂','宋','宋诗','song-poetry','','[]','詩題：對月憶滿子權首句：長風掠海來。',18,'全唐诗/poet.song.70000.json','["詩題：對月憶滿子權首句：長風掠海來。"]'),
('ddfbfdfe-01ca-41ec-ac5e-2529b009e429','劍池','黄昭','宋','宋诗','song-poetry','','[]','一劍已飛去，千年池尚存。',48,'全唐诗/poet.song.70000.json','["一劍已飛去，千年池尚存。", "浮圖入雲表，古寺倚山根。", "虎踞石形險，龍潛水氣昏。", "闔閭成底事，遺恨滿乾坤。"]'),
('3622b8b8-3347-4895-be16-aff543f8e14d','章華臺碑','高道華','宋','宋诗','song-poetry','','[]','故國興亡數，勤民土木嘉。',24,'全唐诗/poet.song.70000.json','["故國興亡數，勤民土木嘉。", "廢臺稱是楚，辨物愧非華。"]'),
('7474734f-214d-4f8c-acf7-2da1fed3e7e4','留題靈巖寺','卞育','宋','宋诗','song-poetry','','[]','屈指數四絕，四絕中最幽。',120,'全唐诗/poet.song.70000.json','["屈指數四絕，四絕中最幽。", "此景冠天下，不獨奇東州。", "夜月透巖白，亂雲和雨收。", "甘泉瀉山腹，聖日穿巖頭。", "大暑不知夏，爽氣常如秋。", "風高松子落，天外鐘身浮。", "祖師生朗石，古殿名般州。", "人巧不可至，天意何所留。", "老僧笑相語，茲事常窮求。", "移出蓬萊島，待吾仙子遊。"]'),
('e22b6c00-7989-4337-a478-ec3bdef27e65','題清芬閣','王念','宋','宋诗','song-poetry','','[]','籍甚詩名世所傳，耳孫今始出遺編。',64,'全唐诗/poet.song.70000.json','["籍甚詩名世所傳，耳孫今始出遺編。", "發揚風教三綱正，包括乾坤一氣全。", "峻拔孤峰當□□，□容幽澗落春泉。", "超然遠思追前古，好續委蛇二雅篇。"]'),
('2f1d62ba-5226-4ea1-9ddc-dc3ad82b9010','南澗寺閣','王滌','宋','宋诗','song-poetry','','[]','上閣便見海，入門方是山。',24,'全唐诗/poet.song.70000.json','["上閣便見海，入門方是山。", "塔高端似筆，城轉曲如環。"]'),
('07836512-556a-4152-ad49-a4d4748f6949','懷潮士吳子野','王滌','宋','宋诗','song-poetry','','[]','旅悰牢落愴離羣，疊翠樓前日漸曛。',64,'全唐诗/poet.song.70000.json','["旅悰牢落愴離羣，疊翠樓前日漸曛。", "金餅光茫升海月，玉龍鱗甲護霜雲。", "星星淡火隨堤見，歷歷樵歌隔水聞。", "馬足車音在何處，嶂南歧路鎖煙氛。"]'),
('d245dce6-f238-413e-942c-e11e6cb48c30','贈子野歸潮時會大名府','王滌','宋','宋诗','song-poetry','','[]','河朔頻河地早寒，城煙牢落水回環。',64,'全唐诗/poet.song.70000.json','["河朔頻河地早寒，城煙牢落水回環。", "幾番夜雨漲新岸，一片秋雲歸舊山。", "君駟漸騰梅嶺外，我車猶枕菊籬間。", "潮人若問何如守，病骨支撐兩鬢斑。"]'),
('92a40232-d8db-4eac-9eec-3aba2dd926d6','劉阮洞','吳師正','宋','宋诗','song-poetry','','[]','天台春煖蘭若馨，海榴噴血黄鳥鳴。',256,'全唐诗/poet.song.70000.json','["天台春煖蘭若馨，海榴噴血黄鳥鳴。", "風晴雨霽洞天曉，畫屏有路遊人行。", "劉郎阮郎剡溪客，結伴窮幽絕人迹。", "洞口遙聞漱玉聲，日有飄英點溪碧。", "捫蘿涉水前攀緣，瞥見勝景層巒巓。", "夭桃瑤草蔓深谷，飛樓傑閣凌青煙。", "潭上金橋跨龍背，綽約雙鸞飲潭水。", "初疑帝子別瀟湘，珠珮珊珊移玉趾。", "環姿瑋態躊躇久，熟視人間未嘗有。", "羅幙深沈邀客留，胡麻爲飯椒漿酒。", "問郎於此何當還，壺中景迥非塵寰。", "客驚遽返覓閭里，子孫雖在皆重玄。", "年華瞬息嗟浮世，往事分明如夢寐。", "相與迴尋舊路非，亂山稠疊煙雲蔽。", "我來躡屐觀遺蹤，松陰坐久曾不逢。", "野僧相引下山宿，落霞斜日林梢紅。"]'),
('e19ac1d0-83a3-4549-b01a-533c248395f9','題成都笮橋觀音院自畫竹','程堂','宋','宋诗','song-poetry','','[]','無姓無名逼夜來，院僧根問苦相猜。',32,'全唐诗/poet.song.70000.json','["無姓無名逼夜來，院僧根問苦相猜。", "攜燈笑指屏間竹，記得當年手自栽。"]'),
('05e391e5-3792-44fd-bfe8-9b8bbe5aa710','登前守李公亭','鮑粹','宋','宋诗','song-poetry','','[]','李公亭即鮑公亭，何事因仍舊日名。',64,'全唐诗/poet.song.70000.json','["李公亭即鮑公亭，何事因仍舊日名。", "官守二年如過客，風流千古是虛名。", "捫蘿繚繞尋新徑，隔水微茫認故城。", "陵谷變遷君莫問，此中氣象轉分明。"]'),
('7127f080-30d6-458a-b553-99765d61f2cb','句  其一','范習父','宋','宋诗','song-poetry','','[]','地收楚蜀西南水，天與江湖旦暮風。',16,'全唐诗/poet.song.70000.json','["地收楚蜀西南水，天與江湖旦暮風。"]'),
('c11c609a-514e-4b51-9700-1aa3394734a5','句  其二','范習父','宋','宋诗','song-poetry','','[]','可年祖龍遊不得，欲於何處訪蓬萊。',16,'全唐诗/poet.song.70000.json','["可年祖龍遊不得，欲於何處訪蓬萊。"]'),
('760cfbd8-a7db-4bc7-98a3-8a0332ad8d32','奉親兩載爲民祈蠶作競渡於此以五十六言即事','韓煜','宋','宋诗','song-poetry','','[]','中巴舊說古刀州，環壁依城水自流。',64,'全唐诗/poet.song.70000.json','["中巴舊說古刀州，環壁依城水自流。", "魚米豈殊京洛在，人民輕向死生不。", "我來二載無青眼，心嘆三農空白頭。", "修禊何妨書即事，放懷杯酒問田疇。"]'),
('3751097b-4cc6-47cf-83c5-51135c72f0b2','句','張君禔','宋','宋诗','song-poetry','','[]','石間佛足明如玉，山外神光散作燈。',16,'全唐诗/poet.song.70000.json','["石間佛足明如玉，山外神光散作燈。"]'),
('774314ed-4711-4cde-992c-37e267d7b40e','見江亭','袁正規','宋','宋诗','song-poetry','','[]','地產靈芝古道場，危亭陡起負重崗。',64,'全唐诗/poet.song.70000.json','["地產靈芝古道場，危亭陡起負重崗。", "江心遠疊通潮浪，海外遙分異域疆。", "繚繞人家依縣市，寂寥煙景認吳航。", "倚欄望斷暮雲碧，不見長安見夕陽。"]'),
('c3675efc-1d5f-4a5a-aaf7-650590c94350','白雲亭和韻二首  其一','袁正規','宋','宋诗','song-poetry','','[]','幽奇山水卒難圖，亭插白雲景象餘。',64,'全唐诗/poet.song.70000.json','["幽奇山水卒難圖，亭插白雲景象餘。", "共樂靈蹤還舊址，好編名字入新書。", "面前滄海迷三島，林下誰人繼二疏。", "洞裏蒼龍頭角老，埋藏歲月意如何。"]'),
('ac4cd319-f27f-4069-85c8-829e75d5928a','白雲亭和韻二首  其二','袁正規','宋','宋诗','song-poetry','','[]','碧桃溪會創幽亭，豈是從前浪得名。',64,'全唐诗/poet.song.70000.json','["碧桃溪會創幽亭，豈是從前浪得名。", "靜對好山閑日月，卻疑塵世有蓬瀛。", "簷間自在煙雲合，砌下長流風雨聲。", "林塢不遮滄海闊，暫來還得眼雙明。"]'),
('b7b57105-b0b0-4797-998c-387a023e8e18','臨江館','袁正規','宋','宋诗','song-poetry','','[]','巍然水曲見樓臺，人指安昌邑壯哉。',64,'全唐诗/poet.song.70000.json','["巍然水曲見樓臺，人指安昌邑壯哉。", "般若山頭當戶外，吳航渡口瞰江回。", "湖平文鷁浮空遠，月滿星槎泛海来。", "投轄不因勤粤主，爲憐煙靄共徘徊。"]'),
('93e61165-d0e0-41a1-9c59-d33ab6a31949','望海亭','袁正規','宋','宋诗','song-poetry','','[]','沆瀣亭前景最豪，委輸江漢任滔滔。',64,'全唐诗/poet.song.70000.json','["沆瀣亭前景最豪，委輸江漢任滔滔。", "蕩雲處處千層浪，沃日重重萬里濤。", "析木有津連地下，蓬萊堆玉插天高。", "飄然直欲乘槎去，世累須憑割愛刀。"]'),
('5bce6eae-a4d4-4b0e-8a40-fc4ff3269791','九日亭  其一','袁正規','宋','宋诗','song-poetry','','[]','崢嶸棟宇壓巍峨，九日遊人自在過。',64,'全唐诗/poet.song.70000.json','["崢嶸棟宇壓巍峨，九日遊人自在過。", "鳳翅岡高圍海國，龍鱗松古蘸煙蘿。", "齊山景色知難比，彭澤風光幾倍多。", "每上醉來開口笑，幽香無奈菊花何。"]'),
('f57e8388-bda2-4fa4-a36f-bf8f32164a18','九日亭  其二','袁正規','宋','宋诗','song-poetry','','[]','不愧嘉名取次題，寓情彷彿古人齊。',64,'全唐诗/poet.song.70000.json','["不愧嘉名取次題，寓情彷彿古人齊。", "菊添細蕊金英重，松覆清幽蓋影低。", "上戴星辰全咫尺，傍躔日月自東西。", "宜將斗酒頻相屬，靖節從來到處迷。"]'),
('04d013be-7504-4f0e-98db-9a6e1159162d','句','鄭周卿','宋','宋诗','song-poetry','','[]','鶴歸空有恨，雲散本無心。',12,'全唐诗/poet.song.70000.json','["鶴歸空有恨，雲散本無心。"]'),
('1db44da7-0e75-4627-9733-c6ac0b057d33','清江曲','蘇堅','宋','宋诗','song-poetry','','[]','屬玉雙飛水滿塘，菰蒲深處浴鴛鴦。',64,'全唐诗/poet.song.70000.json','["屬玉雙飛水滿塘，菰蒲深處浴鴛鴦。", "白蘋滿棹歸來晚，秋著蘆花一岸霜。", "扁舟繫岸依林樾，蕭蕭兩鬢吹華髪。", "萬事不理醉復醒，長占煙波弄明月。"]'),
('9493dd4b-8ed7-46aa-ab2e-b2134d9f2621','後清江曲','蘇堅','宋','宋诗','song-poetry','','[]','層波渺渺山蒼蒼，輕霜殞木蓮葉黄。',64,'全唐诗/poet.song.70000.json','["層波渺渺山蒼蒼，輕霜殞木蓮葉黄。", "呼兒極浦下笭箵，社甕欲熟浮蛆香。", "輕蓑淅瀝鳴秋雨，日暮乘流自相語。", "一笛清風萬事休，白鳥翩翩落煙渚。"]'),
('61d4d684-b3df-410e-9450-29bd0db4320f','重過石井','蘇堅','宋','宋诗','song-poetry','','[]','登臨蕭寺幾回頭，石怪林深山自秋。',64,'全唐诗/poet.song.70000.json','["登臨蕭寺幾回頭，石怪林深山自秋。", "地布黄金長照日，泉溜碧玉暗通溝。", "浚穿地脈疑無底，靜嚙崖根更不流。", "多謝老僧勤供佛，井華曉汲注瓷甌。"]'),
('af06eb22-165f-411d-b5f8-25d4330d28da','題金相寺三首  其一','蘇堅','宋','宋诗','song-poetry','','[]','丈室十一尺，閩山數百層。',24,'全唐诗/poet.song.70000.json','["丈室十一尺，閩山數百層。", "春風近梅柳，臘水漫溝塍。"]'),
('3ab6714d-b1e3-42c9-8122-9da63c758f9a','題金相寺三首  其二','蘇堅','宋','宋诗','song-poetry','','[]','已愛觀音遠俗塵，鷲峰林壑更清新。',32,'全唐诗/poet.song.70000.json','["已愛觀音遠俗塵，鷲峰林壑更清新。", "不辭遍歷安禪地，要使溪山識主人。"]'),
('de5a34f3-89c7-4527-95a7-b3a3bca5fb03','題金相寺三首  其三','蘇堅','宋','宋诗','song-poetry','','[]','隱約開暘谷，坐看雲氣升。',24,'全唐诗/poet.song.70000.json','["隱約開暘谷，坐看雲氣升。", "地神如獻秀，一色露山稜。"]'),
('ee2aca76-1886-4dbd-b0a5-54e20ce9a63d','句','蘇堅','宋','宋诗','song-poetry','','[]','我夢扁舟浮震澤。',8,'全唐诗/poet.song.70000.json','["我夢扁舟浮震澤。"]'),
('542185f2-d0eb-45b2-9d99-fd00c893ef4d','句','蔡雍','宋','宋诗','song-poetry','','[]','滿前青嶂千屏列，直下澄江一带橫。',16,'全唐诗/poet.song.70000.json','["滿前青嶂千屏列，直下澄江一带橫。"]'),
('18cdbaf5-a0c2-42e0-8ad7-3164096915cd','句','曹子方','宋','宋诗','song-poetry','','[]','面前山好無人識，定是飛來小鷲峰。',16,'全唐诗/poet.song.70000.json','["面前山好無人識，定是飛來小鷲峰。"]'),
('35300c91-a545-4143-959d-94b0303ba6a8','句','劉象功','宋','宋诗','song-poetry','','[]','千尋雙劍截不斷，一片閑雲飛過来。',16,'全唐诗/poet.song.70000.json','["千尋雙劍截不斷，一片閑雲飛過来。"]'),
('90c13500-fe35-4624-a9ea-b96445dbdc7b','題拏洋驛','陳宗','宋','宋诗','song-poetry','','[]','畬田高下趁春耕，野水涓涓照眼明。',32,'全唐诗/poet.song.70000.json','["畬田高下趁春耕，野水涓涓照眼明。", "孰道深山最深處，人人解說長官清。"]'),
('b738d7b2-87a0-4c65-b294-adcdb16df30d','秋日遊合江戲題之亭上','郭思','宋','宋诗','song-poetry','','[]','秋風錦水樂無涯，獨上亭軒四望嘉。',64,'全唐诗/poet.song.70000.json','["秋風錦水樂無涯，獨上亭軒四望嘉。", "橘子滿林金作塊，蘆梢拂岸雪飛花。", "酒旗高掛芙蓉港，漁棹斜趨菡萏家。", "描入畫圖收取去，故人相對飲流霞。"]'),
('be797c0e-c6bb-4735-82a2-d094662be765','劍門','郭思','宋','宋诗','song-poetry','','[]','斵石爲梁鐵作樞，武侯於此濟師徒。',32,'全唐诗/poet.song.70000.json','["斵石爲梁鐵作樞，武侯於此濟師徒。", "鞭山怒氣金鰲伏，架壑宏模玉蝀攄。"]'),
('d2af01c0-5331-4fef-bc09-25aedcef47c3','句  其一','郭思','宋','宋诗','song-poetry','','[]','猿戲山花暖，人行塞柳青。',12,'全唐诗/poet.song.70000.json','["猿戲山花暖，人行塞柳青。"]'),
('f630556b-f062-49ca-8e4d-d4c7cbe6138d','句  其二','郭思','宋','宋诗','song-poetry','','[]','落星一石幾千年，門外何人扣漢川。',16,'全唐诗/poet.song.70000.json','["落星一石幾千年，門外何人扣漢川。"]'),
('4fe8c9e4-522e-43d8-b28f-214d983880cf','題崎灘鋪壁','黄穎','宋','宋诗','song-poetry','','[]','雨過長空雲出溪，稻苗刺水綠初齊。',32,'全唐诗/poet.song.70000.json','["雨過長空雲出溪，稻苗刺水綠初齊。", "山花也解憐行客，旋放繁英襯馬啼。"]'),
('bc457147-efb7-4cd6-9b7e-c28814ec103c','祭先農','李新','宋','宋诗','song-poetry','','[]','帝先農功，曰惟孟春。',120,'全唐诗/poet.song.70000.json','["帝先農功，曰惟孟春。", "載耒與耜，昕及南畝。", "穜稑薿薿，以布以種。", "帝躬三推，土膏雷動。", "百工比櫛，其耕澤澤。", "歲約有年，裕帝之德。", "我藝我黍，我歛我稷。", "爲醴爲酪，斟酌吉禮。", "吉禮既至，神祇来游。", "燕及祖考，萬邦作休。", "降福孔穰，飶芬其羞。", "於以正辭，亦又何求。"]'),
('311c57f8-b6c3-49f3-a987-0ffa7e545038','送高執中赴文州楒林','李新','宋','宋诗','song-poetry','','[]','兩眼追霜鷹，鐵石懸肺腑。',288,'全唐诗/poet.song.70000.json','["兩眼追霜鷹，鐵石懸肺腑。", "何爲向北風，送子淚如雨。", "平生珍古交，及今未多數。", "相逢漢江曲，聊作蘋鷗聚。", "我疾子不憎，人棄子或取。", "莊舄尚資越，茅蘭植當戶。", "坐與斥鷃爭，秋蓬塌雲羽。", "嘗笑禰正平，飛毫賦鸚鵡。", "身爲机上肉，手復亂撾鼓。", "老瞞畏口實，假手待黄祖。", "早知時不容，歛板就公府。", "社櫟名散材，長年謝斤斧。", "文豹皮爲災，安所逃繒罟。", "我亦懲禰生，嚴律繩步武。", "閉門收舊學，不管脣舌腐。", "子今落窮邊，武庫泣降虜。", "過客無隻輪，捷布恐旁午。", "黑雲壓孤堞，殘月走夜麈。", "四鄰遞陰風，隔壁嘯乳虎。", "非但飲徒曠，愈覺詩思苦。", "參軍新婦賢，眉頰生媚嫵。", "慰子遠行役，舉桉頭自俯。", "已聞富書囊，到即充棟宇。", "異時寶弓劍，棄置賤如土。"]'),
('5f1ba343-2ef5-4da7-add3-2b6942a382f6','送李能','李新','宋','宋诗','song-poetry','','["\u897f\u6e56"]','擷蕙仙人洲，日下舞雩歸。',144,'全唐诗/poet.song.70000.json','["擷蕙仙人洲，日下舞雩歸。", "晴光闊天宇，羃羃祥煙飛。", "旦起修羊酒，來觀石麟兒。", "刮眼玉骨異，無用金絡羈。", "長楊獻賦去，英譽嵩少低。", "俯署神仙聽，親植桃花枝。", "走馬秦樹側，濯纓錦江湄。", "春深小瀛洲，西湖生綠漪。", "華堂富花氣，春酒歌白眉。", "彼美南方秀，移根天之涯。", "幽巖蔽嘉卉，芳姿長陸離。", "誰如古工師，來採窮民詩。"]'),
('33157e86-a4e0-461f-8e6e-4cca0058aeda','雜言二章送柳慎徽赴道州教授  其一','李新','宋','宋诗','song-poetry','','[]','荷衣老長官，擁紬呼衙晚。',60,'全唐诗/poet.song.70000.json','["荷衣老長官，擁紬呼衙晚。", "黄閣有造父，伏驥起編棧。", "廣文局如水，何人檄慵慢。", "豈無同升公，空谷飽藜莧。", "寄書獲我心，正須衡陽鴈。"]'),
('7375a339-f1b2-4d98-bfb7-3d0f39a16e81','雜言二章送柳慎徽赴道州教授  其二','李新','宋','宋诗','song-poetry','','[]','白髪柳夫子，政是柳州孫。',72,'全唐诗/poet.song.70000.json','["白髪柳夫子，政是柳州孫。", "譚經能解頤，經綸出其門。", "彼美蒼梧士，紉服得蘭蓀。", "抽身朱墨間，初知儒者尊。", "報國直以人，不類一飯恩。", "山中多散材，著意採蟠根。"]'),
('e5b10155-f973-4481-9a49-9d41d225e657','送崔生','李新','宋','宋诗','song-poetry','','[]','斥鷃意自適，舉俛歡一枝。',60,'全唐诗/poet.song.70000.json','["斥鷃意自適，舉俛歡一枝。", "安知摶扶搖，乃有萬里期。", "鳴鳳困高岡，愧此腹背衣。", "我無瓊蕤漿，可以療酒饑。", "一稅西南風，勉從黄鵠飛。"]'),
('81b56dc5-5634-4ad9-afd6-bbd8a2336a3a','送万俟持正三首  其一','李新','宋','宋诗','song-poetry','','[]','棠垂千里翠，冠拂九重煙。',36,'全唐诗/poet.song.70000.json','["棠垂千里翠，冠拂九重煙。", "夾鬢紅霞旆，搖龜淺杏韉。", "酒醒思鳳語，惆悵落花前。"]'),
('b564ba36-6ab3-4df5-b59d-8778dac77574','送万俟持正三首  其二','李新','宋','宋诗','song-poetry','','[]','東湖春水歸，湖上主人去。',36,'全唐诗/poet.song.70000.json','["東湖春水歸，湖上主人去。", "紅塵舞衿暗，水面空落絮。", "明日悵孤風，長安在何處。"]'),
('63bfa60d-e171-40a2-9938-851e92845eb2','送万俟持正三首  其三','李新','宋','宋诗','song-poetry','','[]','高歌聞白雪，美味熟醍醐。',36,'全唐诗/poet.song.70000.json','["高歌聞白雪，美味熟醍醐。", "解印懸虚橐，鳴鞭指上都。", "倚樓懷舊德，目遠認平蕪。"]'),
('dc991d13-6a03-4be4-88e6-42e8092a4a94','別莫倩赴茂林','李新','宋','宋诗','song-poetry','','[]','三疊陽關聲，兩行鉛水淚。',36,'全唐诗/poet.song.70000.json','["三疊陽關聲，兩行鉛水淚。", "人方入荒陋，天或我遐棄。", "雪山鴈不到，音書何以寄。"]'),
('83327763-805b-464e-a8a4-0a3c2db7ac7a','和李卿新軒','李新','宋','宋诗','song-poetry','','[]','宦情魯酒薄，自意能久醒。',144,'全唐诗/poet.song.70000.json','["宦情魯酒薄，自意能久醒。", "窮年太常齋，那得有夙酲。", "將身侣記室，碧鸛趨華楹。", "誤倒名卿屣，目光如許青。", "中臺獨稱妙，九棘舊飛英。", "徊翔舜巖廊，飽見重瞳明。", "苦營便蕃歸，尚顧昔管寧。", "人言猶龍孫，去就一羽輕。", "新軒事隱几，大勝安期生。", "綠篠靜娟娟，徙倚驚流鶯。", "翠荷亂田田，小盎搖清泠。", "欲留妨召節，趣起料繁纓。"]'),
('144b0de1-c9b8-4691-be02-eac5c40ae6c7','次韻宋都運慶豳學成','李新','宋','宋诗','song-poetry','','[]','我昨行邠郊，徒馭顔色欣。',96,'全唐诗/poet.song.70000.json','["我昨行邠郊，徒馭顔色欣。", "周道日已遠，猶復見仁人。", "所挾一世舊，至前豈無因。", "載賡七月詩，古風亦已臻。", "如今天下士，氣偉而多聞。", "政成泮宮新，要起後學勤。", "加我以數年，便與張范鄰。", "明當遊涇河，即是泗水濱。"]'),
('e29387d9-33fd-4c0b-b786-0e631eb2ce84','次韻','李新','宋','宋诗','song-poetry','','[]','九頂如故人，要見或可期。',156,'全唐诗/poet.song.70000.json','["九頂如故人，要見或可期。", "下有瓜字江，一別長相思。", "作客殊不惡，何苦獨念兹。", "吾宗此登臨，未覺鳥道危。", "白雲繚籃輿，一線歸路迷。", "且裁半隱衣，令與蠟屐宜。", "吐霧隔凡俗，勝遊那許追。", "我亦癯仙流，詎堪逋客隨。", "江山自美女，生憎鉛黛施。", "遐矚豈厭意，所遇亦復奇。", "峨峨青蟬冠，嫋嫋紫金羈。", "問公是中樂，鼠輩何與知。", "渠愛錢神論，公有山行詩。"]'),
('f5b08cb8-89d9-48ca-89ea-3448b37f7339','甲午九月十七日留題太平寺','李新','宋','宋诗','song-poetry','','[]','秋飈弄寒菊，老木疏空谷。',144,'全唐诗/poet.song.70000.json','["秋飈弄寒菊，老木疏空谷。", "尫驂疲欲休，征意元未足。", "山行循桔橰，澗走數機軸。", "百年一局棋，歘爾分半局。", "當時不識字，雙鬢今定綠。", "作客寧在家，無愁亂心曲。", "結廬東城東，疏畦界明玉。", "鳴蛙等鹵部，晚食自當肉。", "豈須太樂丞，清聖貫渠竹。", "屬媼但酌酒，與媼創高躅。", "宗武但收詩，清名銷五福。", "他時尋此翁，雲深駕黄犢。"]'),
('322e9545-ab3c-4474-8103-3340ae3df748','有懷高執中','李新','宋','宋诗','song-poetry','','[]','危襟坐西軒，綠牖浮曉光。',72,'全唐诗/poet.song.70000.json','["危襟坐西軒，綠牖浮曉光。", "初疑故人來，冷吹嘯疏簧。", "春意已浩蕩，寒雲尚蒼茫。", "家貧食無魚，但覺早韭香。", "念我莫逆友，失計臨邊塲。", "定當何時歸，共此白日長。"]'),
('2802865e-9e76-4436-b68c-410d26cf5d9b','書韓生壁','李新','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','欲爲洛中英，竟成秦地鬼。',36,'全唐诗/poet.song.70000.json','["欲爲洛中英，竟成秦地鬼。", "音書雲雁絕，故園四千里。", "望歸今不歸，愁滿西江水。"]'),
('1a61c80c-cc42-4fcf-8cbb-4db22fc45147','次韻答西城王尉二十韻','李新','宋','宋诗','song-poetry','','[]','自慚井底蛙，邊幅徒自飾。',240,'全唐诗/poet.song.70000.json','["自慚井底蛙，邊幅徒自飾。", "行遇南山虎，引首叩白額。", "前後履尾者，鮮不斃其側。", "長嘯激虚籟，陰風昏月夕。", "裴旻抱弱弓，蕭蕭失寒魄。", "李廣落神鏃，往往中微石。", "嗟無食虎氣，徒爾中區窄。", "半夜欲編料，當場浪呼索。", "有力但足畏，亡機尚可測。", "正將餘生輕，無乃狂病發。", "貴身非千金，保家空四壁。", "王老恰如虎，吞吐不動色。", "過口雖幸免，探穴反有得。", "祗知抱睡難，誰謂向牆迫。", "新詩來相攻，口語頗籍籍。", "遭逢摩詰後，騷雅甘伏役。", "今雖不負丞，固已愧仙職。", "願交要忘年，憎慵妨割席。", "求逐松雲飛，距容劍嶺隔。", "詩成仍屬君，南窗驚鼻息。"]'),
('1e177b96-0237-496a-8b91-cd7f3aeedbf6','送劉尉','李新','宋','宋诗','song-poetry','','[]','斗南無兩劉，弟子半分魯。',144,'全唐诗/poet.song.70000.json','["斗南無兩劉，弟子半分魯。", "傳法得其人，隻履便西去。", "天章蜀家世，生女如士虎。", "我叔亦不癡，最寶劉家婦。", "道通而爲一，何得區文武。", "子路冠雄雞，初不妨學古。", "西山厭魑魅，造化兒并苦。", "老者方謁醫，少者遽攙舉。", "碧雞金馬間，遍我見諸父。", "定當憐小阮，指與稅駕所。", "勿數大刀頭，碧雲合已暮。", "富貴鄙白首，長安在何處。"]'),
('9c40ce14-2024-4ba9-94a8-858c4df0b54c','古興  其一','李新','宋','宋诗','song-poetry','','[]','春採中洲蘭，秋採芙蓉芳。',120,'全唐诗/poet.song.70000.json','["春採中洲蘭，秋採芙蓉芳。", "芙蓉以爲衣，春蘭佩其香。", "曉織比目魚，暮織雙鴛鴦。", "裁成合歡被，副之君子堂。", "粲粲桃李姿，過時空自傷。", "漢宮專使至，羅搜窮洞房。", "長虹直軒轅，祕艷不可藏。", "平時同閨子，坐看鉛華光。", "共解明月珠，私結羅襦襠。", "出門驅車去，富貴無相忘。"]'),
('4334e3c8-d013-4cd0-9840-2bce4ab5bd2b','古興  其二','李新','宋','宋诗','song-poetry','','[]','良人遠行邁，道經折羊腸。',72,'全唐诗/poet.song.70000.json','["良人遠行邁，道經折羊腸。", "五月日如赭，履地猶探湯。", "濯汗無廣陰，赴渴誰饋漿。", "去未定還期，隙月知空床。", "兒小莫應門，妾身當虎狼。", "峻岨作高臺，日日永相望。"]'),
('1f465da1-859c-417c-8c2a-42900583c812','古興  其三','李新','宋','宋诗','song-poetry','','[]','學仙在空谷，不復顧榮名。',48,'全唐诗/poet.song.70000.json','["學仙在空谷，不復顧榮名。", "肯因入俗語，易此高世情。", "仙道竟寥邈，癯身學未成。", "赤松果安在，日夕哀猿聲。"]'),
('aca9b954-fec6-4e98-8614-0e7f2fbbec97','古興  其四','李新','宋','宋诗','song-poetry','','[]','謂言冥飛鴻，四郊絕網罟。',36,'全唐诗/poet.song.70000.json','["謂言冥飛鴻，四郊絕網罟。", "生命法朝菌，羲驂莫停組。", "山中豈久留，迅反無自苦。"]'),
('ba897cd8-acbd-493e-bb84-755ff389ed79','古興  其五','李新','宋','宋诗','song-poetry','','[]','倮葬畏禮法，厚葬索衣衾。',84,'全唐诗/poet.song.70000.json','["倮葬畏禮法，厚葬索衣衾。", "金縷與玉柙，五陵非不深。", "萬寶埋幽光，苦爲羣盜尋。", "上古莫封植，棄之中野林。", "上以飽飛鳥，下從螻蟻侵。", "人情遠臭腐，焉知孝子心。", "死者或有知，自亦畏奢淫。"]'),
('ebcefba7-6ce5-4db9-89e6-3f663e610848','送劉前谿','李新','宋','宋诗','song-poetry','','[]','耀靈浴虞淵，光屬朝夕池。',156,'全唐诗/poet.song.70000.json','["耀靈浴虞淵，光屬朝夕池。", "氤氲滿寰宇，幽草無閒枝。", "岷山玉嶺花，寸根武陵西。", "寒搖塞北霜，疏影何葳蕤。", "春意已浩蕩，造物夫何爲。", "煙條凝淥雨，纈彩紅參差。", "下有濯錦泉，清泠鑑毫釐。", "佳人古西子，徬徨水之湄。", "蘭苕採朝露，佩服良所宜。", "凜然冰雪顔，效嚬那可希。", "江國日云莫，無媒鬢如絲。", "願言配君子，獨立無言蹊。", "誰獻常山根，與之植龍墀。"]'),
('65c70b59-942f-42bb-b7ce-f53adfdfa51d','勸飲','李新','宋','宋诗','song-poetry','','[]','安所求羈客，比坰徐翁廬。',96,'全唐诗/poet.song.70000.json','["安所求羈客，比坰徐翁廬。", "清聖殊不惡，中之百憂紓。", "癭樽但滿注，一飽隨家蔬。", "卷簾矚平野，木影搖扶疏。", "綠針麥刺土，碧幕煙染虚。", "田父老且耕，我尚堪犁鋤。", "勸翁日飲酒，何苦多著書。", "書成人亦惜，酒至懽有餘。"]'),
('f9f2387c-a9a6-40ba-ac30-c91d816dd879','王朝美招飲有能窺狗竇之語因作詩貽之','李新','宋','宋诗','song-poetry','','[]','校書隱馬隊，飲酒窺狗竇。',156,'全唐诗/poet.song.70000.json','["校書隱馬隊，飲酒窺狗竇。", "禮法不見縛，高軒一宇宙。", "二王咤連璧，小王腹如繡。", "囊無一箇錢，氣自秦楚富。", "公子莫焚券，婦翁幸銅臭。", "往年數青蠅，騰䵬輒尚口。", "言我已投劾，謂子不長壽。", "本自植蕪蘼，返惡芝蘅秀。", "青蠅復青蠅，勸爾一盃酒。", "雲衢無遮攔，鬼錄有先後。", "馬糞多長者，百怨不懷舊。", "持此幾酸餘，諸君相挽就。", "坐上要車公，老李苦春瘦。"]'),
('5748a2a7-2e34-489b-aaaf-34c9941dd319','元次山作友丐予乃諺之','李新','宋','宋诗','song-poetry','','[]','罷惰嫉游手，孤獨嗟窮民。',288,'全唐诗/poet.song.70000.json','["罷惰嫉游手，孤獨嗟窮民。", "聾盲本定業，疥癩詎可親。", "生事自破碎，誰肯收頑嚚。", "期期依馬韀，勃勃根車塵。", "眇者道眇者，跛復有跛僎。", "蹴爾既不屑，嗟來猶發嗔。", "色驕從墦間，所與皆貴人。", "氣微仆桑下，會作山鬼鄰。", "七日不火食，自斷無此身。", "所以號道邊，時逢怛隱仁。", "子胥至瀧口，從者亦在陳。", "志鞭平王尸，弦歌杏壇春。", "不聞汩廉恥，亦豈生顰呻。", "只今趨權門，僞不如爾真。", "盃殘炙已冷，赤澤盈精神。", "舐痔嘗便溲，不怕污吻唇。", "摩足拂粒鬚，猥辱以爲申。", "軒然上車馬，氣耀無等倫。", "造請冒風雷，謁吏訶叱頻。", "嘗聞郭恕先，本是先帝臣。", "酒偶挽屠沽，謂言等縉紳。", "衣而龜紫章，解而衣結鶉。", "扶起溝中瘠，便可席上珍。", "定知節義者，以故長賤貧。"]'),
('27903007-811b-4fba-a21c-3948f8435ec7','楊村四十韻','李新','宋','宋诗','song-poetry','','[]','欻行西山隈，茄荻風颼颼。',288,'全唐诗/poet.song.70000.json','["欻行西山隈，茄荻風颼颼。", "陰巖有積雪，竟日無行輈。", "灘聲下層簷，寫出千古愁。", "斷墟燈火光，慘月神鬼謳。", "巇岑泣哀猿，短篠驅歸牛。", "頑雲籠遠嶠，退水拓新州。", "蟾膚纍石拳，龍影臥松樛。", "顧惟衰病姿，畏作魑魅儔。", "若有負郭田，肯抱窮年羞。", "昔懷截犀堅，今成繞指柔。", "况復僻陋地，可是英俊遊。", "山祠鐘送夜，水國笛横秋。", "薄霧晨欺鬢，斜陽獨倚樓。", "眸寒碧冥鴻，葉小沙際舟。", "漁師獵魚去，數獲惟芒鯫。", "射生持虎歸，熟視俱老彪。", "時世賤兩目，東家如寇讎。", "長沙卑濕國，洛陽年少留。", "太白竄夜郎，退之謫潮州。", "才大難爲庸，不死即長囚。", "官職雖差池，志意相夷侔。", "自匪遷逐客，而有遷逐憂。", "田塍古丈人，來爲寒士謀。", "胡不近長安，遠土終悠悠。"]'),
('bda4f1d2-28eb-4c93-a98b-48a342730f3d','洗竹十八韻','李新','宋','宋诗','song-poetry','','[]','誰倣王郎子，庭前種修竹。',216,'全唐诗/poet.song.70000.json','["誰倣王郎子，庭前種修竹。", "清陰生曉雲，遠意近幽谷。", "歲久太昏翳，客來爲湔沐。", "掠地芟蒙茸，揮空除樸樕。", "碧篠惡微瑣，孤根賞幽獨。", "惟防高節傷，不厭冗材秃。", "露枝借蟬附，風榦貽鳳宿。", "筠消螻蟻驚，影淺虻蚋哭。", "減裁終瘦骨，瀟洒自空腹。", "初勞揀擇手，終入窮淡目。", "月浪細搖金，秋聲寒戛玉。", "差肩存挺直，亂眼憎拳曲。", "洞然大夫心，卓爾高士躅。", "春風雨零紅，林木霜換綠。", "長久此君操，正可起頹俗。", "山陰牛羊侵，渭濱斤斧辱。", "持君易金錢，伐盡猶不足。", "是中主人賢，不作薪藁束。"]'),
('7aee7fb1-1f3c-445a-b0da-a58ff2d1eb58','有酒作','李新','宋','宋诗','song-poetry','','[]','富貴日厭意，志願男子多。',156,'全唐诗/poet.song.70000.json','["富貴日厭意，志願男子多。", "饑寒一身贅，奈此兩臂何。", "有子立參肩，於人猶負痾。", "食菜色染顔，肘露枯樹柯。", "柴門曠賓從，汝往張雀羅。", "不粒尚猶可，無酒傷天和。", "半世友孫生，斗祿才免薖。", "割腹送名酒，一飲衰頰酡。", "弱子知有酒，走戲如投梭。", "鐡也未抵醉，阿林先緩歌。", "環守獨脚銼，盃到傾長河。", "我若不飲酒，顧影已婆娑。", "仰看頽簷日，去去疾滄波。"]'),
('21a80e65-3a4a-481a-8737-798b32f462bb','過淨慧院','李新','宋','宋诗','song-poetry','','[]','曉披鷫鸘裘，繚繞青冰陌。',60,'全唐诗/poet.song.70000.json','["曉披鷫鸘裘，繚繞青冰陌。", "高原回東飈，草木負春色。", "瀟洒竹間寺，慰此流浪客。", "谿梅薦餘馨，林光動寒碧。", "一寸經綸心，長嘆念行役。"]'),
('3b0cc895-312e-4f0a-9518-7c61aacbb6cd','虚明齋','李新','宋','宋诗','song-poetry','','[]','道源泠然白，疏通無一塵。',72,'全唐诗/poet.song.70000.json','["道源泠然白，疏通無一塵。", "中扃泬寥生，太古以上人。", "齋居不三月，水鏡冰壺身。", "日觀紅未昇，綠瑣先知晨。", "逍遙且齊物，靜與鴻濛親。", "如求漆園吏，先與卜西鄰。"]'),
('4d62f371-ea70-4df2-81dd-0794b1f23844','山居','李新','宋','宋诗','song-poetry','','[]','綠樹初浮光，嘉禽自行樂。',48,'全唐诗/poet.song.70000.json','["綠樹初浮光，嘉禽自行樂。", "廚煙續雲根，澗水斷冰脚。", "徜徉一樽酒，坐看山花落。", "日暮歸去來，嫣香裛羅幕。"]'),
('b58c2e8c-105c-44b7-8589-ce8d281b95ce','彦升索春暉亭詩予昔登亭上見凡賦詩率比興於寸草如東野初語予疑命名者意在春暉育物如慈母之賢欲彦升朝夕眂亭名必有得矣今無負於春暉予是以有作也','李新','宋','宋诗','song-poetry','','[]','雕龍雛老師，塊坐司莩灰。',156,'全唐诗/poet.song.70000.json','["雕龍雛老師，塊坐司莩灰。", "東皇駕青車，先動一信來。", "咸池洗日光，擁出扶桑臺。", "從前幽谷根，細甲亦以開。", "百嘉各分榮，差徧嶺頭梅。", "玉壺花箙遲，舒景詎可催。", "河水澌液流，暖意何限回。", "要見物化工，無處求枯摧。", "晴暉最浩蕩，氣律浹九垓。", "慈母融和心，撫弄從提孩。", "明眸照封胡，笑齒發老萊。", "君求賦春暉，世豈無鄒枚。", "孝報日益豐，但先植三槐。"]'),
('342b29c9-a461-4b0f-be61-39eebabce7fc','冬','李新','宋','宋诗','song-poetry','','[]','北風多雪霜，嚴冬無勁草。',48,'全唐诗/poet.song.70000.json','["北風多雪霜，嚴冬無勁草。", "獨有青青松，歲寒能自保。", "坐歌鳳凰曲，心馳千里道。", "歌聲徒繞梁，誰知此懷抱。"]'),
('a45ba79f-5ffc-472c-a538-ef370e988135','南至日過鹽埧官亭','李新','宋','宋诗','song-poetry','','[]','墮衣黄楓香，着鬢青霜濕。',120,'全唐诗/poet.song.70000.json','["墮衣黄楓香，着鬢青霜濕。", "江山如故人，到眼類長揖。", "客行先飛蓬，不肯擬馬立。", "時節當書雲，相將何太急。", "我本芻牧兒，家有舊蓑笠。", "勤心朱墨間，銷減耕耨力。", "欲歸倒虚囊，追赴村社集。", "傳言東鄰翁，但空西向席。", "梨栗隨所有，大白更增一。", "勿復問市朝，與翁醉終日。"]'),
('68560a39-4917-4ab0-90b5-646ae2ea4560','蕎麥','李新','宋','宋诗','song-poetry','','[]','神農播百穀，賜羌荍麥種。',276,'全唐诗/poet.song.70000.json','["神農播百穀，賜羌荍麥種。", "下子分苦甘，甘賤苦蒙寵。", "西山律候晚，春種夏苗茸。", "秋花深入雲，風浪綺霞動。", "灌溉以時節，牧放遠原隴。", "歲登蝸負歸，兔徑行錯總。", "積架連雲根，藁秸亂墟冢。", "赤莖墮釵股，黑實盈缶甕。", "銳首師郭尖，駢結友張仲。", "一身多模稜，四角腹膨腫。", "舂開鐵屑飛，磨澑塵粉凍。", "溲和陶甄手，灰火助培擁。", "劑堅眂鐵石，薄厚擬輕重。", "不問鏡月圖，行至齊眉捧。", "杵窪新炒香，揉以牛羊湩。", "不托遞炊餅，芹美思貢奉。", "來牟莫我貽，桄榔尚珍送。", "大宛來苜蓿，與爾俱闒茸。", "中都千貴人，侍食姬環拱。", "流匙滑玉粒，雕胡不在供。", "四海會萬珍，方丈無點空。", "戎獠犬豕性，真可糠粃共。", "有客飯黄粱，渾忘夢中夢。"]'),
('a5de0fb3-110d-4fd8-8a4a-0d9542202dfc','春日雜言  其一','李新','宋','宋诗','song-poetry','','[]','燕麥詎可食，兔絲那爲衣。',48,'全唐诗/poet.song.70000.json','["燕麥詎可食，兔絲那爲衣。", "重絺不禦寒，野葛難療饑。", "綈袍脫有意，豈得全身歸。", "一飯責相酬，北山寧採薇。"]'),
('ed29a8c8-d3ff-4c8b-aa77-6898587cf5c3','春日雜言  其二','李新','宋','宋诗','song-poetry','','[]','妖桃氣濃暖，蛾眉困風光。',48,'全唐诗/poet.song.70000.json','["妖桃氣濃暖，蛾眉困風光。", "楊花撲羅帳，春夢自悠揚。", "愁心如碧草，隨春日益長。", "碧草逢秋歇，此恨何時忘。"]'),
('5f341abe-4bfb-4f1d-98ca-01409f2d98ad','雜興  其一','李新','宋','宋诗','song-poetry','','[]','燔肉苟不至，何暇稅冕行。',72,'全唐诗/poet.song.70000.json','["燔肉苟不至，何暇稅冕行。", "一日廢禮經，不如無此生。", "相鼠知拱手，寒暑不變更。", "威儀特文具，衽席爲亂萌。", "蔑知聖人意，但以口舌爭。", "如彼爲肉者，死即五鼎烹。"]'),
('b9f96325-c242-4529-9aef-d1a07856d02b','雜興  其二','李新','宋','宋诗','song-poetry','','[]','醴酒偶忘設，於禮殊至微。',72,'全唐诗/poet.song.70000.json','["醴酒偶忘設，於禮殊至微。", "穆生引身去，自昔能見幾。", "陽橋慕香餌，豈知爲禍機。", "楚梟集叢灌，斬伐猶不飛。", "復有陶朱公，去國家亦肥。", "五湖拒扁舟，我信無所歸。"]'),
('ac1ad697-b676-4699-af8e-95b46ae0249b','雜興  其三','李新','宋','宋诗','song-poetry','','[]','四除延月魄，空庭零露滋。',84,'全唐诗/poet.song.70000.json','["四除延月魄，空庭零露滋。", "西風獵黄葉，蕭蕭辭故枝。", "前日秀春陽，詎知彫落時。", "反側孤衾裯，早寒先自知。", "藁砧山上山，刀頭杳無期。", "無乃逐新歡，巧畫雙蛾眉。", "妾心南山石，生死竟不移。"]'),
('7cdbd883-3d00-47dc-8178-2e70eac6050d','辛苦行','李新','宋','宋诗','song-poetry','','[]','君採北山薪，妾捕西谿魚。',48,'全唐诗/poet.song.70000.json','["君採北山薪，妾捕西谿魚。", "登山莫避險，入山深何虞。", "君行妾亦行，辛苦同朝晡。", "相樂成家室，此義千載孤。"]'),
('4cadb253-f1f9-4988-8dec-8b121e767188','古意  其一','李新','宋','宋诗','song-poetry','','[]','虎頭自食肉，何在識一丁。',60,'全唐诗/poet.song.70000.json','["虎頭自食肉，何在識一丁。", "五言纖巧詩，便歎當長城。", "讀書髪早白，不讀鬢晚青。", "窮邊物蕭條，鳥雀下空庭。", "雖亡好事者，勿廢草玄經。"]'),
('5f674d14-4adc-42ad-b4b1-d37d67799fb7','古意  其二','李新','宋','宋诗','song-poetry','','[]','無分清濁流，殺爾投河伯。',48,'全唐诗/poet.song.70000.json','["無分清濁流，殺爾投河伯。", "無結死生交，一死生便隔。", "模稜不失事，禍起分黑白。", "百年過逆旅，今是長安客。"]'),
('c9e4ce37-2346-434b-97a0-bd45461bfc74','古意  其三','李新','宋','宋诗','song-poetry','','[]','嗟來吐食死，漂母愛王孫。',48,'全唐诗/poet.song.70000.json','["嗟來吐食死，漂母愛王孫。", "等是乞憐人，一飽何足論。", "東方老先生，笑傲忘至尊。", "朔饑侏儒飽，且用長短分。"]'),
('be183ccb-d261-462f-81dd-f6a59d90241a','古意  其四','李新','宋','宋诗','song-poetry','','[]','野人孤鶴姿，與雲相伉儷。',72,'全唐诗/poet.song.70000.json','["野人孤鶴姿，與雲相伉儷。", "百禽相和鳴，了不關鶴意。", "彼美靚閨女，窺戶欣客貴。", "復有琴心挑，中夜駕車至。", "詞章燦星漢，市門甘滌器。", "竟使誰病痟，野人却歔欷。"]'),
('bbc47dc1-488a-4426-9504-1f795ed73d6d','日出東南隅','李新','宋','宋诗','song-poetry','','[]','日出東南隅，照見城西途。',60,'全唐诗/poet.song.70000.json','["日出東南隅，照見城西途。", "出門履冰去，荆棘殘人裾。", "洛陽繁華陌，車馬尋芳客。", "欲往從之遊，青松淡無色。", "安得鄰松心，投君千歲陰。"]'),
('90835148-0773-4dfa-a2c8-e36d2ff941fa','憶故園','李新','宋','宋诗','song-poetry','','[]','杖藜出北郭，山阿延餘暉。',72,'全唐诗/poet.song.70000.json','["杖藜出北郭，山阿延餘暉。", "屏營立高原，霜飈吹我衣。", "牛羊稍絕跡，聚落燈火稀。", "顧我豈無家，廢置不得歸。", "大田已蕪沒，故丘人亦非。", "終當問遺老，何如丁令威。"]'),
('b2409b5d-5055-4959-8506-65ae76b980fa','將進酒','李新','宋','宋诗','song-poetry','','[]','君不見青青河畔草，秋死嚴霜春滿道。',128,'全唐诗/poet.song.70000.json','["君不見青青河畔草，秋死嚴霜春滿道。", "又不見天邊日，薄暮入虞泉，曉來復更出。", "匆匆年光不相待，桑海由來有遷改。", "人生荏苒百年間，世上誰能駐光彩。", "秦皇漢武希長生，區區烟霧求蓬瀛。", "驪山茂陵皆蔓草，悠悠千載空含情。", "榮枯自有主，富貴不可求。", "正值百花飛似雪，如何不飲令心憂。"]'),
('496de1b0-a6af-4ed4-b947-ea200beeabba','勸公樂','李新','宋','宋诗','song-poetry','','[]','金印莫療饑，珠玉難可肥。',60,'全唐诗/poet.song.70000.json','["金印莫療饑，珠玉難可肥。", "碧酒濡唇百事美，綠鬟扣眼一笑隨。", "跳丸日月不受縳，朱顔易逐飛花落。", "情知一死同衆人，何不趁取生前樂。"]'),
('2488e7d4-640b-42c2-b27c-798ddd1eb353','有所思','李新','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭始波秋風起，舟人怨遙心在水。',64,'全唐诗/poet.song.70000.json','["洞庭始波秋風起，舟人怨遙心在水。", "眸寒不見瀟湘雲，天碧江沉一千里。", "西洲蓮老誰愁紅，蘭橈欲採悲秋容。", "採得秋容咽無語，白日長安在何處。"]'),
('b0948684-92f9-4c60-8036-54d6ac44ec76','行路難','李新','宋','宋诗','song-poetry','','[]','君不見天上星，萬古耀虚碧。',241,'全唐诗/poet.song.70000.json','["君不見天上星，萬古耀虚碧。", "豈意一夕間，墮地化爲石。", "物理變化無定端，誰保人心無改易。", "憶妾江邊採白蘋，郎騎白馬渡江津。", "垂鞭停棹潛相顧，共惜當年桃李春。", "石城二月東風暮，斷腸狂絮隨郎去。", "百年誓擬同灰塵，醉指青松表情愫。", "可憐一日君心改，前日之言復誰顧。", "棄捐不待顔色衰，忍把流年坐相誤。", "還君明月珠，解妾羅襦結。", "念之空自傷，長慟與君别。", "出門望鄉關，不惜千里行。", "從人既非禮，何以見父兄。", "去住兩不可，佇立以屏營。", "此時心斷絕，始信天無情。", "野水東流去不還，憂樂翻變須臾間。", "婦人將身弗輕許，聽歌今日行路難。"]'),
('a9962704-899e-49ba-8d93-c96afa8c8920','漁父曲  其一','李新','宋','宋诗','song-poetry','','[]','黄蓑老翁守釣車，賣魚得錢還酒家。',64,'全唐诗/poet.song.70000.json','["黄蓑老翁守釣車，賣魚得錢還酒家。", "醉中乘潮過别浦，睡起不知船在沙。", "籬根半落春江水，稚子蓬頭採洲芷。", "蓴絲芹甲滿筠籠，日暮谿橋得紅米。"]'),
('d086717c-cbe9-4bb0-9aa0-e7b3cd12d9ee','漁父曲  其二','李新','宋','宋诗','song-poetry','','[]','秋山遠，秋木黄，斜汀曲嶼苕花香。',64,'全唐诗/poet.song.70000.json','["秋山遠，秋木黄，斜汀曲嶼苕花香。", "歸雲带暝卷寒色，晚吹吹回雙鴈行。", "鱸肥酒熟蓴絲美，獨釣孤舟老烟水。", "故人停漿問生涯，湘水光搖碧千里。"]'),
('392a43bf-7885-41e4-a373-93a845f29e5e','送遠曲','李新','宋','宋诗','song-poetry','','[]','紫騮蕭蕭車轆轆，爲君掩淚歌别曲。',64,'全唐诗/poet.song.70000.json','["紫騮蕭蕭車轆轆，爲君掩淚歌别曲。", "城頭月墮鐘鼓殘，安得輪方馬無足。", "離燈熒熒向人冷，便是歸來照孤影。", "與君從此永相望，星在青天泉在井。"]'),
('1d275645-0575-4003-9091-4dc83b57a11c','坦溪亭','李新','宋','宋诗','song-poetry','','[]','溪上龍孫千歲綠，上亭擬掇青溪曲。',32,'全唐诗/poet.song.70000.json','["溪上龍孫千歲綠，上亭擬掇青溪曲。", "團團白露着琅玕，故與幽人送暮寒。"]'),
('c279c4a4-c47d-49a5-b820-1821c31fdd20','東海曲','李新','宋','宋诗','song-poetry','','[]','鑑湖搖碧冷吞吳，虎丘雪樹紛瓊株。',96,'全唐诗/poet.song.70000.json','["鑑湖搖碧冷吞吳，虎丘雪樹紛瓊株。", "破霧冰輪薄雲母，河漢微茫星有無。", "清輝浩渺夫差國，爽氣横空凝夜白。", "古石寒生萬丈光，飛虹遠射徐卿宅。", "徐卿世有玉麒麟，長吟鳯語城南客。", "東海蟠桃紅復紅，千年消息倚春風。"]'),
('00ee5356-134c-429a-be46-a165629159c9','汾陰曲','李新','宋','宋诗','song-poetry','','[]','吾愛西河段干木，凛然節槩凌孤竹。',80,'全唐诗/poet.song.70000.json','["吾愛西河段干木，凛然節槩凌孤竹。", "遺風掃地青塜存，汾水千年爲誰渌。", "水邊劍佩鏘寒玉，熊車來作江陽牧。", "忠梗峩峩一面霜，想像古人今在目。", "我歎今人似古人，絲桐爲播汾陰曲。"]'),
('7d477873-1605-4c62-a60a-24e385d5cbf6','送春曲','李新','宋','宋诗','song-poetry','','[]','東君欲去繁華滅，城南把酒聊相别。',64,'全唐诗/poet.song.70000.json','["東君欲去繁華滅，城南把酒聊相别。", "雲旗風駕不可親，但見楊花飛似雪。", "楊花送君無返期，高臺望斷夕陽低。", "歸來客散深院靜，門前綠暗啼黄鸝。"]'),
('07a782ea-5d84-4fbe-a6ef-d54a71003953','鶴雛引','李新','宋','宋诗','song-poetry','','[]','君不見郝氏庭前晚日破秋陰，隆也便便千古心。',152,'全唐诗/poet.song.70000.json','["君不見郝氏庭前晚日破秋陰，隆也便便千古心。", "又不見雲夢漁磯碧水處，俊也清名掛青史。", "儒風忠節兩傳家，傑氣源源長不已。", "武威夜色沈秋月，武威樓上歌聲咽。", "夢回天與玉麒麟，爭似峩眉千仞雪。", "雪中落落多喬松，蒼枝偃榦如虬龍。", "枝上曾棲雲表鶴，養雛飛去翔寥廓。", "年來又見鶴雛歸，城郭依然人已非。", "悠悠却返烟霄去，蜀霧秦雲千里暮。"]'),
('f28e66ef-d026-4be3-a6cb-47e0e700c545','春郊行','李新','宋','宋诗','song-poetry','','[]','半夜東風入桃李，楊柳烟深塵不起。',64,'全唐诗/poet.song.70000.json','["半夜東風入桃李，楊柳烟深塵不起。", "江南乍煖蜂滿園，洛陽初晴花出市。", "走馬尋芳白面郎，回頭巧笑人在牆。", "一聲鶯囀墻南北，引斷行人歸未得。"]'),
('112d5125-a103-4da9-97de-9d16a4be19ab','曉霧行','李新','宋','宋诗','song-poetry','','[]','山川蒸空氣充塞，宇宙冥冥晝昏黑。',128,'全唐诗/poet.song.70000.json','["山川蒸空氣充塞，宇宙冥冥晝昏黑。", "九州四海安在哉，出門寸步迷南北。", "赤烏觜距非不剛，執轡神人身更長。", "胡爲柔濡甘隱翳，坐令萬里無晶光。", "我欲奮袂揮霜刀，恨身無翼愁天高。", "茫然一身不可斷，力微援寡誠徒勞。", "安得長風生海邊，掃除氛穢開青天。", "葵藿傾心知所向，共看白日當空懸。"]'),
('40e2a0c7-ffd2-41e3-9b85-4515113d2a39','中秋夜玄雲蔽月行','李新','宋','宋诗','song-poetry','','[]','惆悵中秋不見月，太陰垂雲兔藏窟。',96,'全唐诗/poet.song.70000.json','["惆悵中秋不見月，太陰垂雲兔藏窟。", "我欲上天掃玄雲，桂露團團漬冰闕。", "中天放出千里光，層樓翠閣遙相望。", "一盃一盃重相勸，今年賞汝中秋願。", "上天高高末由到，玄雲愈濃不可掃。", "空庭蠟炬落寒花，宮裘起舞秋風老。"]'),
('866e92d2-c012-4bd8-b0b4-09e36471672b','江邊行貽趙彦成','李新','宋','宋诗','song-poetry','','[]','江頭舊路楓林遠，長笛欺梅紅尚淺。',64,'全唐诗/poet.song.70000.json','["江頭舊路楓林遠，長笛欺梅紅尚淺。", "榿茅破樹綠無餘，水霧團空寒不展。", "髯郎雙鬢春山青，眼光射客詞如雲。", "却恐抱書移席去，竹風吹雨更愁人。"]'),
('085aa35f-4196-4e29-9e9c-a0f2664bfbf7','感歌行','李新','宋','宋诗','song-poetry','','[]','春陌露草悲銅駞，漢宮秋吹驚紈羅。',80,'全唐诗/poet.song.70000.json','["春陌露草悲銅駞，漢宮秋吹驚紈羅。", "北蟲成塵天峩峩，鐵牛古背横黄河。", "蘭陵千篇窮愁死，屠狗一劍袪羣魔。", "酒闌感槩心如軻，兩眼耀日雲生波。", "是時功名當如何，癡兒竪女徒悲歌。"]'),
('b415a4c7-1f8f-493e-90ef-b18205eea7a1','抱璞吟','李新','宋','宋诗','song-poetry','','[]','最憐皇孫衣如鶉，嘗笑參謀衾似鐵。',128,'全唐诗/poet.song.70000.json','["最憐皇孫衣如鶉，嘗笑參謀衾似鐵。", "我今短褐秃無尾，窮年絮被還百結。", "朂清祗飲洛口水，祁寒欲避西山雪。", "奈何童婢生菜顔，雞肋相將伴頭屑。", "小兒窺見已么麽，自言身是西州傑。", "青天白日用意深，浮雲薄霧生愁絕。", "一夕飲水成內熱，抱璞出門望折節。", "餘光箭牖驚客眠，唤作非真應泣血。"]'),
('552b8f61-13a8-4035-90ae-3c5ffb2482e4','霜月吟','李新','宋','宋诗','song-poetry','','[]','飄飄青女顔如花，雲軿羽蓋乘烟霞。',96,'全唐诗/poet.song.70000.json','["飄飄青女顔如花，雲軿羽蓋乘烟霞。", "手持鳯尾青錦紋，掃空颯颯飛瓊沙。", "嫦娥孤棲宮四寂，倚柱長吟愁永夕。", "曳裾搖珮渡明河，閑弄銀波洗虚碧。", "嬋娟相如争清夜，素彩寒光色相射。", "金烏翻樹不成棲，啞啞半夜遶林啼。"]'),
('13b3668d-ebc7-45da-acbc-84738e7c5595','綺閣吟嘉州李使君命官妓段倩乞詩席上爲賦','李新','宋','宋诗','song-poetry','','[]','秋風瑟瑟吹簾旌，浪英碎玉秋渚平。',112,'全唐诗/poet.song.70000.json','["秋風瑟瑟吹簾旌，浪英碎玉秋渚平。", "綺閣美人抱明月，坐洒銀鈎錐畫雪。", "神情何似衛夫人，小年學歌風挽雲。", "錦囊乞句苦不早，種樹江南今亦老。", "閣中璧月閑搖空，美人巧笑開芙蓉。", "凌波莫背欄干立，捲簾但放餘霞入。", "茂陵白馬何時歸，江北楓花處處飛。"]'),
('2f8c07a6-5537-4e01-8a0b-a6eda72a7bef','有酒歌','李新','宋','宋诗','song-poetry','','[]','晴暘斥沈陰，散漫浮空雲。',100,'全唐诗/poet.song.70000.json','["晴暘斥沈陰，散漫浮空雲。", "手提竹谿醪，疾聲呼細君。", "且滌牛頭樽，我欲有所云。", "仰看東南天，始見昭回文。", "星星眩兩目，歘爾還相分。", "天下愛浮雲，浮雲能自寄。", "屬君看浮雲，要識浮雲意。", "何必持身苦苦愁，但願有酒長長醉。"]'),
('b968c1b7-5f3f-4fe0-9745-a03abf94a89e','醉中歌','李新','宋','宋诗','song-poetry','','[]','駱夫子，逢惡客，酒食未闌客呼索。',142,'全唐诗/poet.song.70000.json','["駱夫子，逢惡客，酒食未闌客呼索。", "燭花銷鑠不肯起，口縱長歌手彈拍。", "一年所得能幾許，一日散盡何所惜。", "囊無千黄金，亦無雙白璧。", "負郭二頃田，歛稅三四石。", "十九種秫穀，以助糟丘癖。", "家釀憙次道，狗竇招光逸。", "何物駱夫子，乃爾太曠生。", "始知張翰一盃酒，愈於身後名。", "駱夫子，聽歌聲，爲君留好語，伴月照江城。"]'),
('d0e97025-bfe7-4255-8766-89846dc2f69e','飛練歌呈宋豳州宏父','李新','宋','宋诗','song-poetry','','[]','玉娥入月雲鈎衣，素裙雪綃雲畔垂。',144,'全唐诗/poet.song.70000.json','["玉娥入月雲鈎衣，素裙雪綃雲畔垂。", "三山老仙不倦舞，霓裳半在秋江舉。", "謝郎解取澄江擬，飛下高城化清泚。", "朝元環珮玉玲瓏，天風吹落人間耳。", "六月夸父暍將死，一吸瀾翻九河水。", "蟾鄉換入石泉中，古柳陰前授瓊几。", "清泉無苦多酌我，空洞麟腸已行舸。", "窮源直上翠微峰，小段參差繡嶺宮。", "歸來泉邊却張席，女頭殘月投蒼璧。"]'),
('8e2659fe-1f9e-4f25-bff5-ba1a91a72357','送張德翁推官赴闕歌','李新','宋','宋诗','song-poetry','','[]','君不見長安城中長樂坡，坡前冠蓋肩相摩。',115,'全唐诗/poet.song.70000.json','["君不見長安城中長樂坡，坡前冠蓋肩相摩。", "十人八九送别者，我今亦吟送别歌。", "任煩應劇青山裏，下望州廛如井底。", "白雲滿眼心無塵，明月到窗詩就紙。", "山花映面春日遲，紫騮嘶去聞行期。", "年來聲韻非相知，幾屬喧啾輕薄兒。", "我歌止此不復作，更欲作歌當寄誰。"]'),
('a1f0e9ac-c0ae-448e-b486-57123ec8412f','春晝歌','李新','宋','宋诗','song-poetry','','[]','櫻桃花落春風暖，綠波浤浤春渚滿。',64,'全唐诗/poet.song.70000.json','["櫻桃花落春風暖，綠波浤浤春渚滿。", "龜屏六曲晝夢回，紅日一庭香絮亂。", "層樓幛雲身半倚，春意撲人濃似醉。", "茂陵白馬歸不歸，眼没平蕪一千里。"]'),
('1d259e99-8660-4afe-9270-3cdb09b091d3','苦寒歌','李新','宋','宋诗','song-poetry','','[]','北風吹窗琴自動，擁爐不覺氈裘重。',64,'全唐诗/poet.song.70000.json','["北風吹窗琴自動，擁爐不覺氈裘重。", "孤城日落星斗稀，一寸清霜壓寒夢。", "河冰嶺雪隨高深，山雞啄土鶴在林。", "西樓歌舞隔珠幄，獨有春風人不覺。"]'),
('1646b815-8129-4008-8425-263bdbd359fa','龍興客旅效子美寓居同谷七歌  其一','李新','宋','宋诗','song-poetry','','[]','陰風刮天雲自幕，窮山十月愁搖落。',65,'全唐诗/poet.song.70000.json','["陰風刮天雲自幕，窮山十月愁搖落。", "歸來嚢有惜空虚，石田擬與誰耕鑿。", "我生正坐儒冠誤，終年凍餓如癯鶴。", "嗚呼一歌兮歌已悲，山鬼爲我相追啼。"]'),
('08457b07-99b4-4a37-872e-771e5b6d3bc9','龍興客旅效子美寓居同谷七歌  其二','李新','宋','宋诗','song-poetry','','[]','隔窗冷吹嘯疏篁，頹雲逼月色無光。',65,'全唐诗/poet.song.70000.json','["隔窗冷吹嘯疏篁，頹雲逼月色無光。", "南鄰昨歌今日哭，訣别未永相思長。", "我今與之正同調，無錐能直九回腸。", "嗚呼二歌兮歌再曲，唧唧悲音斷還續。"]'),
('35019bc1-cf29-4bfa-a6dd-f01e15b29570','龍興客旅效子美寓居同谷七歌  其三','李新','宋','宋诗','song-poetry','','[]','殞我父天悲入骨，更有諸昆寄吳越。',65,'全唐诗/poet.song.70000.json','["殞我父天悲入骨，更有諸昆寄吳越。", "拊膺洒血欲長號，畏傷孀母輙不發。", "罪逆自合當刑誅，神譴人怒豈汝忽。", "嗚呼三歌兮歌極傷，午天爲我下嚴霜。"]'),
('95470c67-4c58-443b-82e4-93d8053da208','龍興客旅效子美寓居同谷七歌  其四','李新','宋','宋诗','song-poetry','','[]','有弟有弟汴之陽，共失所怙心摧傷。',65,'全唐诗/poet.song.70000.json','["有弟有弟汴之陽，共失所怙心摧傷。", "裁書黄耳送不到，道遠未知存與亡。", "歲云暮矣天蒼蒼，鴈飛安得隨汝行。", "嗚呼四歌兮歌愈急，漏天爲我同時泣。"]'),
('f1186e18-6563-4486-af6e-d800e48d0ecc','龍興客旅效子美寓居同谷七歌  其五','李新','宋','宋诗','song-poetry','','[]','蕭蕭角聲疊疊鼓，招提曠蕩無環堵。',65,'全唐诗/poet.song.70000.json','["蕭蕭角聲疊疊鼓，招提曠蕩無環堵。", "編蓬懸席不遮攔，西面透風東面雨。", "官歸庇身無一瓦，反更罹此百憂苦。", "嗚呼五歌兮歌思多，不曰有命其如何。"]'),
('10380026-0837-4e9f-ac4e-f00a35c6e6d5','龍興客旅效子美寓居同谷七歌  其六','李新','宋','宋诗','song-poetry','','[]','西山白虎跳天遊，朝食行人暮噬牛。',65,'全唐诗/poet.song.70000.json','["西山白虎跳天遊，朝食行人暮噬牛。", "居民胡不避此苦，復聞暴吏猛於虎。", "怪爾巨蠧敢身由，拔劍一擊誓不留。", "嗚呼六歌兮歌六疊，太息仰空淚横臆。"]'),
('e46b0fa3-74b0-4c74-9dd9-17804c35220a','龍興客旅效子美寓居同谷七歌  其七','李新','宋','宋诗','song-poetry','','[]','富貴貧賤無巧拙，時來火光遞生滅。',65,'全唐诗/poet.song.70000.json','["富貴貧賤無巧拙，時來火光遞生滅。", "世路不容一井寛，啞啞跳蛙笑東鼈。", "殘盃冷炙勿復道，故交惟有西山雪。", "嗚呼七歌兮歌章畢，死血埋墳色應碧。"]'),
('2dbe30eb-0a7b-4422-9b87-e825e06ae5c9','丙寅四月乙丑夜漏未盡五鼓三嵎程平起問安堂上燈爛然有圓相事異耳根故孝聲大譟士爭賦詩伻來叩某某亦爲作燈光謠','李新','宋','宋诗','song-poetry','','[]','夢過漆園胡蝶入，月落松窗煙霧濕。',96,'全唐诗/poet.song.70000.json','["夢過漆園胡蝶入，月落松窗煙霧濕。", "曉涼却恐老兒寒，驚起薪牀穿破褶。", "土壁蕭條室如水，貸粟何人借甘旨。", "金蓮駕象得得來，華燈一滴祥光開。", "彩暈收還香火寂，門外塵空鏡天碧。", "桂樹殘花蒼影沉，玉娥掃徹雲中魄。"]'),
('54cc6892-2e05-476c-8e65-80cddee960d2','某夏夜酣寢飄然身若凌雲其覺也作夢遊仙以原其所自與狀其所以歸獻於楊德翁其辭云','李新','宋','宋诗','song-poetry','','[]','飄飄夜半身凌雲，夢與羣仙遊玉京。',256,'全唐诗/poet.song.70000.json','["飄飄夜半身凌雲，夢與羣仙遊玉京。", "龍虎騰驤争引導，侍童羅絡甘逢迎。", "絳幡羽扇前驅列，寶蓋華旗助旌節。", "鈞天九奏畢笙竽，飈馭數行響環玦。", "初朝太一何所爲，次歷紫微心自知。", "青虬吐烟滿瓊殿，白鶴起舞臨丹墀。", "更過十洲尋舊友，旋返瑤池燕王母。", "文章已作人間遊，功業却從天上走。", "朝霞乍吸心耳清，沆瀣忽餐肌骨瑩。", "九門不掩閶闔靜，玉女下詔馳名姓。", "始驚造作玉樓記，白馬詩嚢空委地。", "又疑本是謫仙人，錦綬紗巾初溷塵。", "鳯簫一聲輕哽咽，霧卷雲收天水徹。", "葛洪伯喬兩無知，送下九霄不言别。", "時人學仙不得仙，未能白日升青天。", "無心却向夢中見，千萬人中何處傳。"]'),
('bf5c6b09-992f-4387-a30b-4a26145354f3','大雪不宜干人','李新','宋','宋诗','song-poetry','','[]','漫瀰江天慁霏雪，市薪黄金粲環玦。',76,'全唐诗/poet.song.70000.json','["漫瀰江天慁霏雪，市薪黄金粲環玦。", "大寒叵堪出門戶，已麾中涓束漫謁。", "著作千卷字不同，下希牧守上三公。", "榻西有酒鵝兒色，鴻音讀書句成拍。", "句成拍，不是平生等閑客。"]'),
('86afcd98-21cc-4a5e-9c79-eee5fda3c1d7','乘興可以訪戴','李新','宋','宋诗','song-poetry','','[]','瀟湘千里凍誰結，夜趣小傖駕桃葉。',64,'全唐诗/poet.song.70000.json','["瀟湘千里凍誰結，夜趣小傖駕桃葉。", "故人此心思見之，幸有寒光交雪月。", "興來興盡我自樂，棹去棹回共何約。", "入門篝火撥新醅，相對此君殊不惡。"]'),
('95938ee3-486c-4e67-b25d-3eccadcb9296','題遂寧馮德夫隱士畫像','李新','宋','宋诗','song-poetry','','[]','一年三百六十齋，一日不齋事如麻。',78,'全唐诗/poet.song.70000.json','["一年三百六十齋，一日不齋事如麻。", "蒲團曲几烏藤杖，是中正要心出家。", "不耽錢之龐老，未剗草之丹霞。", "幅巾紫裰春顔在，已見山雲埋秋槎。", "逢人莫問西來意，春去杜鵑啼落花。"]'),
('b8efe874-9c5e-49d2-93ad-feb6cc674d19','歸美堂','李新','宋','宋诗','song-poetry','','[]','妙齡通籍金閨裏，三媺垂輝分鼎趾。',128,'全唐诗/poet.song.70000.json','["妙齡通籍金閨裏，三媺垂輝分鼎趾。", "君恩至重論報難，烱烱臣心罄歸美。", "太山深根蟠厚地，嵩華連鼇隆國址。", "黄河一曲一千里，初自崑崙薦繁祉。", "龍馬負出卜世圖，玉敷萬葉春有餘。", "走問南箕天永久，莫計後天難老壽。", "中和賡入頌聲中，明堂布政知無窮。", "當時五章寄天保，而今三祝增華封。"]'),
('51852b0e-8926-45e5-94f1-de9942d6818d','籌筆驛','李新','宋','宋诗','song-poetry','','[]','惡潮翻海真龍泣，未央庭露秋蓬濕。',96,'全唐诗/poet.song.70000.json','["惡潮翻海真龍泣，未央庭露秋蓬濕。", "崧雲無意招不來，旌旗日月隨山入。", "茅屋主人長臥揖，盛氣虬髯横槊立。", "漢陵白骨生春光，半夜平懷聽呼吸。", "筆端隱語飛英略，潛拉秦原老鯢角。", "天心不肯續金刀，渭橋水急妖星落。"]'),
('f661aca1-b05a-402d-af5b-44c14c146057','武功驛留題','李新','宋','宋诗','song-poetry','','[]','霧捲馬蹄塵自起，東風送渡咸陽水。',128,'全唐诗/poet.song.70000.json','["霧捲馬蹄塵自起，東風送渡咸陽水。", "故園花木綠成圍，猶向關中見桃李。", "聞道春前雪最深，行人僵死薪如金。", "羲和不肯爲日馭，潛入北海分幽陰。", "長安今過何曾識，此度劉郎老於昔。", "終南入望眼長青，渭水翻波心更赤。", "只今身在選官圖，夢守么么五十餘。", "衣輕躍駿美年少，愛爾平時不讀書。"]'),
('9b0d5841-c6a7-4289-9f7a-d09a58e20983','項羽廟','李新','宋','宋诗','song-poetry','','[]','平生虎力鼎可扛，憤氣不作咸陽降。',64,'全唐诗/poet.song.70000.json','["平生虎力鼎可扛，憤氣不作咸陽降。", "江東子弟累千百，誰知國士元無雙。", "一夕楚歌四面起，伯圖未就人懷邦。", "自古功業有再舉，何不隱忍過烏江。"]'),
('f6131c75-497a-41e5-b8b7-a0aa09c62547','過垂雲亭','李新','宋','宋诗','song-poetry','','[]','西風吹秋落山谷，霜紅換盡煙邊綠。',64,'全唐诗/poet.song.70000.json','["西風吹秋落山谷，霜紅換盡煙邊綠。", "垂雲門冷一事無，只有庭松與籬菊。", "白日蘭堂一局棋，百年閑事無游絲。", "山僧更勸黄粱飯，真似邯鄲枕上時。"]'),
('4bd768c4-cb2e-4eb3-b460-accc81eade56','飛仙道中','李新','宋','宋诗','song-poetry','','[]','鳥銜桃李墮高卑，陵谷逢春花作衣。',96,'全唐诗/poet.song.70000.json','["鳥銜桃李墮高卑，陵谷逢春花作衣。", "猶憶去年攜小筥，上山獨自採春薇。", "澗流到海住家處，今我無家何更歸。", "修途老來倍酸苦，晚雨一絲愁一縷。", "曉征春事太半無，未盡蜀天已秦語。", "仰看鴻鵠向南飛，笑殺鴟鳶争腐鼠。"]'),
('22d9be7a-9665-43da-baee-7a7becfd9f59','廣都道中作','李新','宋','宋诗','song-poetry','','[]','萬花織籬凡幾曲，繡屏處處圍茅屋。',48,'全唐诗/poet.song.70000.json','["萬花織籬凡幾曲，繡屏處處圍茅屋。", "家貧張日無羅幕，東風吹開莫吹落。", "居人應笑行客癡，春去春歸殊不知。"]'),
('34ae93c2-31a5-430d-8b75-2e905a3e5c85','過東界','李新','宋','宋诗','song-poetry','','[]','雲浮山腰末之頂，水穴青崖浚于井。',96,'全唐诗/poet.song.70000.json','["雲浮山腰末之頂，水穴青崖浚于井。", "孔明不死吾其歸，左衽豈宜蝤蠐領。", "羣羌負藥倍車載，螺齒錢丈束嚢癭。", "得茶便重不便輕，肩突駝峰猶外屏。", "石碉設嶮鳥鼠智，銅鼓銷聲犬羊靜。", "入門蹲足唤煮茶，嚼鐵相甘苦荍餅。"]'),
('39e681ba-45ca-45d5-b349-32a5de0ece09','東陂','李新','宋','宋诗','song-poetry','','[]','珠槃出海山崢嶸，滎陽城東春水生。',112,'全唐诗/poet.song.70000.json','["珠槃出海山崢嶸，滎陽城東春水生。", "路沙陷車沒馬脚，行人避沙堤下行。", "箇中人利魚芡美，輕舠細網晨縱横。", "烟雲瀰茫水面闊，鷗鷺不管機心萌。", "齒繁九州無曠土，此地何得無人爭。", "我欲決水界畦壟，萬頃畢種淵明秔。", "黄簑大笠趁春雨，日與老農来勸耕。"]'),
('9c098bfd-0d30-499a-8b8e-59e1fdcaa9e2','出塞','李新','宋','宋诗','song-poetry','','[]','城頭落日黄雲起，斷草飛蓬滿千里。',120,'全唐诗/poet.song.70000.json','["城頭落日黄雲起，斷草飛蓬滿千里。", "紅塵一騎踏高回，半夜驅兵渡遼水。", "馬蹄行盡關山月，燕然山下沙如雪。", "負戈淚落暗吞聲，煙隴悲笳共幽咽。", "我皇有四海，何用窮元冥。", "邊人縱戮盡，亦是吾生靈。", "先王修德懷四夷，梯航重譯歸無爲。", "不使城南征夫怨，三春折盡綠楊枝。"]'),
('9f31b8d7-db89-4ab1-91db-62e89667f68c','訪幽人','李新','宋','宋诗','song-poetry','','[]','紫騮搖玉東城東，綠睂少年雙頰紅。',76,'全唐诗/poet.song.70000.json','["紫騮搖玉東城東，綠睂少年雙頰紅。", "掃塵先過風騷客，豪氣幾吞雲夢澤。", "新詩一夜急春風，飄落櫻桃點窗白。", "青烟晝覆琉璃罇，何時投袂歌王孫。", "歸去來，黄陵老鴉啼日昏。"]'),
('013bc8c2-3276-4961-9652-68b9b1f7a519','登牛溪嶺','李新','宋','宋诗','song-poetry','','[]','岷峨潤眼長可人，清江水綠如九親。',64,'全唐诗/poet.song.70000.json','["岷峨潤眼長可人，清江水綠如九親。", "水光山色不相送，自涯而返情太真。", "别車驅將向何處，到此已與魑魅鄰。", "投荒哀過三良死，可贖人亦百其身。"]'),
('e45651e1-25b2-425e-a5a5-6f4a1c291e32','題月山亭','李新','宋','宋诗','song-poetry','','[]','山如偃月江如玦，我歌驪駒與公别。',112,'全唐诗/poet.song.70000.json','["山如偃月江如玦，我歌驪駒與公别。", "出門大路礲砥平，何得却言新徑捷。", "新徑無人可問迷，荆棘勾衣馬蹄折。", "急行先到決不疑，大路知公笑人拙。", "巾車和鑾長中節，緩綏脂轂循安轍。", "此身逸樂無疏虞，五里少休十里歇。", "一遲一速勿復論，只將大路指兒孫。"]'),
('023b2c93-2ded-4053-b638-adcd8c11a12b','西軒雜言','李新','宋','宋诗','song-poetry','','[]','風琴牛笛難度曲，早韭晚菘誰當肉。',128,'全唐诗/poet.song.70000.json','["風琴牛笛難度曲，早韭晚菘誰當肉。", "筆端畫餅不得飽，汁少熬雞渾未熟。", "三年楮葉太勞力，八尺鼓圍竟空腹。", "遙遙華胄猶龍孫，皎皎白駒縶空谷。", "頭風豈無草檄愈，醬瓿正須太玄覆。", "供書小吏腕幾脱，免冠毛頴髮仍秃。", "年來軋思倒挽牛，逃虚僧社高如秋。", "乞身得此清涼國，不減人間萬戶侯。"]'),
('441b2af3-f2e3-4b9c-9e2b-1893c22adb34','打剥牡丹','李新','宋','宋诗','song-poetry','','[]','大芽如繭肥，小芽瘦如錐。',204,'全唐诗/poet.song.70000.json','["大芽如繭肥，小芽瘦如錐。", "我今取去無厚薄，不欲氣本多支離。", "綠尖墮地那復數，存者屹立珊瑚枝。", "姚黄魏紫各王后，肯許闒冗相追隨。", "姬周祧廟曾祖禰，主父强漢疏宗支。", "昔人立朝惡黨盛，敗羣雜莠何可知。", "一母宜男竟衰弱，豈有如許寧馨兒。", "吾懼生蛇爲龍禍，又畏百工無一師。", "故今披剥信老手，如與造化俱無私。", "明年春歸迺翁出，空庭還閉絕代姿。", "風雨大是遭白眼，酒炙誰復來齊眉。", "衡門一鎻略安分，幽谷待賞幾無時。", "寄根王謝自得地，燕子歸來汝莫疑。"]'),
('cf8ba985-2a12-4c97-b171-544b33379c7b','飛將','李新','宋','宋诗','song-poetry','','[]','老翁望封竟無有，自是翁骨生來醜。',96,'全唐诗/poet.song.70000.json','["老翁望封竟無有，自是翁骨生來醜。", "猿臂懸知不入相，且有殺降聊藉口。", "翁今遠孫骨雖瘦，不解射鵰能飲酒。", "自漢至今太寂寥，何得遙遙紀華胄。", "尚方侯印只方寸，豈有鑄金大於斗。", "爲翁力取置肘間，令翁千歲無恨顔。"]'),
('ede63695-0645-46d4-8ac5-4a12827cac53','樂園假寐','李新','宋','宋诗','song-poetry','','[]','鵲聲去復回，蟲絲長復短。',40,'全唐诗/poet.song.70000.json','["鵲聲去復回，蟲絲長復短。", "江村石枕冷，一睫春夢斷。", "明朝騎馬且重來，日遲更爲楊花煖。"]'),
('e644c5d7-7ad8-44e8-988f-84fa32313bdc','麻姑','李新','宋','宋诗','song-poetry','','[]','楓樹隔雲香，桃花千歲紅。',80,'全唐诗/poet.song.70000.json','["楓樹隔雲香，桃花千歲紅。", "朝飲瓊華臺，暮燕蓬萊宮。", "翠鬒垂綠烟，霞裾藕絲重。", "明月落空山，那得人間夢。", "手甲鈎長玉芽薄，不墜髻鬟愁綰約。", "入門騎鳯出無蹤，洞外寒聲悵孤鶴。"]'),
('e3006770-e874-46e7-8306-af9bb5aa600a','梓潼張孝女','李新','宋','宋诗','song-poetry','','[]','七盤小阿張孝女，廬墓三年竭酸苦。',144,'全唐诗/poet.song.70000.json','["七盤小阿張孝女，廬墓三年竭酸苦。", "揚塵篩土秃指尖，墮淚漣漣等秋雨。", "領長鶴脊不勝衣，手杖半銷縗百縷。", "彼蒼者天呼不聞，那知此女行高古。", "路行多少忤逆兒，已後令人重生女。", "我哀怙恃今十年，不及增培一坏土。", "俯首廬前有愧色，劓刖情知無可補。", "問女膝行日幾曲，哀聲雖微動巖谷。", "夜燈熒熒慘苫屋，神鬼同愁鴉伴哭。"]'),
('2200bd20-7ed1-4c3a-a0cb-49504fbe3c9d','冬夜有感','李新','宋','宋诗','song-poetry','','[]','蓼蟲常食苦，旅鴈自知寒。',224,'全唐诗/poet.song.70000.json','["蓼蟲常食苦，旅鴈自知寒。", "談士惜卷舌，將軍解愁鞍。", "雪霜滿天冬夜永，地爐無火青燈殘。", "功名富貴苦不早，一年百日紅塵道。", "西還故國無故人，憔悴少年心已老。", "讀書當許萬戶侯，豈意却作蘇秦羞。", "深取閭閻薄徒笑，魯人不識東家丘。", "吾祖謫官還舊里，灞陵亭尉猶低視。", "少卿偶作匈奴降，隴西士人慚姓李。", "由來人世輕不遇，文章第一空徒爾。", "俛出跨下何施顔，當時悔過淮陰市。", "夜深氣射青雲霄，此生早晚當乘軺。", "彈冠舉手揖豪貴，行得紫綬牢結腰。", "本是壯夫志，幾成兒女曹。", "平生重恩義，聊爲寄風騷。"]'),
('659b3d52-1818-43b8-918d-51512fbe39e8','送杜丞','李新','宋','宋诗','song-poetry','','[]','鴨頭未換秋谿綠，漲水吹沙亂泥玉。',124,'全唐诗/poet.song.70000.json','["鴨頭未換秋谿綠，漲水吹沙亂泥玉。", "孤城雨過星斗稀，曉起爲誰歌别曲。", "江臯人散空鷗鷺，飛截長煙斷寒素。", "當年珠珮更悠悠，岸草黄花重回顧。", "細看錦嚢詩字字，杜郎生得真男子。", "太尉國風偃如草，丞相家聲清似水。", "八月涼風來，吹斷浮陰雲。", "風檣急轉望中遠，明日東苑生清芬。"]'),
('6b3a0ed0-52b9-43bd-8228-c453a0d1d1f6','送范秉彝','李新','宋','宋诗','song-poetry','','[]','東風吹起原頭綠，墻暗萋萋芳草縟。',244,'全唐诗/poet.song.70000.json','["東風吹起原頭綠，墻暗萋萋芳草縟。", "舞筵輟按杜韋娘，旗亭便聽金衣曲。", "石城山下路，回首不堪顧。", "灼灼小桃燃，蕭蕭疏雨暮。", "錦岸海棠烟，重尋已四年。", "新班慶蓮幕，舊鬢愧華巔。", "市橋萬縷森森柳，玉勒錦韀快鞭走。", "故人半夜洗牛頭，望載濡唇百壺酒。", "須臾還上鹿頭嶺，道入猨猱怯分影。", "槐陰萬笏黄閣深，沙路歸來定重省。", "後生不乏樂職詩，幽處西南恐未知。", "吏部門人密無數，但慚駑馬煩鞭笞。", "天邊鴈翮已光華，試睨銀鈎看草麻。", "夜直蓬萊得歸晚，照衣金炬長飛花。", "縱鑿城南溝，常有河東鳯。", "青嶂入高吟，行臺集佳夢。", "宦遊無定居，相逢又相送。"]'),
('6d86fe3d-4625-45ba-b047-f48ef6b8fd91','送趙伯高','李新','宋','宋诗','song-poetry','','[]','北窗玩韋編，窮年見三絕。',184,'全唐诗/poet.song.70000.json','["北窗玩韋編，窮年見三絕。", "持文鬬時英，勝不待口舌。", "以此起門戶，鶺鴒同好音。", "何物弟兄賢，令人笑書滛。", "車中瑩連璧，世外無南金。", "當時聲名卑賈馬，嗟今位出稠人下。", "我歸政欲質經疑，禮失尚容求諸野。", "争名國寄涎蝸角，得少失多人不覺。", "渾無鈎距肖子都，大有詼諧勝方朔。", "平時出山遊錦官，馬蹄踏君門前道。", "江長舟自横，逕荒人莫掃。", "不須苦洗霜根髮，星星復出如秋草。", "龍華美酒賤如水，一酌令君變衰老。"]'),
('173e1652-43dd-491d-8e5a-67258711e815','送鞠彭山','李新','宋','宋诗','song-poetry','','[]','丹輪隨待十三州，青瑣文章汗馬牛。',128,'全唐诗/poet.song.70000.json','["丹輪隨待十三州，青瑣文章汗馬牛。", "喜見錢塘山水好，卜居爲有荻花秋。", "年來遊宦無覊束，要醉海棠西入蜀。", "侯門不慣撲車塵，猶憶畫堂紅映燭。", "未易池中甘索寞，乍屈數旬聊自託。", "牛刀行割武陽城，夢魂已到天章閣。", "勸君强作岷峨客，莫念鳯凰煙景隔。", "歸家重倚望湖樓，依前水浸吳天白。"]'),
('8e22177a-c98f-417a-9de4-040354e7bc0a','送菜徐安叟','李新','宋','宋诗','song-poetry','','[]','清非太常而有三百六十齋，貧似庾郎而無二十七種菜。',120,'全唐诗/poet.song.70000.json','["清非太常而有三百六十齋，貧似庾郎而無二十七種菜。", "日食萬錢竟虚語，不糝藜羮時可再。", "一杯瀲灧翻綠波，作客不妨窮鼎鼐。", "大兒咀嚼等太牢，小兒飲啜甘沆瀣。", "青青染腸形於色，阿騖渾無食魚態。", "聞君亦有釡轑聲，大本須煩一車載。", "何苦厲聲責妻孥，乘興可能來訪戴。"]'),
('3e286075-877b-4479-8368-4daaa216c76a','送時仲西歸','李新','宋','宋诗','song-poetry','','[]','掛書牛角來東都，短小不長五尺餘。',176,'全唐诗/poet.song.70000.json','["掛書牛角來東都，短小不長五尺餘。", "龍章鳯姿蘄見用，回叱關吏身無繻。", "志如秋鶚氣如虎，整束衣冠詫齊魯。", "膏油繼晷不識眠，虀鹽充腸久味苦。", "爾來試擬觀國賓，執筆四顧旁無人。", "劉蕡射策不中彀，何蕃如家知有親。", "不平豪憤四五載，虚老身姓三十春。", "杜門讀書破萬卷，終教此道淳乎淳。", "行行雪霜寒凝野，侵星據鞍跨羸馬。", "妻子評郎被褐還，玉柱機頭差不下。", "但誇舌在終可圗，肯向明時慚達者。"]'),
('528e2e31-cc20-42ff-be7f-9623f72ddf50','送柳慎徽赴道州教授','李新','宋','宋诗','song-poetry','','[]','何以送之山前月，千里隨人光不滅。',80,'全唐诗/poet.song.70000.json','["何以送之山前月，千里隨人光不滅。", "何以贈之嶺上雲，出入無心疑似君。", "何爲自此陽城逐，邊老日高快便腹。", "次山曲愛道州民，昔日亂離今太平。", "後來賓興無短瘠，帳裏先生猶七尺。"]'),
('da50840c-8587-4c9d-b54e-95f6f45f8f64','送犢鼻褌與任敦夫','李新','宋','宋诗','song-poetry','','[]','任翁何爲窮，一性共癖左。',212,'全唐诗/poet.song.70000.json','["任翁何爲窮，一性共癖左。", "不妄取芥粒，甘似西山餓。", "短褐結郭絲，犢鼻詎穿破。", "當時北阮貧，矯枉幾太過。", "肯揭長竿頭，恐亦是奇貨。", "豈惟宜躋升，抑自利頓挫。", "濟河不擷褰，秃尾正便坐。", "遲行少前跋，趨急或後簸。", "刀尺初與形，蟣蝨已相賀。", "平生馬鞍間，髀肉已稍磨。", "此既身之章，十年共起臥。", "必以狐裘易，顧我應難和。", "子賦從軍樂，城壚始煩癉。", "服之遠行邁，百步無一蹉。", "爾來玉泉老，以此勸勤怠。", "猶憶當時庾嶺前，傳衣正是普通年。", "問道未餘衣下事，寥寥千載不相傳。"]'),
('d2262220-3220-4e42-a7f1-803a7904a31d','送吳使君','李新','宋','宋诗','song-poetry','','[]','西南世家無十族，吳范生兒長食肉。',224,'全唐诗/poet.song.70000.json','["西南世家無十族，吳范生兒長食肉。", "虎頭犀骨初長成，閉門教草三千牘。", "傳來舊物凌雲筆，楷字君王無第一。", "墨池染盡俱拙人，柿葉學成幾失實。", "聞道甘棠陰已密，相共政聲同一律。", "玉壺盈尺不消冰，清峻照人常慘慄。", "歸侍安車幅巾叟，石建板輿憐白首。", "二年贏得倚欄干，醉看紅梅霜雪後。", "草玄故人偏嗜酒，試拚黄金追百斗。", "芋魁榿木的然成，丙穴郫筒依舊不。", "行舟牽挽由來有，十倍青衿折楊柳。", "未容學舍鞠園蔬，歲月用陶燕許手。", "駑驂無取休推轂，二十四蹄肥苜蓿。", "近時牙頰惜春風，吾曹易效窮途哭。"]'),
('af5ae03d-2469-493b-aca8-d8064b1ba76f','予宿承德日夜苦霪雨擬金筌賦六韻呈陳居中','李新','宋','宋诗','song-poetry','','[]','黑雲䟃𧽼陣巋麓，女媧補天伴天哭。',96,'全唐诗/poet.song.70000.json','["黑雲䟃𧽼陣巋麓，女媧補天伴天哭。", "結愁起坐函丈間，祠禴除門繡黄犢。", "書冊入眼萬花纈，石泉冰腸河九曲。", "市頭老木昏鴉歸，屋角赭山瞿麥熟。", "胡村水平已可渡，軟屐青燈循昔路。", "後期詎能數甲子，希夷長年耳不死。"]'),
('cff4d561-dc2a-4375-aec3-ee23b40b8a50','歲盡行縣歸示時雨','李新','宋','宋诗','song-poetry','','[]','五府辟書如齧鐵，八關炙手能令熱。',96,'全唐诗/poet.song.70000.json','["五府辟書如齧鐵，八關炙手能令熱。", "山梅何苦要先春，清艷更多終欠葉。", "貴遊結懽過美酒，不問賢愚皆可口。", "粃糠簸揚在米前，雞口差池落牛後。", "迺翁活計真么麽，欲掛冠纓猶未果。", "一歲山行今解火，百巧百窮無似我。"]'),
('55f19d02-c360-4e82-b549-d4dcd58ce034','贈術士羅公弼','李新','宋','宋诗','song-poetry','','[]','陂迥山空谿水淺，騎牛信牛行自遠。',192,'全唐诗/poet.song.70000.json','["陂迥山空谿水淺，騎牛信牛行自遠。", "大翁織笠六銖輕，阿母理衣簑直軟。", "短笛叫雲無曲終，年年但見巖花紅。", "何者爲榮何等辱，牛飽歸來睡亦足。", "識字無多浪得官，出門車折舟風瀾。", "當時牧牛無許事，初信人間行路難。", "羅生邂逅孤城角，細數直推期命薄。", "五福無有六極全，四字干頭三字惡。", "逆知大似他心通，元辰空亡那免窮。", "壬癸是非終可畏，收拾人情稱晚貴。", "我家幸有石田在，夢裏歸耕心未改。", "季咸再見應茫然，壺子而今藏九淵。"]'),
('cd1ff5d0-f5fa-4295-95f9-80041c09eb27','謝王司戶惠紙被','李新','宋','宋诗','song-poetry','','[]','霧中楮皮厚一尺，岷溪秋浪如藍碧。',176,'全唐诗/poet.song.70000.json','["霧中楮皮厚一尺，岷溪秋浪如藍碧。", "山僧夜抄山鬼愁，白雪千番沍墻壁。", "裁成素被劣繒綺，故人聊助蘇門癖。", "經年鼾鼻吼蝸室，睡魔已作膏盲疾。", "蕭蕭散髮臥南窗，腹稿未成空費日。", "小兒惡寐驚踏裂，村妻手線自縫密。", "幸無寒泪泣牛衣，却有春温借光逸。", "的知非布誰譏詐，沙汰襆歸安足訝。", "合歡若繡雙鴛鴦，出門便有連城價。", "世外浮華雖自許，錦爛珠光變爲土。", "落日南柯一夢回，斷雲流水無尋處。"]'),
('b0d773f1-e8ff-4aa2-93e1-8037e7d5762e','聽王子定吹簫','李新','宋','宋诗','song-poetry','','[]','水花浸鬢根，荷葉踐衫色。',231,'全唐诗/poet.song.70000.json','["水花浸鬢根，荷葉踐衫色。", "西城王老子，豪健不可得。", "客從日沒來，鶉衣遍黄埃。", "銀盃未羽化，公餘煩一開。", "山猿供嘉果，書螢驚蠟炬。", "能持白玉簫，爲作蒼鸞語。", "涼飈助清奏，雨脚揮殘暑。", "臺邊舞鳯拍雲來，潭底吟龍撆波去。", "君不見寧王當日争門迎，三十六宮學新聲。", "玉人今夜教何處，二十四橋空月明。", "西城煙景何疏索，王子宦情殊不惡。", "有田日種黄金茅，叵奈蠧蟲搖齒脚。", "少年英氣無覊絡，浩唱高彈神自若。", "春風走馬入花林，紅日垂頭困瑤閣。", "老去腰支便矍鑠，座人那肯妨詼謔。", "飛觴得似少年時，西窗幾度燈花落。"]'),
('279fa132-b77d-4dc2-b7c4-bdecb1392733','陳蜀州','李新','宋','宋诗','song-poetry','','[]','黄鶯哺兒驚不起，蜂子飲花渴瓊蘃。',160,'全唐诗/poet.song.70000.json','["黄鶯哺兒驚不起，蜂子飲花渴瓊蘃。", "日長燕語踏簾鈎，柳絮榆錢撲流水。", "紫霧五雲斜掛壁，夢破長庚海天碧。", "不乏當年感遇詩，定知光焰三千尺。", "細香繞熏白玉爐，長生酒滿黄金壺。", "爐煙直起射河漢，壺酒滴滴如明珠。", "祝公富貴薦公壽，夜煮振靈晨進酒。", "上皇方倚老成人，自問天翁借商叟。", "别島花深燕未闌，瀛洲春老尚餘寒。", "似聞延揖真仙侣，乞取人間不死丹。"]'),
('aa3daf0b-e37f-45f6-b2b6-54b699eed006','懷酒','李新','宋','宋诗','song-poetry','','[]','清聖濁賢莫區分，一入愁腸功等倫。',128,'全唐诗/poet.song.70000.json','["清聖濁賢莫區分，一入愁腸功等倫。", "石爐三日不舉火，麴車過門齒生津。", "松窗草玄亦已勤，好事勿謂秦無人。", "呼兒但滌牛頭爵，正恐壺榼來繽紛。", "凍消講舌流冰凘，寒破笑頰生紅雲。", "愛酒未減子猷竹，豈可一日無此君。", "謫居無田種秫米，忘懷有詩上嚢紙。", "鄰醅不隔一航水，却隔醉鄉三萬里。"]'),
('d6af1122-43c0-43d4-851c-b4dff324b700','王中玉生辰','李新','宋','宋诗','song-poetry','','[]','瑤磩桂楹香霧濃，貴人罷直承明宮。',160,'全唐诗/poet.song.70000.json','["瑤磩桂楹香霧濃，貴人罷直承明宮。", "高樓內集慶生子，酒面油膏紅復紅。", "嵩雲入洛秋容曉，水冷青洲蘭蕙小。", "露蠲仙掌生寒光，翡幄華帳飄晚涼。", "虬電蜿蜿護飈駕，吹笙子晉從天下。", "泬寥緱氏空月明，世間唯識王司稼。", "野人薦公千百壽，大椿骨健龍腰瘦。", "紫芝老艾副椒漿，請公倒盡長生酒。", "天廟明堂遲飛棟，杜宇數驚銅輦夢。", "錦城雖好不如歸，中散年來憶雙鳯。"]'),
('9b885c15-cf5c-4b99-9593-74d9311a7e15','石鼓寺晚歸','李新','宋','宋诗','song-poetry','','[]','野鳥音喧豗，蒼欒翠轇轕。',92,'全唐诗/poet.song.70000.json','["野鳥音喧豗，蒼欒翠轇轕。", "冷光雪色陵雲端，亂流江勢侵天末。", "蒙衲老僧初睡美，倚榻陂龍暗搖尾。", "竹庵虎子呼未回，石竈茶煙寒不起。", "阿昕愛山定忘返，我已興窮歸路晚。", "悲風鳴鴈一聲聲，眸寒更覺江城遠。"]'),
('12be54cc-aa55-48a4-9a21-5f61aa77c1c6','青銼山寺','李新','宋','宋诗','song-poetry','','[]','春去山鳥悲，春歸山鳥樂。',54,'全唐诗/poet.song.70000.json','["春去山鳥悲，春歸山鳥樂。", "高軒一樽酒，臥看山花落。", "厨煙續雲根，澗水斷冰脚。", "山中不可留兮歸去來，日暮芸香裛羅幕。"]'),
('0ad7660e-22a8-4dbf-909d-e8fb118e191d','古塞','李新','宋','宋诗','song-poetry','','[]','曾經古塞間，萬里控長關。',48,'全唐诗/poet.song.70000.json','["曾經古塞間，萬里控長關。", "卧日邊鼙舊，嘶風戰馬閒。", "戍樓喧暮角，羌笛怨空山。", "應賀升平久，車書混八蠻。"]'),
('260bb3df-09ff-4215-8a75-4ac68d0372c8','漢江','李新','宋','宋诗','song-poetry','','[]','低靄横沙碧，長灘宿鴈孤。',48,'全唐诗/poet.song.70000.json','["低靄横沙碧，長灘宿鴈孤。", "樵薪窺樹癭，漁父就龜趺。", "落日駢游女，鳴波咽佩珠。", "啼烏與驚鵲，先我渡城隅。"]'),
('5c4dc87b-2ce2-4c4b-964b-4c6eae9c44da','湖上招故人','李新','宋','宋诗','song-poetry','','[]','柳影依窗過，荷香拂枕浮。',48,'全唐诗/poet.song.70000.json','["柳影依窗過，荷香拂枕浮。", "雲邊山近雨，石下水通秋。", "白藕離新斸，嘉魚落晚鈎。", "還同動情興，已爲掃西樓。"]'),
('7919182f-70c5-44e1-8595-e0f93bdfa7c9','磁釣翁','李新','宋','宋诗','song-poetry','','[]','尺巘方壺小，泓泉渤海深。',48,'全唐诗/poet.song.70000.json','["尺巘方壺小，泓泉渤海深。", "陶公慈母手，抔土故人心。", "蓑笠不愁敝，鰷鱨何處尋。", "虚堂值蕭瑟，猶苦百蟲吟。"]'),
('d4d27a40-9238-4f6d-a031-2c456c71b544','高祖試劍石','李新','宋','宋诗','song-poetry','','[]','巨石中分斷，涓流自此東。',48,'全唐诗/poet.song.70000.json','["巨石中分斷，涓流自此東。", "堯仁方宅土，項氏曷當鋒。", "興起漢高業，勤勞夏禹功。", "故應行道者，千古企遺蹤。"]'),
('08a0841d-2acc-4b6b-a616-ddb85231e7f5','官歸','李新','宋','宋诗','song-poetry','','[]','旅巢幾百指，水國漫三年。',48,'全唐诗/poet.song.70000.json','["旅巢幾百指，水國漫三年。", "極望祇秋草，歸耕惟石田。", "不成便招隱，漸擬欲安禪。", "那得蘇司業，相逢乞酒錢。"]'),
('da8b6408-108d-4294-8d30-5b60508f0b11','不寐','李新','宋','宋诗','song-poetry','','[]','不寐成孤坐，悠悠百感生。',48,'全唐诗/poet.song.70000.json','["不寐成孤坐，悠悠百感生。", "燈明將續晝，鼓急欲移更。", "藥熟知僮倦，杯殘任鼠爭。", "羈懷忘未得，時作下階行。"]'),
('3f129980-0fef-4b3b-af50-ebf0256d2b46','晚宿江漲橋','李新','宋','宋诗','song-poetry','','[]','鳥徑青山外，人家苦竹邊。',48,'全唐诗/poet.song.70000.json','["鳥徑青山外，人家苦竹邊。", "江城懸夜鎖，魚市散空船。", "岸靜涵秋月，林昏宿水煙。", "又尋僧榻卧，夜冷欲無眠。"]'),
('01bc67a8-d773-4a27-b2d3-90d0ffb83543','龍洞','李新','宋','宋诗','song-poetry','','[]','龍睡抱明月，我來窺碧潯。',48,'全唐诗/poet.song.70000.json','["龍睡抱明月，我來窺碧潯。", "攖鱗徒有志，探頷本無心。", "雷去春霖足，雲歸夜水深。", "餘波應不惜，好爲濯塵襟。"]'),
('4a5ee52e-668b-47fd-9fda-55acec32fcc5','分蒲萄遺蘇必强','李新','宋','宋诗','song-poetry','','[]','吏歸珍客賜，手自舉銅盤。',48,'全唐诗/poet.song.70000.json','["吏歸珍客賜，手自舉銅盤。", "珠釀舊瓊液，煙勻秋露漙。", "初分馬乳碧，聊別水晶寒。", "教徹梨園曲，停歌一處餐。"]'),
('b49de441-ae02-4745-abd1-7c8e7e206904','鑑亭','李新','宋','宋诗','song-poetry','','[]','石壁緣雲白，松風特地哀。',48,'全唐诗/poet.song.70000.json','["石壁緣雲白，松風特地哀。", "斷鴻随眼没，秋浪擘山來。", "鼓急船頭轉，山明雨脚開。", "知公歸未得，此作望鄉臺。"]'),
('f182704f-ad68-4b8c-a007-ff41c0865214','次韻員子春遊馬溪二首  其一','李新','宋','宋诗','song-poetry','','[]','有花栽性地，餘法寄燈房。',48,'全唐诗/poet.song.70000.json','["有花栽性地，餘法寄燈房。", "虬蜿駢松瘦，鍾寒殷谷長。", "赤髯班石坐，白驥踏雲驤。", "一夕參玄客，森森出虎場。"]'),
('1ac30c4a-c51d-4908-a56b-0fc473632b3e','次韻員子春遊馬溪二首  其二','李新','宋','宋诗','song-poetry','','[]','樹影陰蒙逕，雲衣淺撲門。',48,'全唐诗/poet.song.70000.json','["樹影陰蒙逕，雲衣淺撲門。", "禪心無冷暖，客意自晨昏。", "澗水鳴璫破，山花野血噴。", "再來何薄暮，騶從觸狐蹲。"]'),
('14bdbf54-9a42-4783-af64-fefd09fbd3d7','春遊','李新','宋','宋诗','song-poetry','','[]','寂寂茂陵春，文園病後情。',48,'全唐诗/poet.song.70000.json','["寂寂茂陵春，文園病後情。", "黄蜂腰欲斷，細柳眼初明。", "麗服駢遊女，餘酣失老兵。", "殘粧深院落，相對任卿卿。"]'),
('a138147d-4920-4435-b3f7-cf489f3e87d5','杜鵑','李新','宋','宋诗','song-poetry','','[]','終日欲歸去，蹉跎空歲華。',48,'全唐诗/poet.song.70000.json','["終日欲歸去，蹉跎空歲華。", "只知催客泪，何處是君家。", "寄子他巢穩，頒春故國賒。", "林梢啼不盡，流恨入山花。"]'),
('2798d1fd-e68c-459d-b219-493107ef22c5','桃花菊','李新','宋','宋诗','song-poetry','','[]','秋雨秋風夜，閑爲桃菊吟。',48,'全唐诗/poet.song.70000.json','["秋雨秋風夜，閑爲桃菊吟。", "任香飄澗水，回翠入籬金。", "苦李自胡越，幽蘭初腹心。", "故山千里外，回首暝煙深。"]'),
('2f9cf22c-6176-4444-9ad3-ad88f251b44b','官居偶書','李新','宋','宋诗','song-poetry','','[]','湖山随顧盼，薄俸亦甘心。',48,'全唐诗/poet.song.70000.json','["湖山随顧盼，薄俸亦甘心。", "窮鬼不教富，詩魔長使吟。", "支頤聞落葉，隱几見棲禽。", "此意竟誰喻，蕭蕭秋夜深。"]'),
('34a52c45-f0e8-4a94-b0d5-3bc438eb6d92','重九','李新','宋','宋诗','song-poetry','','[]','出戶非我識，長安雖萬家。',48,'全唐诗/poet.song.70000.json','["出戶非我識，長安雖萬家。", "有愁焦綠髪，無語插黄華。", "酒僻喜宮醖，衾寒怯絳紗。", "欲傳此情况，行客在天涯。"]'),
('5d859be6-fac8-4c32-8c91-ef5351abae18','中江道中','李新','宋','宋诗','song-poetry','','[]','茅結蕭蕭宅，松周淺淺山。',48,'全唐诗/poet.song.70000.json','["茅結蕭蕭宅，松周淺淺山。", "斧桑雲堕綠，堤水月留彎。", "楊蕋風團去，蟲絲燕掠還。", "行經雙隻堠，曾未徹重關。"]'),
('649d7e39-03c1-4754-8918-df139efeb6f4','醉鄉','李新','宋','宋诗','song-poetry','','[]','客至終投轄，朝回詎典衣。',48,'全唐诗/poet.song.70000.json','["客至終投轄，朝回詎典衣。", "待眠卿且去，亟酌我將歸。", "泉郡新封邑，糟丘小翠微。", "離家今萬里，坐隔羽觴飛。"]'),
('15517cfe-2649-455c-ab84-68be1fa255e5','經甘相廟','李新','宋','宋诗','song-poetry','','[]','相君天所佑，童子知何神。',48,'全唐诗/poet.song.70000.json','["相君天所佑，童子知何神。", "不必茂爲祖，因知秦有人。", "一言成大計，千古仰青春。", "廟下塵勞客，將慚白髪新。"]'),
('abf71beb-ad8c-4d3b-bb0e-6dfcffbd582f','遊石鼓寺','李新','宋','宋诗','song-poetry','','[]','石鼓寂不振，金聲無處求。',48,'全唐诗/poet.song.70000.json','["石鼓寂不振，金聲無處求。", "層巖參霧樹，亂玉響冰溝。", "破屐前無齒，孤城遠見樓。", "山僧癡問客，阿汝謂湯休。"]'),
('387c3974-2f02-4f08-8e63-0f5fd2d02ce0','龍興行香遊寶蓮寺','李新','宋','宋诗','song-poetry','','[]','魚舞天清日，經行小刹初。',48,'全唐诗/poet.song.70000.json','["魚舞天清日，經行小刹初。", "松柯青羽葆，貝葉細蠅書。", "杜畫奇無敵，周妻俗有餘。", "業無支遁輩，難自卜幽居。"]'),
('71faca00-4e5a-45d0-a823-ef405a35529f','張安化重陽日置酒挽同官遊靈泉寺登高時適有客占牧之詩一聯因緝成一首書寺垣','李新','宋','宋诗','song-poetry','','[]','白髪新遷客，黄雲古戰場。',48,'全唐诗/poet.song.70000.json','["白髪新遷客，黄雲古戰場。", "自然堪堕淚，何必更重陽。", "山削孤城起，河兮細水長。", "蜀峰高處望，猶是隔秦鄉。"]'),
('c5a06ff4-3ed8-4481-b34f-fc69a51a2e46','八月十五日過蓬谿書淨戒寺','李新','宋','宋诗','song-poetry','','[]','瓦冷雲埋殿，燈長黑暗沙。',48,'全唐诗/poet.song.70000.json','["瓦冷雲埋殿，燈長黑暗沙。", "藥靈閒草木，蔓走古龍蛇。", "石佛随山老，松梯轉路賒。", "門前溪水淺，無處問仙家。"]'),
('91965f93-11e7-4afe-96e4-80efaaf61b3d','過永安院','李新','宋','宋诗','song-poetry','','[]','山暗雲垂地，谿回樹倒流。',48,'全唐诗/poet.song.70000.json','["山暗雲垂地，谿回樹倒流。", "詩随梅冷落，夢入鳥鈎輈。", "欲住無佳致，重來即舊遊。", "村眉攢八字，已解作春愁。"]'),
('e51fb516-7cc1-4472-aea6-1b352cea8b69','寶巖寺','李新','宋','宋诗','song-poetry','','[]','竹影與溪聲，蕭蕭眼底明。',48,'全唐诗/poet.song.70000.json','["竹影與溪聲，蕭蕭眼底明。", "秋雲浮古樹，山石削長城。", "暝色凝黄碧，啼烏伴晚征。", "高僧不知客，故遣作詩鳴。"]'),
('97106796-003e-4ede-a689-575c4cde37d5','龍遊寺南屏軒和宋宏父韻','李新','宋','宋诗','song-poetry','','[]','平日江干過，南屏首重迴。',48,'全唐诗/poet.song.70000.json','["平日江干過，南屏首重迴。", "不妨圖裏見，曾是夢中來。", "近市樓臺逼，高城鼓角催。", "老年知涉世，臨事却銜枚。"]'),
('aecc1da9-9a61-4ad4-8960-49dcc400b9fc','感俗','李新','宋','宋诗','song-poetry','','[]','回腸驚紺髪，汩脚沁寒眸。',48,'全唐诗/poet.song.70000.json','["回腸驚紺髪，汩脚沁寒眸。", "沃壤連千里，封狐媚一丘。", "生憎守錢虜，冷誚富民侯。", "不厭江西水，長年傍屋流。"]'),
('7a77e7db-d090-40a4-8919-5799b4c04a1b','問俗','李新','宋','宋诗','song-poetry','','[]','窮極天窺涘，幽陰地絕春。',48,'全唐诗/poet.song.70000.json','["窮極天窺涘，幽陰地絕春。", "石壇荒誓鬼，藥媪下羌神。", "鬭雀分疏事，晴山親近人。", "刲羊留髄骨，正欲卜歸辰。"]'),
('f6f6a005-a7be-4af5-a647-770a2653ee2f','羌俗','李新','宋','宋诗','song-poetry','','[]','卜占遵火兆，詛誓謹歸誠。',48,'全唐诗/poet.song.70000.json','["卜占遵火兆，詛誓謹歸誠。", "渡笮蒼猱捷，旋碉墨蟻輕。", "養生茶作命，據嶮石爲城。", "縱去擒來事，無人是孔明。"]'),
('68bca072-7489-49f7-996b-202559c6d31a','山間女','李新','宋','宋诗','song-poetry','','[]','倚竹情何極，傷春事已闌。',48,'全唐诗/poet.song.70000.json','["倚竹情何極，傷春事已闌。", "長眉彎月薄，翠袖怯天寒。", "倩婦攏新鬢，憑人易舊冠。", "輕聞騎馬客，相趁隔籬看。"]'),
('9ffdf459-f75a-480c-83ef-5f67c8ce9893','九支池二首  其一','李新','宋','宋诗','song-poetry','','[]','萬里車書自一家，新城蜿蜿卧龍蛇。',64,'全唐诗/poet.song.70000.json','["萬里車書自一家，新城蜿蜿卧龍蛇。", "路民已别東西日，樓鼓初聞早晚衙。", "洗出雲巖銷虎穴，掃開煙瘴離椒花。", "受廛不惜躬耕去，欲與滕公度歲華。"]'),
('55b08343-af6e-4ab6-8005-bdb45965279a','九支池二首  其二','李新','宋','宋诗','song-poetry','','[]','際天州縣出要荒，始覺承平日月長。',64,'全唐诗/poet.song.70000.json','["際天州縣出要荒，始覺承平日月長。", "一望宛無戎甲馬，四圍皆是漢封疆。", "清笳沓沓翻新曲，寒月低低下乳墻。", "說與遠人知德意，九重深處是成康。"]'),
('9ea3d6f3-d2d9-468a-a203-908d4c36f131','題小瀛洲','李新','宋','宋诗','song-poetry','','[]','紫霞香霧隔氛塵，擬囑安期謝海神。',64,'全唐诗/poet.song.70000.json','["紫霞香霧隔氛塵，擬囑安期謝海神。", "聞道仙居随處有，故教湖景到來新。", "菓成行拾千年子，花落休悲二月春。", "咫尺徐生身不到，自應船載世間人。"]'),
('e25d30c2-d1fa-4523-a232-f41eefb26a11','題永康縣山光閣','李新','宋','宋诗','song-poetry','','[]','吹鬢東風可但寒，倦飛孤鶴已知還。',64,'全唐诗/poet.song.70000.json','["吹鬢東風可但寒，倦飛孤鶴已知還。", "花光弄暖翻承雪，雲翼回陰却見山。", "野水曲行林下綠，春禽喚出夣中閒。", "欲營老宅南頭住，待駐人間耐久顔。"]'),
('3d9364d8-14d4-4aed-9a21-1ff85a4689aa','題絕勝亭','李新','宋','宋诗','song-poetry','','[]','孤鴻落照下滄洲，人在雲間選勝幽。',64,'全唐诗/poet.song.70000.json','["孤鴻落照下滄洲，人在雲間選勝幽。", "好夣知君依魏闕，此生惟我識荆州。", "卜居支遁應同志，載酒山公已絕憂。", "他日澄江浄如練，主人端在塞垣秋。"]'),
('801f94cd-99fd-44aa-93c3-966cc54c5a64','題朱令德祠','李新','宋','宋诗','song-poetry','','[]','全家領項付吳鈎，香骨當年誰共收。',64,'全唐诗/poet.song.70000.json','["全家領項付吳鈎，香骨當年誰共收。", "鼎鑊九泉留景進，旌幢千騎憶同州。", "唐人鐵券驚何語，蜀國壺漿笑舊遊。", "古柏參天僧社冷，暮煙風雨使人愁。"]'),
('ba9fa1e2-a6db-4cb6-8e0c-0b348108776f','題石子溪亭','李新','宋','宋诗','song-poetry','','[]','怪事年來一禿翁，懶能揮涕謝途窮。',64,'全唐诗/poet.song.70000.json','["怪事年來一禿翁，懶能揮涕謝途窮。", "歸心豈但杜鵑勸，官味正嫌玄酒濃。", "柘葉展開蠶命老，山花飛盡蝶家空。", "願從春社田塍飲，內史而今要治聾。"]'),
('0dce19b5-0563-42b1-abdb-fb2c7b0e53f2','趙壹讀書臺','李新','宋','宋诗','song-poetry','','[]','臺上看書千載客，故基青草白芊綿。',64,'全唐诗/poet.song.70000.json','["臺上看書千載客，故基青草白芊綿。", "那由府檄平平起，除到柴車特特賢。", "土俗更無堪計吏，古風空解惜囊錢。", "五行俱下何人見，獨有高名伴漢川。"]'),
('579c5441-e5d3-485f-9f36-06310b509f86','觀瀾堂  其一','李新','宋','宋诗','song-poetry','','[]','風觀生涼底事雄，五湖煙浪一堂中。',64,'全唐诗/poet.song.70000.json','["風觀生涼底事雄，五湖煙浪一堂中。", "公方觀水那無術，客欲工詩正坐窮。", "翻出秋潮真是幻，化成蓬嶠本來空。", "筆端造化渾奇特，爲掃茅茨半畝宮。"]'),
('bfe6d416-339a-488c-acb9-1c1001bd8826','觀瀾堂  其二','李新','宋','宋诗','song-poetry','','[]','鈴閣文書得少休，故將湖水慁清眸。',64,'全唐诗/poet.song.70000.json','["鈴閣文書得少休，故將湖水慁清眸。", "似從天姥逡巡坐，擬放仙槎自在流。", "具眼不隨千派轉，此身元並一漚浮。", "羌誰戲墨通三昧，信是人間萬法儔。"]'),
('57d87537-5eca-4580-a910-7e8cebbb868d','題舊新明縣孝義驛','李新','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','平生職事馬蹄塵，三月鶯花世路新。',64,'全唐诗/poet.song.70000.json','["平生職事馬蹄塵，三月鶯花世路新。", "廢邑尚餘當日市，旌門已忘昔年陳。", "長江浪拍西山脚，喬木陰回太古春。", "惟有柳綿情不惡，解將柔遠逐行人。"]'),
('629c7298-8b51-44cb-806e-808eb56b4dfd','令狐秀才書堂','李新','宋','宋诗','song-poetry','','[]','剩擷芸香辟蠧魚，足音差遠自逃虚。',64,'全唐诗/poet.song.70000.json','["剩擷芸香辟蠧魚，足音差遠自逃虚。", "春醅已許暮留客，凍筆不妨寒著書。", "龜甲屏風雲散漫，月窗花影樹扶疏。", "他年子伯無閒暇，但遣兒曹訪隱居。"]'),
('08cc046e-db72-476a-93d3-57558c4d91ca','題嘯竹軒','李新','宋','宋诗','song-poetry','','[]','借與江風入茂林，低低戞玉伴龍吟。',64,'全唐诗/poet.song.70000.json','["借與江風入茂林，低低戞玉伴龍吟。", "琅玕影動分清奏，鸞鳳聲寒得至音。", "妙處成文元有節，虚中出樂自無心。", "子期一聽終區别，流水高山不在吟。"]'),
('510794bd-91b4-4168-9a63-1d012d2c44eb','題南寺吟軒','李新','宋','宋诗','song-poetry','','[]','市聲幽鳥幾相呼，指點前村認有無。',64,'全唐诗/poet.song.70000.json','["市聲幽鳥幾相呼，指點前村認有無。", "初見江山懷子美，更因樓閣夣姑蘇。", "慣看渡口飛桃葉，細結籬根護木奴。", "蹙得錦囊多少句，暮歸傾倒九淵珠。"]'),
('1cdc87f7-abb5-4dc9-928a-d7f1dba2ecf0','題質龜軒','李新','宋','宋诗','song-poetry','','[]','百歲纔容山鬼知，九淵那許季咸窺。',64,'全唐诗/poet.song.70000.json','["百歲纔容山鬼知，九淵那許季咸窺。", "事明告我肯三瀆，謀既協人何兩疑。", "曳尾詎堪從太史，刳腸猶歎漏神蓍。", "試看左顧懷恩處，莫記巢蓮睡足時。"]'),
('3c51dda1-3dc2-4f27-892f-82b19f25debf','相鶴軒','李新','宋','宋诗','song-poetry','','[]','别傳眼法定何如，不用平平許負書。',64,'全唐诗/poet.song.70000.json','["别傳眼法定何如，不用平平許負書。", "貴客逢軒乘有分，道人得玉食無餘。", "鈞天萬舞知新奏，華表千年識故居。", "田屋老翁虧鑒戒，伴鷄同放不知渠。"]'),
('98897d81-7a58-47ce-a2df-837637de9e73','題籌筆驛','李新','宋','宋诗','song-poetry','','[]','流馬飛粮下蜀都，卧龍曾此寫雄圖。',64,'全唐诗/poet.song.70000.json','["流馬飛粮下蜀都，卧龍曾此寫雄圖。", "金刀有義輕三顧，銅爵雖強視一夫。", "鼎足山河終有漢，鴈行兄弟亦忠吳。", "當年若盡毫端計，魏狗還羞不令無。"]'),
('31ce265a-47ce-40c0-9b4c-9744df62740b','悅老堂','李新','宋','宋诗','song-poetry','','[]','厚蔭林烟翠一圍，幽幽門館暗生輝。',64,'全唐诗/poet.song.70000.json','["厚蔭林烟翠一圍，幽幽門館暗生輝。", "行雲轉影月先到，流水飄香鶯自歸。", "碧玉已抽雲夢幹，芙蕖猶舞漢宮衣。", "風歷北窗琴自動，成文無處問知音。"]'),
('8575174e-d3f4-4914-b142-4d6891f09372','同宋長江登江店唐氏山閣','李新','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','白頭記室朱顔令，山閣忙來去却遲。',64,'全唐诗/poet.song.70000.json','["白頭記室朱顔令，山閣忙來去却遲。", "礙盡江天松不管，吹平沙篆鴈應知。", "思傾竹葉疑無分，要賦梅花恰是時。", "王粲從軍歸信近，貯囊試看幾多詩。"]'),
('5b9ce1c4-70c5-451b-8aa2-7a35abfa8939','蓬萊别島','李新','宋','宋诗','song-poetry','','[]','已駕神鼇遠翠埃，外人休詠北山萊。',64,'全唐诗/poet.song.70000.json','["已駕神鼇遠翠埃，外人休詠北山萊。", "自無失脚劉郎到，怕有吹笙子晉來。", "雲散曉風飄鶴氅，月明春浪浸瑤臺。", "似聞方士窮真色，歸笑長紅越女腮。"]'),
('564e28c4-2bee-4ce7-b495-c607aac34626','清泉館','李新','宋','宋诗','song-poetry','','[]','曉踏高坡日始懸，清泉未見口生煙。',64,'全唐诗/poet.song.70000.json','["曉踏高坡日始懸，清泉未見口生煙。", "飛鳬欲到二千里，挾筴徒勞三十年。", "綉带長川初背眼，雲根雙劍遠磨天。", "驌驦齒健嘶風去，更敢披頭重著鞭。"]'),
('fa34d702-c04b-4bfc-bcf1-db8785dc5273','黑水館','李新','宋','宋诗','song-poetry','','[]','孤宦輪蹄消歲月，誰緣清賞慰蹉跎。',64,'全唐诗/poet.song.70000.json','["孤宦輪蹄消歲月，誰緣清賞慰蹉跎。", "曾行軒戶昔無處，見在江山今得多。", "雪色雲容通劍閣，鏡光池溜屬天河。", "本來一段真奇絕，不肯關情奈俗何。"]'),
('c3bf7448-da91-4744-885f-d198a83f21ed','浮春齋','李新','宋','宋诗','song-poetry','','[]','煙鼎金顔碧線長，是中日日載春陽。',64,'全唐诗/poet.song.70000.json','["煙鼎金顔碧線長，是中日日載春陽。", "翠翰結屋驚鼇背，綠葉翻波夢水鄉。", "静晝鳥啼三月老，路人風送百花香。", "從它流出紅英去，化作人間有韻粧。"]'),
('22628791-91bd-496c-a658-4e4098dc670d','遊羅園','李新','宋','宋诗','song-poetry','','[]','故山新寄小郫筒，春事而今一半空。',64,'全唐诗/poet.song.70000.json','["故山新寄小郫筒，春事而今一半空。", "兒女笑從花影外，盃盤香在水光中。", "泉分石溜渾罌白，病得春醅半頰紅。", "祓禊山陰已陳迹，試将青草葄衰翁。"]'),
('3451075e-0eb7-487b-9e4b-0f2197c9e234','資州鄧園','李新','宋','宋诗','song-poetry','','[]','蒼官愯愯護重崗，綠玉寒梢亞短墻。',64,'全唐诗/poet.song.70000.json','["蒼官愯愯護重崗，綠玉寒梢亞短墻。", "春事鳥啼三月老，路人風送百花香。", "蜂衙歸去欄干静，江面飛來燕予忙。", "簿領堆中催白髪，不知閒日許多長。"]'),
('5635f486-b457-4b01-b60c-6f17b4f7fcb8','巴山','李新','宋','宋诗','song-poetry','','[]','飛雲冉冉隔層巒，漲水茫茫失舊灣。',64,'全唐诗/poet.song.70000.json','["飛雲冉冉隔層巒，漲水茫茫失舊灣。", "自昔秋風悲宋玉，這回夜雨宿巴山。", "獨行雲嶠雙飛舄，誰置壺漿一解顔。", "世事人情隨日改，不妨老子解癡頑。"]'),
('101609ca-2f97-477b-9c51-5eb073d47ba9','中秋夜宿穆陵關','李新','宋','宋诗','song-poetry','','[]','覊旅情懷不自禁，清霜岐路馬駸駸。',64,'全唐诗/poet.song.70000.json','["覊旅情懷不自禁，清霜岐路馬駸駸。", "一年明月最圎夜，千里故人常别心。", "幸有酒沽除是醉，更無人賞又如陰。", "寒蛩似識風騷意，伴我凄凄到曉吟。"]'),
('5c1537f1-cbe8-4f0b-a97c-500ea0b3907f','金牛道中','李新','宋','宋诗','song-poetry','','[]','龍鱗鳳翼阻騰驤，仰首青雲自渺茫。',64,'全唐诗/poet.song.70000.json','["龍鱗鳳翼阻騰驤，仰首青雲自渺茫。", "漢月滿衣諳客思，巴音側耳覺吾鄉。", "金牛有路通秦惠，籌筆無功愧蜀王。", "祗笑無成謾來往，回頭慚愧綠衣郎。"]'),
('5fa75185-1ca6-4e02-8ccc-8f7767bd81f3','晚過銀山','李新','宋','宋诗','song-poetry','','[]','荒溪屈曲中郎篆，白鷺參差玉笋班。',64,'全唐诗/poet.song.70000.json','["荒溪屈曲中郎篆，白鷺參差玉笋班。", "竿日已移三丈外，水雲猶垜兩山間。", "石橋梅蕚餘香冷，茅店人家晚夢閒。", "幸自歸心過飛鳥，不須循指示刀環。"]'),
('dbe36eaf-1578-4dcc-b17d-a01a6d5009d2','江道中','李新','宋','宋诗','song-poetry','','[]','項沒黄茆疑虎蹲，風搖脱木本浮雲。',64,'全唐诗/poet.song.70000.json','["項沒黄茆疑虎蹲，風搖脱木本浮雲。", "忘機沙溆雙鶬遠，小景人家一水分。", "野寺鐘聲昏後寂，寒衣砧子夜深聞。", "山中悅老無亭榭，白酒長新橡栗肥。"]'),
('68189169-4d9e-418e-916f-08ec1736c85d','上亭書事','李新','宋','宋诗','song-poetry','','[]','自笑癡公日據鞍，誰令生不近長安。',64,'全唐诗/poet.song.70000.json','["自笑癡公日據鞍，誰令生不近長安。", "此條太樂非清職，何物先生祗冷官。", "背日潢汙猶鼎沸，隔唇喉舌亦灰乾。", "五漿不饋尋常客，却作行人一等看。"]'),
('bfaa5ca3-33fd-4fae-93cd-b343a8feac19','題明遠軒','李新','宋','宋诗','song-poetry','','[]','聊能半日止游韁，拂拂塵裾未滌黄。',64,'全唐诗/poet.song.70000.json','["聊能半日止游韁，拂拂塵裾未滌黄。", "山揜谿光龍脊斷，谷傳天籟虎風涼。", "亂雲過眼不妨好，細徑入村何限長。", "獨酌苦吟清意在，可憐禽鳥亦相忘。"]'),
('d349fdea-78ee-4fec-afbe-e894bf04313c','題延賓亭','李新','宋','宋诗','song-poetry','','[]','秋葉春風自一村，主人高誼揖公孫。',64,'全唐诗/poet.song.70000.json','["秋葉春風自一村，主人高誼揖公孫。", "未容急去須投轄，却恐重來不置門。", "歌徹曉雲歸曲席，酒醒殘月照空樽。", "何時下客腰懸印，西嚮償君一飯恩。"]'),
('c25722fd-f4a8-4184-832e-032da1361a46','西軒  其一','李新','宋','宋诗','song-poetry','','[]','夢中得鹿本無心，覺後人亡只見金。',64,'全唐诗/poet.song.70000.json','["夢中得鹿本無心，覺後人亡只見金。", "水出吐蕃分黑白，地窮全蜀隔幽陰。", "枯腸正伴空城雀，白首更爲梁甫吟。", "急求賈傅今宣室，誰賦傷讒屈子文。"]'),
('711da99a-47ed-4838-bcf7-ecdf33ba3f0a','西軒  其二','李新','宋','宋诗','song-poetry','','[]','谷滿牛羊路覆莎，翠編終日倦坡流。',64,'全唐诗/poet.song.70000.json','["谷滿牛羊路覆莎，翠編終日倦坡流。", "寺依石角高低見，水遶山根曲折多。", "風入長松零馬尾，人藏病事設禽羅。", "方壺海嶠知何處，縱得飛騰奈老何。"]'),
('71fdc5bc-27bd-481b-9357-fde060d86c7e','興利山居','李新','宋','宋诗','song-poetry','','[]','江左風流恐未真，南州人物竟成塵。',64,'全唐诗/poet.song.70000.json','["江左風流恐未真，南州人物竟成塵。", "全家莫恨癭張醜，四國且圖山作鄰。", "小漏天光渾失熱，綠槐樹盖始知春。", "柴扉晝鑰能高枕，一到華胥勝路人。"]'),
('0572a484-5b23-4bd4-b415-5a65b43d3784','過邠郊歸蜀','李新','宋','宋诗','song-poetry','','[]','摩笄綠玉筍抽芽，卷地兜羅柳放花。',64,'全唐诗/poet.song.70000.json','["摩笄綠玉筍抽芽，卷地兜羅柳放花。", "蛺蝶團空飛錦繡，葡萄上架走龍蛇。", "河源曲曲無千仞，土室層層有幾家。", "脫得身歸銀漢近，雲津卻擬問仙槎。"]'),
('1527deb5-4819-4024-8375-c5efa86dcc97','過長灘','李新','宋','宋诗','song-poetry','','[]','尾劄泥塗賤此身，手提雞肋戀虛名。',64,'全唐诗/poet.song.70000.json','["尾劄泥塗賤此身，手提雞肋戀虛名。", "蘆花伴我頭俱白，山色迎秋意轉清。", "沙軟馬留金褭印，雁歸灘列水犀兵。", "尚能趁得黄花酒，聽取東籬笑語聲。"]'),
('d358a325-8408-41bf-9921-1bc3090654ad','往銀山深道亡寺觀暮投宿民居','李新','宋','宋诗','song-poetry','','[]','入谷清光寒刮眼，遠分蒼樹遶樓臺。',64,'全唐诗/poet.song.70000.json','["入谷清光寒刮眼，遠分蒼樹遶樓臺。", "急鏘環珮谿流迅，晚下牛羊雪迹開。", "山影不隨雲影轉，竹聲長作雨聲來。", "野梅弄色何人愛，空抱幽香沒草萊。"]'),
('117dceeb-008b-40ac-ae52-b44f3f3d47e3','安溪','李新','宋','宋诗','song-poetry','','[]','岸草綿綿一葉舟，野煙開盡水光浮。',64,'全唐诗/poet.song.70000.json','["岸草綿綿一葉舟，野煙開盡水光浮。", "寺連野竹微茫見，溪出寒山自在流。", "愁裏詩情隨浩渺，鳥邊春夢入鈎輈。", "泉嘶石鼎新茶熟，且爲山僧更少留。"]'),
('1ae7c050-b677-4f68-853f-c8b2429d77e8','登城望江邊','李新','宋','宋诗','song-poetry','','[]','山外浮雲雲外城，江邊羌角水中聲。',64,'全唐诗/poet.song.70000.json','["山外浮雲雲外城，江邊羌角水中聲。", "九分雪髪功名晚，一寸冰衘去就輕。", "山與繡屏天刻畫，獸編土宇地欹傾。", "早扶藜杖關頭去，要向中州看太平。"]'),
('a43197fc-452c-4084-b983-764119b90bd3','暮春泛舟涪江','李新','宋','宋诗','song-poetry','','[]','已把荷衣換釣裘，不妨官柳繫漁舟。',64,'全唐诗/poet.song.70000.json','["已把荷衣換釣裘，不妨官柳繫漁舟。", "提壺勸酒雖無意，杜宇言歸却自由。", "十里江風吹晝夢，一川梅雨敵春愁。", "忘機鷗鷺休飛去，且爲閒人更少留。"]'),
('752caa8d-c280-4687-8a14-3dd403219dd6','出茂州','李新','宋','宋诗','song-poetry','','[]','日落城空鳥少知，戰場依舊昔人非。',64,'全唐诗/poet.song.70000.json','["日落城空鳥少知，戰場依舊昔人非。", "雪花籠石商皓首，楓葉滿山秦赭衣。", "月入空罍人自恥，塵蒙西榻客元稀。", "窮荒石紐那生禹，料得當時殛鯀歸。"]'),
('2d16b2d3-6140-4274-9581-75704517aaba','又出差還茂州','李新','宋','宋诗','song-poetry','','[]','深入不毛何所負，不妨老子解癡頑。',64,'全唐诗/poet.song.70000.json','["深入不毛何所負，不妨老子解癡頑。", "九峰自積十年雪，八國猶遺六詔蠻。", "楸带綠垂蚯蚓直，苔衣翠滴鷓鴣斑。", "山前人事如麻麥，却憶孤城日日閒。"]'),
('6c3515fa-6cee-44a1-97b4-32daee45a414','從辟瀘南道中曉征三首  其一','李新','宋','宋诗','song-poetry','','[]','人情世事今如此，與作叢林眼目看。',64,'全唐诗/poet.song.70000.json','["人情世事今如此，與作叢林眼目看。", "髀肉未能銷犢鼻，溪篁先與斸漁竿。", "山銜落月金盤缺，馬踏清霜玉珮寒。", "一十九年閒睡足，欲將春夢入長安。"]'),
('24581824-c34a-47b6-91ff-c5fb2470b620','從辟瀘南道中曉征三首  其二','李新','宋','宋诗','song-poetry','','[]','矍鑠從戎恃骨彊，舊衣襃愽詎堪裝。',64,'全唐诗/poet.song.70000.json','["矍鑠從戎恃骨彊，舊衣襃愽詎堪裝。", "歲云暮矣家安在，月出皎兮山更長。", "錐子秃毛窮有分，碑顔沒字老何妨。", "憑君爲護痴兒女，白首相期樂未央。"]'),
('5ec67df3-6019-4a85-b86c-ccea0eb95623','從辟瀘南道中曉征三首  其三','李新','宋','宋诗','song-poetry','','[]','貂裘紫帽日程程，不得修途一紙平。',64,'全唐诗/poet.song.70000.json','["貂裘紫帽日程程，不得修途一紙平。", "作雪曉天梅蕚重，壓塵小雨馬蹄輕。", "隨身詩酒三勍敵，入眼山川幾畫屏。", "到日未須投我轄，爲燒蘭水濯繁纓。"]'),
('19751cff-e04c-4723-be3b-ae6c568dc6b0','金匱道中','李新','宋','宋诗','song-poetry','','[]','白雲包裹石城賒，幾度親歸夢裏家。',64,'全唐诗/poet.song.70000.json','["白雲包裹石城賒，幾度親歸夢裏家。", "春入小桃渾綺繡，風回殘雪半塵沙。", "唐賢碎瀉真珠粒，鄭老微明白杏花。", "莫道窮邊無好語，二公流落亦天涯。"]'),
('595bbc46-2749-419c-9b05-996feda021ee','銅鼓道中所見詩','李新','宋','宋诗','song-poetry','','[]','麥秋塲圃面顔光，蠶月絲車繭水黄。',64,'全唐诗/poet.song.70000.json','["麥秋塲圃面顔光，蠶月絲車繭水黄。", "豆飯餉田薅鼓住，田塍收水婦翁忙。", "明沙粲粲流泉慢，綠竹猗猗苦笋香。", "赩日不黔形自黑，剩收斗粉傅何郎。"]'),
('276fae0b-47e4-4191-be85-3585efbc2ed1','尹公湖晚歸','李新','宋','宋诗','song-poetry','','[]','箇中適意即吾廬，可是秋來杖屨疏。',64,'全唐诗/poet.song.70000.json','["箇中適意即吾廬，可是秋來杖屨疏。", "碧樹野煙連廣莫，暮池斜照落函虚。", "天高鴈迥字明滅，林杳笛寒聲有無。", "喜見眉間知底事，近鄉頻領北堂書。"]'),
('50be5fd6-897d-4b32-ae68-3d3b381156a9','崇寧寺晚歸','李新','宋','宋诗','song-poetry','','[]','遠意難隨燕燕歸，故園春冷杏花稀。',64,'全唐诗/poet.song.70000.json','["遠意難隨燕燕歸，故園春冷杏花稀。", "虚名自古雙蝸角，别業從來一釣磯。", "已後無人能立雪，他年知子可傳衣。", "結廬薄有西山地，更遣何人賦式微。"]'),
('4e6e7ec1-8a5a-4280-ba67-6b0e5493889b','落解西歸長安道中書所懷','李新','宋','宋诗','song-poetry','','[]','年少將軍師羽林，追奔翻爲白頭吟。',64,'全唐诗/poet.song.70000.json','["年少將軍師羽林，追奔翻爲白頭吟。", "不平豪憤三年氣，未死英雄萬里心。", "故國山川知好在，異鄉風物許重尋。", "捷書不報渾閒事，西出潼關無好音。"]'),
('6402cfe4-b082-4c8b-b506-348b585ed639','再書','李新','宋','宋诗','song-poetry','','[]','北風過河霜霧深，凍入毛骨殊侵尋。',64,'全唐诗/poet.song.70000.json','["北風過河霜霧深，凍入毛骨殊侵尋。", "行人已苦長安道，俗眼徒慚季子金。", "風月秦樓愁處别，鶯花蜀國病中吟。", "莫嗤今日西歸計，直爲重安親老心。"]'),
('43bbe2a6-c6d6-4a3a-a0b0-82fb88244ca0','還三嵎先寄舍弟','李新','宋','宋诗','song-poetry','','[]','客宦乘流同木偶，入村隨俗自猴冠。',64,'全唐诗/poet.song.70000.json','["客宦乘流同木偶，入村隨俗自猴冠。", "鴒飛原上正相應，豆泣釜中當少寛。", "貂闕長憂狗尾續，客來應借鳯毛看。", "隴西衣鉢傳無盡，熟看羣兒現宰官。"]'),
('8e1fa91f-a8ab-4e73-ab13-eccd36810367','寄舍弟二首  其一','李新','宋','宋诗','song-poetry','','[]','周三千界貧無敵，垂四十年癡有名。',64,'全唐诗/poet.song.70000.json','["周三千界貧無敵，垂四十年癡有名。", "不怕貴人譏巧宦，但教窮鬼笑難兄。", "異鄉置酒能招客，曉夢還家莫計程。", "起寫新詩歸寄汝，尚餘山月過窗明。"]'),
('181aa1c6-dcfa-4bc5-bb3c-852ecb8d3078','寄舍弟二首  其二','李新','宋','宋诗','song-poetry','','[]','冷漿庭巷四時秋，巧拙時情不解謀。',64,'全唐诗/poet.song.70000.json','["冷漿庭巷四時秋，巧拙時情不解謀。", "遠客病容詩共瘦，故鄉野水泪通流。", "稍辜破鏡刀頭約，盡失蒼蠅驥尾遊。", "他日江湖看生計，鴨頭春浪一扁舟。"]'),
('c5788985-87b7-4dcf-bce9-71af6e06c2e9','貽家弟','李新','宋','宋诗','song-poetry','','[]','但知四壁有連珠，底事虚名更拙圖。',64,'全唐诗/poet.song.70000.json','["但知四壁有連珠，底事虚名更拙圖。", "一斗病予猶百首，十年笑爾拙三都。", "霜風入頰休驚冷，瓦埦無油願急呼。", "世上舌根皆識味，滿傾終是愛醍醐。"]'),
('8c9c331b-1b9d-432b-8f99-83b67c67eede','徐安叟郊居','李新','宋','宋诗','song-poetry','','[]','旋補疏籬短短遮，郊居初似厭紛華。',64,'全唐诗/poet.song.70000.json','["旋補疏籬短短遮，郊居初似厭紛華。", "鄰燈林腹幾螢小，市路山腰一線斜。", "衰草綴珠看曉露，暮天飛墨數歸鴉。", "憐君近歲頭渾白，兩泪臨風數祭拏。"]'),
('6ff5c4fb-fe0a-4be6-a2bc-ce213571cf0e','飲田家洞','李新','宋','宋诗','song-poetry','','[]','日脚歸雲到坐隅，凍禽唧㗚樹扶疏。',64,'全唐诗/poet.song.70000.json','["日脚歸雲到坐隅，凍禽唧㗚樹扶疏。", "望窮野麥綠不斷，春入山梅香有餘。", "恐是滕公千載室，定無汲冢五車書。", "人間可乏賢公子，長鋏歌成食有魚。"]'),
('b728153d-b616-4d50-972c-12f8ee78fafd','山中秋意','李新','宋','宋诗','song-poetry','','[]','擬握陂龍陟鳯臺，厭聞遠鴈一聲哀。',64,'全唐诗/poet.song.70000.json','["擬握陂龍陟鳯臺，厭聞遠鴈一聲哀。", "霜乾殷葉背林去，雨足黄雲歸谷來。", "蕙幛可能留鶴宿，草堂終待覓榿栽。", "有心培養山中桂，不束輪囷作散材。"]'),
('5e04451d-763c-4e4e-a8f8-4666610a27d3','劉子常約賞海棠','李新','宋','宋诗','song-poetry','','[]','共愁明月照空杯，莫逐時人溺死灰。',64,'全唐诗/poet.song.70000.json','["共愁明月照空杯，莫逐時人溺死灰。", "百日酒隨山客盡，一年春逐海棠回。", "門無轍迹草自長，燕不世情貧肯來。", "豆飯芋羮容易繼，明朝花落不重開。"]'),
('021ee538-9c05-4057-a959-fa82f634fb03','問田尉公俞丐菊栽','李新','宋','宋诗','song-poetry','','[]','冷官廳外病陰陰，猶向西風擁鼻吟。',64,'全唐诗/poet.song.70000.json','["冷官廳外病陰陰，猶向西風擁鼻吟。", "梅福儘藏雲外宅，陶潛難老菊邊心。", "許因秋社前頭雨，分與東籬匝後金。", "待到重陽不開放，却收樽酒去相尋。"]'),
('48e2bd6c-cf26-4209-ac5b-fb1b67b09905','早梅','李新','宋','宋诗','song-poetry','','[]','冥寞元崖宅有神，冷香寒色漏天真。',64,'全唐诗/poet.song.70000.json','["冥寞元崖宅有神，冷香寒色漏天真。", "感深暖日常爲力，傑出飛霜恐後春。", "千里故人何以寄，一枝幽意望誰親。", "孤標若值芳華菀，羞與妖紅碧樹鄰。"]'),
('7c854807-d054-49de-a806-5773ebd587ea','笋竹','李新','宋','宋诗','song-poetry','','[]','崢嶸澤國與煙村，飽見尖尖破土痕。',64,'全唐诗/poet.song.70000.json','["崢嶸澤國與煙村，飽見尖尖破土痕。", "稍倩南風開鵲尾，數煩夜雨送龍孫。", "平生直節初揮籜，後日清陰自庇根。", "殘月莫雲林外看，森森矛戟萬軍屯。"]'),
('0adfd894-d84c-4311-b4dd-a2d035d5d38d','催李祖申賞蓮會','李新','宋','宋诗','song-poetry','','[]','亭亭綠蓋密回塘，縹緲青娥麗素粧。',64,'全唐诗/poet.song.70000.json','["亭亭綠蓋密回塘，縹緲青娥麗素粧。", "雪覆千年巢曳尾，風翻一曲舞霓裳。", "小槽酒滴隨慳雨，北海樽空類亢陽。", "何事却妨彭澤醉，幾時聊發次公狂。"]'),
('d01377e1-6fae-44b9-a900-6337d0017c17','讀五代史','李新','宋','宋诗','song-poetry','','[]','瓜割溝分幾戰場，坎蛙穴蟻自侯王。',64,'全唐诗/poet.song.70000.json','["瓜割溝分幾戰場，坎蛙穴蟻自侯王。", "鐡槍妄謂千人敵，溺器猶須七寶粧。", "諸國豈能臣癩子，九龍那得貯歸郎。", "堪悲五十年來事，荼毒蒸民倍感傷。"]'),
('5c50abbc-096a-4d23-9e03-54b852da345a','觀梁輔之曉閱','李新','宋','宋诗','song-poetry','','[]','羽林出戍死忘家，坐作行趨聽虎牙。',64,'全唐诗/poet.song.70000.json','["羽林出戍死忘家，坐作行趨聽虎牙。", "碧月初生弓入抱，青蛇不動劍藏花。", "風吹細柳旗陰轉，日過寒谿陣脚斜。", "回笑書生頭白早，空將筆硯戰年華。"]'),
('78429374-0db6-4302-9041-e3a7078d93e4','凌雲','李新','宋','宋诗','song-poetry','','[]','江匯潨流搖地軸，路窮九頂切彤霄。',64,'全唐诗/poet.song.70000.json','["江匯潨流搖地軸，路窮九頂切彤霄。", "半犁好雨田香潤，一簸殘花春寂寥。", "土馬未騣愁敗草，仙人得杖厭靈苖。", "與公莫論從前事，楚些遊魂却可招。"]'),
('823e9597-17bb-4902-98d9-4bdc2f5b06b0','隔墻吹簫悲深有作','李新','宋','宋诗','song-poetry','','[]','攖心人事細如蓑，渾有童心奈老何。',64,'全唐诗/poet.song.70000.json','["攖心人事細如蓑，渾有童心奈老何。", "濕雪盡隨哀泪堕，清簫不與哭聲和。", "歸休最病良田少，侵老終憐季子多。", "無命無才猶有友，但憐雄辯正懸河。"]'),
('d7e9fb1b-b03b-45b7-a245-8867804a9a0b','問張興州覓酒','李新','宋','宋诗','song-poetry','','[]','䟃𧽼雲陣暮天低，家在雲天西畔西。',64,'全唐诗/poet.song.70000.json','["䟃𧽼雲陣暮天低，家在雲天西畔西。", "雪片未容欺白髪，貂裘不管污黄泥。", "梅寒花晚休吹笛，水瘦江空莫照犀。", "便有綈袍憐過客，不如春釀亟封題。"]'),
('454ee749-0865-45a5-9c8b-51afc73da6ce','時雨試步寄員子春','李新','宋','宋诗','song-poetry','','[]','與竹他年僅有衣，敢愁天賦鮮岐嶷。',64,'全唐诗/poet.song.70000.json','["與竹他年僅有衣，敢愁天賦鮮岐嶷。", "拏乂不拜渾閑事，踉蹡初行更效誰。", "莫道漢家飛將種，那知天上石麟兒。", "若令新歲能翻舌，先寄城東老員詩。"]'),
('4f22eab4-86d5-4750-8f74-46e82191b17f','詠晴','李新','宋','宋诗','song-poetry','','[]','髯老新詩錦自裁，雨綃烟帳玉屏開。',64,'全唐诗/poet.song.70000.json','["髯老新詩錦自裁，雨綃烟帳玉屏開。", "風摩團碧陰雲破，簷倒斜紅晚景來。", "蟻陣爭雄人未覺，蚊雷强聒夜相陪。", "請君日醉兵厨酒，千古英流安在哉。"]'),
('7d85d5f3-0c50-40c5-88e8-d1554897bbb8','夜坐有感并簡與訥教授','李新','宋','宋诗','song-poetry','','[]','青燈微火照寒更，不信儒冠誤此生。',64,'全唐诗/poet.song.70000.json','["青燈微火照寒更，不信儒冠誤此生。", "翻覺廣文官未冷，始聞工部辟初行。", "三年宦況秋蕭瑟，一枕時情夢戰爭。", "思過故園尋故老，旋持春酒看春耕。"]'),
('e42ac6fc-c655-485c-9b5e-b88414853739','感事','李新','宋','宋诗','song-poetry','','[]','銀濤千里引長吟，玉軫他年有古音。',64,'全唐诗/poet.song.70000.json','["銀濤千里引長吟，玉軫他年有古音。", "雲起不知山有助，鳥啼爭奈竹無心。", "畫蛇可笑須安足，攖市堪悲只見金。", "莫與浮雲較休戚，北窗棋酒夜方深。"]'),
('0c658db0-a2ff-413e-b7b8-794ceabe9295','正月晦書事','李新','宋','宋诗','song-poetry','','[]','業無家釀致鄰翁，得有薪溫引頰紅。',64,'全唐诗/poet.song.70000.json','["業無家釀致鄰翁，得有薪溫引頰紅。", "准擬片言能悟主，復求一飽定傷弓。", "詩書奴婢晨占鵩，鹽米妻兒夜送窮。", "早晚郊原莫零涕，動搖葵麥有春風。"]'),
('3be07b7a-f358-46c4-bf44-c1cab404edcd','次韻子溫檢覆書事','李新','宋','宋诗','song-poetry','','[]','博山灰冷一星寒，散亂文書少讀殘。',64,'全唐诗/poet.song.70000.json','["博山灰冷一星寒，散亂文書少讀殘。", "夕飲清冰消熱易，夢爲胡蝶過家難。", "潘郎桃樹參差見，沈老腰圍隱約寛。", "雅量故應容嬾拙，功名同向鏡中看。"]'),
('51d3c028-c6ac-4812-a181-dcc975118089','上張幕','李新','宋','宋诗','song-poetry','','[]','草色恩袍九品中，文章高步屈英雄。',64,'全唐诗/poet.song.70000.json','["草色恩袍九品中，文章高步屈英雄。", "紅蓮綠水開新幕，絳帳青衿走下風。", "沛雨蒼龍功已奮，翔雲丹鳯路潛通。", "塵迷試問劉安訣，就學仙源點化工。"]'),
('ecdbd4f9-9a1e-43c9-b904-33fa889a0e95','送胡運使  其一','李新','宋','宋诗','song-poetry','','[]','吳江冰散水溶溶，乍見山花襭眼紅。',64,'全唐诗/poet.song.70000.json','["吳江冰散水溶溶，乍見山花襭眼紅。", "六日春容歸漢苑，千年桃樹倚天風。", "預留黄閣朱衣吏，令侍商丘白髪翁。", "元圃長生新釀熟，一盃相屬月明中。"]'),
('17843e96-0508-4a06-86d1-cd9bfbada845','送胡運使  其二','李新','宋','宋诗','song-poetry','','[]','請將龜壽卜椒觴，遲日花塼幾刻長。',64,'全唐诗/poet.song.70000.json','["請將龜壽卜椒觴，遲日花塼幾刻長。", "千里煖風春夢好，半鈎新月繡衣光。", "帝前動笏搖山嶽，劍外行車映雪霜。", "湖上柳青歸未得，里人爭掃德星堂。"]'),
('eabc9711-be6b-41cb-8cf4-0738b0a597e7','送胡運使  其三','李新','宋','宋诗','song-poetry','','[]','當年姓字列仙曹，醉逐西王折海桃。',64,'全唐诗/poet.song.70000.json','["當年姓字列仙曹，醉逐西王折海桃。", "萬策水平祥霧合，峨眉嵐靜使星高。", "泥封明日傳清詔，台量何人薦佩刀。", "老去功成解金印，卧雲閒笑一生勞。"]'),
('75515f68-7544-4745-9b26-e98b991442ad','劉小漕  其一','李新','宋','宋诗','song-poetry','','[]','亂紅纈眼柳花飛，煙抹沱溪秀一圍。',64,'全唐诗/poet.song.70000.json','["亂紅纈眼柳花飛，煙抹沱溪秀一圍。", "北背美人占夢去，夕陽行客舞雩歸。", "三吳父老傳冰節，兩蜀江山識繡衣。", "預草封章千百紙，此身明日接天威。"]'),
('60ea15e1-b04f-4d55-a551-b64d98a2d954','劉小漕  其二','李新','宋','宋诗','song-poetry','','[]','小槽軋玉逗瓊漿，滿酌金花薦壽觴。',64,'全唐诗/poet.song.70000.json','["小槽軋玉逗瓊漿，滿酌金花薦壽觴。", "已有駿駒傳驥足，莫辭持節下羊腸。", "護詩何處無靈物，報國新來有皂囊。", "要覓甘棠尋舊愛，莫雲千里蔽柔桑。"]'),
('041b6844-d6a1-4c8e-ad47-cd3bdf81a125','劉小漕  其三','李新','宋','宋诗','song-poetry','','[]','五雲入夢翠浮空，正在高陽巴里中。',64,'全唐诗/poet.song.70000.json','["五雲入夢翠浮空，正在高陽巴里中。", "八葉蓂含天露綠，千年桃映海波紅。", "流錢遠裔爭推晏，青史何人獨比雄。", "白面門生指椿檜，願肩華髪倚春風。"]'),
('2093ea16-d65a-46b8-9ff1-a7846b793790','江提倉生日二首  其一','李新','宋','宋诗','song-poetry','','[]','青鎖沈煙暝著沙，芙渠雲帳曉吞霞。',64,'全唐诗/poet.song.70000.json','["青鎖沈煙暝著沙，芙渠雲帳曉吞霞。", "南金人物無雙士，宮錦文章自一家。", "賞過十分銀漢月，採歸千歲海桃花。", "蜀仙行勸長生酒，燕寝凝香碧霧斜。"]'),
('c453c024-e4cc-4404-8c30-140b8e7ce81c','江提倉生日二首  其二','李新','宋','宋诗','song-poetry','','[]','自應騎鶴下浮丘，雅意人間事俊遊。',64,'全唐诗/poet.song.70000.json','["自應騎鶴下浮丘，雅意人間事俊遊。", "長久方壺新歲月，飄颻江左舊風流。", "巖椿骨老三千尺，佳氣春回十五州。", "溫詔趨歸行有日，此封端是富民侯。"]'),
('edfc4280-dc24-476d-a206-a04b88159898','贈翟提刑  其一','李新','宋','宋诗','song-poetry','','[]','雲麥供羞薦紫閽，里閭初識子威孫。',64,'全唐诗/poet.song.70000.json','["雲麥供羞薦紫閽，里閭初識子威孫。", "千年海骨蟠桃實，六日天眉畫桂痕。", "飽見雪霜威劍閣，行看松柏老夷門。", "石麟下作人間客，故有光芒掃夕昏。"]'),
('981544fa-3374-4a6c-bc3d-2a1588914e5c','贈翟提刑  其二','李新','宋','宋诗','song-poetry','','[]','虬龍金璧走天閽，下有高陵幾代孫。',64,'全唐诗/poet.song.70000.json','["虬龍金璧走天閽，下有高陵幾代孫。", "賦擲玉聲那問價，筆生春意自無痕。", "尚書補去由高第，廷尉除歸不署門。", "元圃長生新釀熟，一庭椿露滴黄昏。"]'),
('acd89a69-b315-49c7-a232-34d85b63d94c','呈恩主戶部郎中  其一','李新','宋','宋诗','song-poetry','','[]','玉翰飛出漢江東，蜀道三年興已窮。',64,'全唐诗/poet.song.70000.json','["玉翰飛出漢江東，蜀道三年興已窮。", "城郭宛然人未老，笑談終日座生風。", "汴雲歸去觚稜近，珠佩收來漢月空。", "衰草寒苕更惆悵，亂鴉無數失征鴻。"]'),
('83913c36-970b-42c7-a852-d04024db1b84','呈恩主戶部郎中  其二','李新','宋','宋诗','song-poetry','','[]','何必庭臯木葉黄，秋風無處不凄涼。',64,'全唐诗/poet.song.70000.json','["何必庭臯木葉黄，秋風無處不凄涼。", "莫言短髪遊郎署，且伴閒雲入故鄉。", "漢殿早瞻新日月，劍屏猶帯舊冰霜。", "一飛碧落三千里，還向瑤池浴鳯凰。"]'),
('246ac7dd-d676-4501-a644-59fde586e6bb','呈恩主戶部郎中  其三','李新','宋','宋诗','song-poetry','','[]','翠軺行色倦秋陰，且聽新來澤畔吟。',64,'全唐诗/poet.song.70000.json','["翠軺行色倦秋陰，且聽新來澤畔吟。", "雲起已知山有助，鳥啼爭奈竹無心。", "斗光指客求佳氣，桐尾收煙得好音。", "他日欲通千里信，西風吹鴈亦浮沉。"]'),
('12ad2ff2-23c8-4244-bd83-7c25be760e81','壽王提舉二首  其一','李新','宋','宋诗','song-poetry','','[]','新歲祥分葆羽車，老君抱送浹雲霞。',64,'全唐诗/poet.song.70000.json','["新歲祥分葆羽車，老君抱送浹雲霞。", "夏正更籥稱觴近，蜀道占星故國賒。", "尚憶前時司玉牒，試簪明日剪金花。", "這回飛燕知恩舊，肯到尋常百姓家。"]'),
('2437689b-fea1-48ba-ad5f-6c158ede86d1','壽王提舉二首  其二','李新','宋','宋诗','song-poetry','','[]','本來卿伯籍神霄，時與羣仙立舜朝。',64,'全唐诗/poet.song.70000.json','["本來卿伯籍神霄，時與羣仙立舜朝。", "邂逅吹笙雲鶴並，等閒飛舄海天遙。", "在公載燕方稱壽，厥日惟人只隔宵。", "黄閣年年春酒熟，商山皓首却煩招。"]'),
('1692a979-306a-4ad2-a814-b01cc2978a67','留别寄元裕','李新','宋','宋诗','song-poetry','','[]','耳熟英聲相見晚，解顔一笑盡天真。',64,'全唐诗/poet.song.70000.json','["耳熟英聲相見晚，解顔一笑盡天真。", "有魚待客不妨醉，無玉藏花初厭貧。", "疏竹已留清夜月，好風先斷過江塵。", "幽居莫薙庭前草，枕葄他時有故人。"]'),
('c72e48d2-893e-4bd8-bceb-a46967f39822','過何權道幽居不遇','李新','宋','宋诗','song-poetry','','[]','水部風流小隱居，别來眼法定何如。',64,'全唐诗/poet.song.70000.json','["水部風流小隱居，别來眼法定何如。", "霧中不見空峒子，世外空傳珞琭書。", "今歲紫荆簪未得，後溪黄鮓食無餘。", "素冠如遇文園宅，爲我慇懃借子虚。"]'),
('939eec86-84be-4689-9929-3ce7e378b7ce','過卧龍先生幽居','李新','宋','宋诗','song-poetry','','[]','手調鼎劑作清涼，不秘千金肘後方。',64,'全唐诗/poet.song.70000.json','["手調鼎劑作清涼，不秘千金肘後方。", "閒數嶺雲松自翠，卧聽梅雨藥初香。", "三山夢斷黄粱熟，一逕莓封白日長。", "我欲從公結幽隱，不干泉石解膏盲。"]'),
('294b94aa-ca0c-428b-9ee9-cdfefa84448c','鹽井','李新','宋','宋诗','song-poetry','','[]','鑿到金輪水際通，綆長牛領血垂紅。',64,'全唐诗/poet.song.70000.json','["鑿到金輪水際通，綆長牛領血垂紅。", "作梅後日看調鼎，擬雪前人欲散空。", "波素儘熬青瀚海，虎形不待盬南風。", "輸官已足金籯滿，坐咲騎驢困五窮。"]'),
('ef781fb2-d0e0-4b05-b4e0-92f8019d1bbe','次韻張永錫待制留題通泉聚古堂','李新','宋','宋诗','song-poetry','','[]','及時瓜李任浮沉，畏景遊雲苦太侵。',64,'全唐诗/poet.song.70000.json','["及時瓜李任浮沉，畏景遊雲苦太侵。", "環縣江流元渺渺，參天喬木自森森。", "七言妙語騰光焰，八法新題冠古今。", "聞道宵征最清處，風翻旌旆月流襟。"]'),
('c22d53f2-b99b-45fa-91a6-4bb8318944fd','送劉金部三首  其一','李新','宋','宋诗','song-poetry','','[]','綺鸞衘詔碧霜林，按部歸來聽好音。',64,'全唐诗/poet.song.70000.json','["綺鸞衘詔碧霜林，按部歸來聽好音。", "卧看蜀雲山曆曆，行遊蘭省夜沉沉。", "柔桑平帯三川綠，蒼桂同鋪百里陰。", "天子虚懷求妙道，肯令公負一生心。"]'),
('ed1f810e-6955-4af9-b06d-b5465dd2747f','送劉金部三首  其二','李新','宋','宋诗','song-poetry','','[]','煙老谿花幾堕紅，高陽閭巷接吳宮。',64,'全唐诗/poet.song.70000.json','["煙老谿花幾堕紅，高陽閭巷接吳宮。", "禁墻鐘斷翻新雨，劍嶺雲寒想去鴻。", "汴水波聲天地遠，上林春色古今同。", "行觀勳筞知多少，河水安流敵帳空。"]'),
('f09ac7ec-b8fb-4946-86fb-2baaf40cf275','送劉金部三首  其三','李新','宋','宋诗','song-poetry','','[]','七里亭中酒滿樽，野梅疏淡月黄昏。',64,'全唐诗/poet.song.70000.json','["七里亭中酒滿樽，野梅疏淡月黄昏。", "可憐白屋西南士，占得青春雨露恩。", "千載誓言飛將種，一生歸報豢龍孫。", "年來佩劍人相笑，寧立孤風晝掩門。"]'),
('04e5ec84-a442-4152-a1e4-11a39c108868','送元景參辟廱','李新','宋','宋诗','song-poetry','','[]','老年鶴瘠玉蒼蒼，送汝難收淚兩行。',64,'全唐诗/poet.song.70000.json','["老年鶴瘠玉蒼蒼，送汝難收淚兩行。", "短褐尚存慈母線，義居初割紫蜂房。", "塤箎元自音聲協，鴻鴈而今羽翼長。", "别業未嘗收菽粟，一家溫飽待文章。"]'),
('751cb05e-9c84-4030-8891-ed8ee9a6f4c3','送張君實赴制舉','李新','宋','宋诗','song-poetry','','[]','不用名矜自半千，高才十二許爭先。',64,'全唐诗/poet.song.70000.json','["不用名矜自半千，高才十二許爭先。", "乘軺遠道三千里，下筆談王數百篇。", "忠胆自能傾白日，決科時似選青錢。", "山城送别無他祝，早屬登瀛第一仙。"]'),
('9026be0d-60e3-48aa-8bc3-e9a58807964c','送知府王大夫  其一','李新','宋','宋诗','song-poetry','','[]','一笑行抛漢水湄，野梅殘雪照旌旗。',64,'全唐诗/poet.song.70000.json','["一笑行抛漢水湄，野梅殘雪照旌旗。", "啼鶯未與春先去，歸騎猶呼雨自隨。", "干禄且優垂老姊，窮經自有起家兒。", "後人覓得松巖石，先刻寒生送别詩。"]'),
('8057b59c-7af9-4f8e-b16f-c1500ae05fd5','送知府王大夫  其二','李新','宋','宋诗','song-poetry','','[]','平生和氣滿襟春，往事飛鳬自在身。',64,'全唐诗/poet.song.70000.json','["平生和氣滿襟春，往事飛鳬自在身。", "風伯已驅天上霧，鳯書仍起漢濱人。", "一鞭草色吟青嶂，幾刻花陰夢紫宸。", "從此唐衢哀世泪，爲公無復更霑巾。"]'),
('5af729b6-5778-4dc2-8483-21442f37af39','送權守解印趨闕','李新','宋','宋诗','song-poetry','','[]','欲挽行人入醉鄉，殘春岐路日偏長。',64,'全唐诗/poet.song.70000.json','["欲挽行人入醉鄉，殘春岐路日偏長。", "花容貼雨蜂兒靜，麥浪翻風燕子涼。", "心計已高劉晏幕，恩波終戴召公棠。", "去思正伴東溪水，聽得潺湲更斷腸。"]'),
('d5557ad6-6a60-4e35-a986-d835ab5cb7f3','喜王子溫教子','李新','宋','宋诗','song-poetry','','[]','諸郎春鬢綠鬖鬖，閬苑幽人爲指南。',64,'全唐诗/poet.song.70000.json','["諸郎春鬢綠鬖鬖，閬苑幽人爲指南。", "大率已經平子目，未應更與阿戎談。", "夜螢撲案光分燭，秋水挼青色染藍。", "的見松窗珠樹客，碧潯龍頷問誰探。"]'),
('6bb0e4b2-402c-46b5-a536-24c93f8983d3','喜孫伯遠王周彦遠訪','李新','宋','宋诗','song-poetry','','[]','晚聞佳客過煙城，抛檄歸來掃榻塵。',64,'全唐诗/poet.song.70000.json','["晚聞佳客過煙城，抛檄歸來掃榻塵。", "連騎莫憂原叔病，食鮭誰謂庾郎貧。", "定因殘雪尋穿履，聊覓江梅遺故人。", "重與論文在何日，自應乘興一相親。"]'),
('da0ff455-e49d-4534-bb97-cb1031da1b76','次韻蘇必强見寄','李新','宋','宋诗','song-poetry','','[]','不知暗室鬼揶揄，曾入魚鳬伴蠧書。',64,'全唐诗/poet.song.70000.json','["不知暗室鬼揶揄，曾入魚鳬伴蠧書。", "分背鴈音清漢遠，動簾風竹故人疏。", "小桃煙老三年樹，白馬原空百兩車。", "消去泪流冰筯若，待憑濁酒一樽餘。"]'),
('ee94fe4e-2e59-4dd9-85ea-1fb9de4df9a0','再和','李新','宋','宋诗','song-poetry','','[]','憶訪東坡舊隱居，飄飄兒姪幾家書。',64,'全唐诗/poet.song.70000.json','["憶訪東坡舊隱居，飄飄兒姪幾家書。", "閉門草牘人誰識，抱膝吟詩客自疏。", "枳棘那棲雲表翼，壺漿爭勞雪中車。", "窮愁定笑江干尉，瘦骨空長六尺餘。"]'),
('d22af991-8f88-44e8-b48e-f3945852e655','燕走馬少卿口號','李新','宋','宋诗','song-poetry','','[]','冠蓋相逢好駐鞍，况知北陸已迎寒。',64,'全唐诗/poet.song.70000.json','["冠蓋相逢好駐鞍，况知北陸已迎寒。", "詔歸未覺堯天遠，星應休辭蜀道難。", "欵聽話言敦夙契，更催歌舞奉清歡。", "慇懃莫惜通宵醉，歸約松梢月影殘。"]'),
('f10f551c-ab91-42aa-abb2-75d1f4480d82','和李少卿見貽之什','李新','宋','宋诗','song-poetry','','[]','碧江青嶂冷翻光，水鏡冰壺照座涼。',64,'全唐诗/poet.song.70000.json','["碧江青嶂冷翻光，水鏡冰壺照座涼。", "舜日有時琴自動，鱸魚何處鱠飛香。", "竹開細尾攙先出，雀引新雛底事忙。", "老去得爲裴度客，舊來頻過鄭公鄉。"]'),
('98478bdd-ded1-43f6-9bc5-cd74452f1c8a','和任普州冬至日作','李新','宋','宋诗','song-poetry','','[]','詩成椽筆一何工，元有英聲妙洛中。',64,'全唐诗/poet.song.70000.json','["詩成椽筆一何工，元有英聲妙洛中。", "已是少師扶日手，更看公子釣鼇風。", "書雲寶筴開新瑞，脱木香山堕晚紅。", "經濟通才猶補外，與騎星鶴問圓穹。"]'),
('72464304-0a1b-4035-8ccc-24e7824a9202','答李丞用其韻  其一','李新','宋','宋诗','song-poetry','','[]','四時秋色可春回，古錦囊空信短才。',64,'全唐诗/poet.song.70000.json','["四時秋色可春回，古錦囊空信短才。", "紙尾依隨丞不負，天西窮絕客何來。", "頑雲垂翼山碉暗，喬麥饒花雪嶺開。", "投老播流情味惡，孤城移作望鄉臺。"]'),
('3fcb2bce-8e22-45c9-8d2f-ec39c8a6a19e','答李丞用其韻  其二','李新','宋','宋诗','song-poetry','','[]','年少文聲許過秦，仕塗便失自由身。',64,'全唐诗/poet.song.70000.json','["年少文聲許過秦，仕塗便失自由身。", "初思鱸鱠翻歸興，不見仙槎却問津。", "道德千言遙胄事，文章萬丈當家春。", "魚從丙穴如收得，更與張華細辨鱗。"]'),
('0e5266b6-a16a-4978-a405-b4c301939b15','謝楊秀才惠文編','李新','宋','宋诗','song-poetry','','[]','漆園夢過感天涯，坐客元非借齒牙。',64,'全唐诗/poet.song.70000.json','["漆園夢過感天涯，坐客元非借齒牙。", "小杜阿房終是好，沈郎雌霓不容差。", "豈羞東郭先生履，行謝關西孔子家。", "五斗折腰聞道晚，未窮摛藻勝春花。"]'),
('84d60c31-0d6c-40fe-8230-f79231d7a836','寄鄭明舉香','李新','宋','宋诗','song-poetry','','[]','手匀沉實伴蘭蓀，著壁青煙未有痕。',64,'全唐诗/poet.song.70000.json','["手匀沉實伴蘭蓀，著壁青煙未有痕。", "掩鼻新來憎甲俗，拂衣無處避膏昏。", "不成亂臭須持棗，却恐偷生誤返魂。", "寄語山間鄭夫子，年來懸麝厭當門。"]'),
('ee4e6108-0c7d-4601-a895-345b13cef728','代張元老上許漕  其一','李新','宋','宋诗','song-poetry','','[]','人在坤維久覆醯，故教使節出天西。',64,'全唐诗/poet.song.70000.json','["人在坤維久覆醯，故教使節出天西。", "後來武庫成清職，平日家風歸品題。", "欲見流錢凴馬策，稍聞刮膜待金篦。", "鴒原曾冠仙鼇頂，應覺人間太華低。"]'),
('2e529a08-3d7f-4c45-b302-6c8d9fc68544','代張元老上許漕  其二','李新','宋','宋诗','song-poetry','','[]','文章摛錦已堆胸，直指威聲俯仰中。',64,'全唐诗/poet.song.70000.json','["文章摛錦已堆胸，直指威聲俯仰中。", "蜀部星高千幛靜，平輿龍起一淵空。", "閱人妙學函明鏡，飛鏑清心本素風。", "垂手污塗收醬瓿，爲憐識字老揚雄。"]'),
('b5320bbe-5842-4a4c-8622-5e7948318e92','青石阻雨','李新','宋','宋诗','song-poetry','','[]','茅屋陰多麥化蛾，西山雲重雨流禾。',64,'全唐诗/poet.song.70000.json','["茅屋陰多麥化蛾，西山雲重雨流禾。", "未聞回也改其樂，解道虞兮奈若何。", "身與前村孤堠遠，泪隨流水一溪多。", "文章生世元無力，半歲邊城伴枕戈。"]'),
('a5c30d4c-7b1d-4bec-94e2-ee4cb093e9b5','隱居','李新','宋','宋诗','song-poetry','','[]','伯鸞翠構元臨市，靖節幽居最近朝。',64,'全唐诗/poet.song.70000.json','["伯鸞翠構元臨市，靖節幽居最近朝。", "事過自餘安水石，客忙何至走漁樵。", "價高少室仍休問，徑捷終南更易招。", "嶺上有雲如可寄，肯將台鼎換簞瓢。"]'),
('6e7ce0be-a13b-4638-bf0b-881ccc6c401f','龍水板橋院','李新','宋','宋诗','song-poetry','','[]','送臘溫濃萬井同，筠輿猶走萬山中。',64,'全唐诗/poet.song.70000.json','["送臘溫濃萬井同，筠輿猶走萬山中。", "曝成枯菜依簷白，染出春衣映壁紅。", "掩豆豚肩仍歲儉，傳觴釀甕幾家空。", "不知新歲招陶否，待向江干送五窮。"]'),
('564a631b-60c8-4e8e-b17b-e614ad432594','普通院','李新','宋','宋诗','song-poetry','','[]','而今漫叟正聱牙，無復新詩賴碧紗。',64,'全唐诗/poet.song.70000.json','["而今漫叟正聱牙，無復新詩賴碧紗。", "行馭乘風方少快，歸期破鏡儘從差。", "月頭漸黑山雲𠥕，雨脚更斜江路义。", "寒士規模新宰相，這回行處亦堤沙。"]'),
('2ebad720-8ac1-41ee-8da2-5a0150babaf3','東津淨行院','李新','宋','宋诗','song-poetry','','[]','老於春事無交涉，退作淘金榻底沙。',64,'全唐诗/poet.song.70000.json','["老於春事無交涉，退作淘金榻底沙。", "蠺到兩眠方健葉，柳成三倒却飛花。", "小桃漲浪堤痕潤，綠麥翻風燕羽斜。", "不得毫釐稽古力，起人松竹問誰家。"]'),
('ee249953-66d0-451b-a2fa-f0a8d7a425f3','留題華嚴壁','李新','宋','宋诗','song-poetry','','[]','直向忙中得少休，一生緣分屬清幽。',64,'全唐诗/poet.song.70000.json','["直向忙中得少休，一生緣分屬清幽。", "好山不許尋常見，野水從教自在流。", "種竹養茶雙碧重，有僧無客四時秋。", "當初著眼如低下，不識光芒射斗牛。"]'),
('dbcf2f39-0875-4701-a11e-2933b45f532f','書梁山楊氏亭壁','李新','宋','宋诗','song-poetry','','[]','騎馬黄塵本不知，作新軒榭發幽奇。',64,'全唐诗/poet.song.70000.json','["騎馬黄塵本不知，作新軒榭發幽奇。", "纈雲山色屏千曲，繡地花光春四時。", "滌器詎須能賦客，力書自有起家兒。", "心肝嘔出無空處，一宿相酬不廢詩。"]'),
('630db1d8-5ac3-49ac-9d86-f9541bd3b382','遊寂照院','李新','宋','宋诗','song-poetry','','[]','萬箇當時几席深，想搖寒碧邃陰陰。',64,'全唐诗/poet.song.70000.json','["萬箇當時几席深，想搖寒碧邃陰陰。", "青山甚富猶藏石，焦尾曾收更愛琴。", "籬脚稻花香遶夢，雲梢桂樹色分金。", "他年寂子如更變，佛法從來不離心。"]'),
('7fea6fda-875b-4528-ba6c-755d36af1b64','寂照院','李新','宋','宋诗','song-poetry','','[]','道人築室不草草，燕壘蜂房斷有才。',64,'全唐诗/poet.song.70000.json','["道人築室不草草，燕壘蜂房斷有才。", "細細轉泉縈屋去，疏疏栽竹放山來。", "琴無殺意客何憚，士怕移文車自回。", "清夜不眠留遲月，譟天耘鼓急如雷。"]'),
('48af6ea4-894f-4d62-a9f2-c35dce44d324','遊雍熙寺','李新','宋','宋诗','song-poetry','','[]','隨身刀筆快投空，黄鵠憑君放出籠。',64,'全唐诗/poet.song.70000.json','["隨身刀筆快投空，黄鵠憑君放出籠。", "野馬已飛樽俎外，白雲端在笑譚中。", "太平老將辜三略，遲鈍參軍得五窮。", "近日半聾并半啞，莫將佛法問龐公。"]'),
('b6019c7f-4ddb-48b2-89c4-92d2ee6b5837','遊化城寺','李新','宋','宋诗','song-poetry','','[]','山色從來不世情，水光分與萬家清。',64,'全唐诗/poet.song.70000.json','["山色從來不世情，水光分與萬家清。", "連雲種竹官租薄，入谷收茶野屫輕。", "小雨結緣留俗客，好風吹夢過江城。", "這回勸飲休辭醉，後日西山第幾程。"]'),
('58821ac9-2d7d-48c2-8093-11091e746d0a','遊雲門山寺','李新','宋','宋诗','song-poetry','','[]','宰官得度却無能，直斷曹溪一點燈。',64,'全唐诗/poet.song.70000.json','["宰官得度却無能，直斷曹溪一點燈。", "脫體化爲牛馬走，隻身歸是水雲僧。", "晚煙破竈迷村落，桴鼓譁空走稻塍。", "弄水看山元未足，半規初月上觚稜。"]'),
('a5883da9-f352-4774-bbb1-7097d7f4eb4f','再遊雲門山寺','李新','宋','宋诗','song-poetry','','[]','筠馬梯空正肉飛，山幽鳴鳥自聲微。',64,'全唐诗/poet.song.70000.json','["筠馬梯空正肉飛，山幽鳴鳥自聲微。", "地趨玉嶂新朝眼，巖織天花欲墜衣。", "雲木綢繆青羽葆，竇泉零落小珠璣。", "重來且與看華表，秪恐無人識令威。"]'),
('e2d50f0e-a33d-4597-bd51-fc58d1b90cc2','暮還官寺','李新','宋','宋诗','song-poetry','','[]','新雨初平萬頃波，移家歸去舊煙蘿。',64,'全唐诗/poet.song.70000.json','["新雨初平萬頃波，移家歸去舊煙蘿。", "三年鄰里定相笑，八斗才名豈是多。", "地近聊爲分袂别，酒醺閒作扣舷歌。", "晚投方丈雖岑寂，客喜談玄自見過。"]'),
('3e379b5b-aef9-465a-bb92-06802e9d80c5','宿青城板橋寺','李新','宋','宋诗','song-poetry','','[]','村落蕭蕭煙雨收，鶉衣寒竪挽歸牛。',64,'全唐诗/poet.song.70000.json','["村落蕭蕭煙雨收，鶉衣寒竪挽歸牛。", "平生脚力未到處，當路貴人安肯遊。", "蹶失馬蹄無限恐，荒涼僧墅不勝愁。", "北窗季弟還知否，一夜秋聲已白頭。"]'),
('c01206db-3916-4755-a9e6-7b7552c69184','春日自錦封歸寧過寶巖寺','李新','宋','宋诗','song-poetry','','[]','曲檻横橋盡落梅，春風草木自承恩。',64,'全唐诗/poet.song.70000.json','["曲檻横橋盡落梅，春風草木自承恩。", "一身初逐斷鴻去，百里猶餘殘燒痕。", "回首錦谿花柳市，那如山寺水雲村。", "鳴騶喜色知多少，白髪雙親笑倚門。"]'),
('eec3c231-8fd4-4a91-847a-7fe1ccffceea','過江遊靈泉寺','李新','宋','宋诗','song-poetry','','[]','徐卿才力已無雙，幾日飛書約渡江。',64,'全唐诗/poet.song.70000.json','["徐卿才力已無雙，幾日飛書約渡江。", "岸石有紋欺錦繡，野蘆無數認旌幢。", "酒投渤澥難招偶，詩築長城欲受降。", "玉麈清談更通昔，定容寒月半侵窗。"]'),
('b1fd089f-c536-4731-b93d-24103c0ea4b7','遊法濟寺  其一','李新','宋','宋诗','song-poetry','','[]','俯檻微歌猛虎行，暮樓鐘鐡又錚錚。',64,'全唐诗/poet.song.70000.json','["俯檻微歌猛虎行，暮樓鐘鐡又錚錚。", "好將石劍磨三伏，自有巴猿報五更。", "種竹養茶家計薄，依山臨水國風清。", "張王左道曹劉戰，秖此祇園不識兵。"]'),
('0c2fe147-8ede-4c42-b83b-4b33ba73619b','遊法濟寺  其二','李新','宋','宋诗','song-poetry','','[]','暮鐘曉磬雜啼鴉，尤覺幽棲與市賒。',64,'全唐诗/poet.song.70000.json','["暮鐘曉磬雜啼鴉，尤覺幽棲與市賒。", "風力吹回千嶂雨，柳陰遮斷一谿花。", "蒼皮樹癭何妨醜，横水橋虹不厭斜。", "夜半春雷亂車軋，不須鳴鼓助驚茶。"]'),
('9f04c14b-13ca-4891-b9d6-8485a07706cb','大佛寺留題','李新','宋','宋诗','song-poetry','','[]','綠篠寒松小翠微，魚聲寂寂鼓聲稀。',64,'全唐诗/poet.song.70000.json','["綠篠寒松小翠微，魚聲寂寂鼓聲稀。", "山頭遠見龜屏出，海嶠誰遷石笋歸。", "欲得鬼神添嶺檜，却愁風雨斷天衣。", "醵錢欲作翬飛觀，一鉢無妨厭蕨薇。"]'),
('ae98aa5b-240f-4eea-ba6a-9bfadabcd5c1','感貧女','李新','宋','宋诗','song-poetry','','[]','天然素質勝鉛華，一握青絲過老鴉。',64,'全唐诗/poet.song.70000.json','["天然素質勝鉛華，一握青絲過老鴉。", "信手畫眉成柳葉，移盆貯水當菱花。", "長憂夜雪侵肌骨，不識春風到齒牙。", "媒妁近來趨勢利，終年元未適良家。"]'),
('45ca14b5-cab3-4506-b89a-e4a392911047','送姚深之','李新','宋','宋诗','song-poetry','','[]','急向空花認此身，莫因宦學苦傷貧。',64,'全唐诗/poet.song.70000.json','["急向空花認此身，莫因宦學苦傷貧。", "遲遲海菓未成子，忽忽荷衣看作塵。", "玉有細疵那覺病，谷無雌虎自生春。", "還家少鼓男兒氣，麈尾驅牛笑煞人。"]'),
('c678876a-0587-403b-9633-b2e314fd7cee','鐡山祠成二首  其一','李新','宋','宋诗','song-poetry','','[]','千嶺分崗一嶺西，一峰驤首萬峰低。',64,'全唐诗/poet.song.70000.json','["千嶺分崗一嶺西，一峰驤首萬峰低。", "仰看木杪樓臺小，猶聽雲端甲馬嘶。", "暮角回風吹落葉，曉暾籠樹轉寒霓。", "要知血食無窮處，陰壑藏雷水遶谿。"]'),
('04f8a464-42c1-4c40-a95a-8e1b0bd5db86','鐡山祠成二首  其二','李新','宋','宋诗','song-poetry','','[]','縹緲團空翠一圍，叢神社鼓日相依。',64,'全唐诗/poet.song.70000.json','["縹緲團空翠一圍，叢神社鼓日相依。", "陰天幾處看雲陣，夜雪何時化鐡衣。", "鳥鼠莫棲新蘂殿，風塵從染舊龍旗。", "門前汗馬蹄翻玉，猶似當年力戰歸。"]'),
('ee4d0a6b-3c31-45b3-bef9-6bc14d82d6fb','賦鄧士載祠','李新','宋','宋诗','song-poetry','','[]','高鳥無餘弓自除，由來名盛不堪居。',64,'全唐诗/poet.song.70000.json','["高鳥無餘弓自除，由來名盛不堪居。", "易揮道左降王縛，難弭朝端謗篋書。", "更欲平吳功未就，可憐出蜀智何疏。", "鳯臺山月知寃魄，夜夜停光照故墟。"]'),
('0c3036c5-cd94-4f48-bd93-35f94861b891','磁釣翁  其一','李新','宋','宋诗','song-poetry','','[]','磁釣翁寧傍釣磯，且當兀坐小盆池。',64,'全唐诗/poet.song.70000.json','["磁釣翁寧傍釣磯，且當兀坐小盆池。", "模形陶氏不須怪，入手蒼鯨未可知。", "風雨不渝端此志，江湖歸去定何時。", "閒惟秋水磻谿客，船入蘆花笛卧吹。"]'),
('5ef85be1-12f3-436d-820e-f174b97a5c6b','磁釣翁  其二','李新','宋','宋诗','song-poetry','','[]','無心不自任公子，手引龍魚敵萬鈞。',64,'全唐诗/poet.song.70000.json','["無心不自任公子，手引龍魚敵萬鈞。", "瓦解弟兄驚墜甑，塊居煙雨勝流人。", "非關釣譽雖攘臂，未欲垂言却卷綸。", "更與甄陶一坏土，鈴齋相伴豈無因。"]'),
('679be70e-d5df-433b-a897-91c464985537','曉起','李新','宋','宋诗','song-poetry','','[]','曉禽聒起坐薪床，梳裹斑絲短短蒼。',64,'全唐诗/poet.song.70000.json','["曉禽聒起坐薪床，梳裹斑絲短短蒼。", "甕面撥來蛆子白，花心飛出蝶鬚黄。", "遊蜂聲沓晨衙退，細篆香縈碧線長。", "已約鄰家來小飲，是中容得次公狂。"]'),
('75a6b4c9-7dcc-4ae1-b1b3-e71ffa807132','過馮十夜飲見燭花有作','李新','宋','宋诗','song-poetry','','[]','世事不知渾井底，巴音猶在已天涯。',64,'全唐诗/poet.song.70000.json','["世事不知渾井底，巴音猶在已天涯。", "攻愁有酒盃吹浪，報喜非春燭自花。", "賈誼長才空賦鵩，東陵餘地欲栽瓜。", "詔書許逐陽和至，寧乞西山度歲華。"]'),
('fe74f56e-8dc1-414f-b4d4-192af0d9b530','下鹿頭坂偶成','李新','宋','宋诗','song-poetry','','[]','朝來喜下鹿頭關，誰謂追奔匹馬還。',64,'全唐诗/poet.song.70000.json','["朝來喜下鹿頭關，誰謂追奔匹馬還。", "意氣已無豪憤態，夢魂猶在嶮崎間。", "白雲親老愁歸計，明月知音笑病顔。", "天子已籌西夏策，將軍未易許安閒。"]'),
('1af6a67d-a828-4156-bf71-83dc54f79892','九日林守同飲因思昔年朱侍講跨鶴之集','李新','宋','宋诗','song-poetry','','[]','常記秋登跨鶴臺，儒先杖履共追陪。',64,'全唐诗/poet.song.70000.json','["常記秋登跨鶴臺，儒先杖履共追陪。", "如公已到蓬萊上，過我又分符竹來。", "往事已成千古話，遺風空負十分盃。", "依依正爾重陽日，襟抱何時得好開。"]'),
('56bd468e-eaac-4cd3-8cfd-051577e2dbfe','次韻任使君詠梅二首  其一','李新','宋','宋诗','song-poetry','','[]','堂上高人解賞音，孤根未放草來侵。',64,'全唐诗/poet.song.70000.json','["堂上高人解賞音，孤根未放草來侵。", "不妨此後頒春力，却得從前愛日心。", "模臘曾看黄淡淡，試粧猶恐暈深深。", "而今驛使行如織，聽取新來塞上吟。"]'),
('10f667b7-6fb1-4780-9dfc-008e1e042393','次韻任使君詠梅二首  其二','李新','宋','宋诗','song-poetry','','[]','平時化力與扶持，莫道春工未肯私。',64,'全唐诗/poet.song.70000.json','["平時化力與扶持，莫道春工未肯私。", "暗有浮香通淡月，瘦無寒葉到空枝。", "腹中太白何多錦，句下韋郎自不知。", "陰谷未開公見否，葭灰暖律更煩吹。"]'),
('7fadd05d-a19f-49d1-88a6-f8d99353f5c0','次韻解君接感懷  其一','李新','宋','宋诗','song-poetry','','[]','能向風塵識馬周，新豐飲盡得相留。',64,'全唐诗/poet.song.70000.json','["能向風塵識馬周，新豐飲盡得相留。", "後車慣載胡王縛，衰草頻驚戰馬秋。", "靈武須公來闢土，桃林他日待歸牛。", "承平衛霍知虛老，剩著新篇繼日休。"]'),
('051c1e2c-6f38-4316-8edb-ef12c39187b2','次韻解君接感懷  其二','李新','宋','宋诗','song-poetry','','[]','太平事業按商周，麟閣儀形待子留。',64,'全唐诗/poet.song.70000.json','["太平事業按商周，麟閣儀形待子留。", "壯士長歌三箭定，鴟夷歸老五湖秋。", "生涯底事空藏劍，英氣平時已食牛。", "歌扇舞衫今太寂，暮雲佳句敵湯休。"]'),
('892a1e93-28a7-4ae7-9a49-d218203e170d','天池讀書寄元明','李新','宋','宋诗','song-poetry','','[]','絺葛皮冠蕭隱居，溪山隨我亦名愚。',64,'全唐诗/poet.song.70000.json','["絺葛皮冠蕭隱居，溪山隨我亦名愚。", "調和得所弟乳酪，麗澤不均兄瓠壺。", "曉雨莫償雙淚落，夜燈常照一心孤。", "阿松活計今多少，試問山前幾木奴。"]'),
('669cb95f-a9a7-4abf-962b-98386e1c4ab5','甲子春趨太學過華山賦仙掌峰','李新','宋','宋诗','song-poetry','','[]','一掌巍然占碧巔，分明高舉欲擎天。',64,'全唐诗/poet.song.70000.json','["一掌巍然占碧巔，分明高舉欲擎天。", "升沉盡待招攜力，指點都歸造化權。", "好與清霄扶日月，莫留寒嶂弄雲烟。", "不知千古興亡事，屈指而今是幾年。"]'),
('049f3391-0679-4340-a29f-a75b20bf93b0','北窗偶成呈遺逸','李新','宋','宋诗','song-poetry','','[]','北窗冰硏碎魚鱗，未伏徐翁筆有神。',64,'全唐诗/poet.song.70000.json','["北窗冰硏碎魚鱗，未伏徐翁筆有神。", "止酒詩成三逕曉，買山錢就一家春。", "饑鼯如市莫欺客，窮鬼作朋終笑人。", "未敢移文謝逋客，且看除道過蒲輪。"]'),
('9b044718-44d0-40d5-bbc8-b37c572ba3ed','觀前古美人圖','李新','宋','宋诗','song-poetry','','[]','璧月塵昏瓊樹秋，無從百媚一回眸。',64,'全唐诗/poet.song.70000.json','["璧月塵昏瓊樹秋，無從百媚一回眸。", "荼䕷香度梅粧冷，鸚鵡聲低玉笛幽。", "唾背但能知禍水，逢春且莫上迷樓。", "歸來安守無鹽女，不寵無驚共白頭。"]'),
('cde18f62-e628-4359-ac69-bafcfbe8af45','所見','李新','宋','宋诗','song-poetry','','[]','鬢絲蕭散忙蠶月，笑靨勻停喜麥秋。',64,'全唐诗/poet.song.70000.json','["鬢絲蕭散忙蠶月，笑靨勻停喜麥秋。", "落照已斜猶曝繭，故人未渡莫横舟。", "屋欹雲影長年見，枕壓谿聲半夜流。", "料得此生無好夢，却勝終日有閒愁。"]'),
('e3bb5a1d-61e4-43f4-9ae4-a7655e067555','蓬溪道中所見  其一','李新','宋','宋诗','song-poetry','','[]','筠輿百曲篆谿灣，潤麥催花小雨慳。',64,'全唐诗/poet.song.70000.json','["筠輿百曲篆谿灣，潤麥催花小雨慳。", "鶗鴃弄聲知境静，鞦韆垂影見春閒。", "一生瘦骨幾隨鶴，萬事無心却愛山。", "爲濯小槽收重碧，掃除東閣待翁還。"]'),
('42bbaa91-e1df-411c-bcab-da8158648a78','蓬溪道中所見  其二','李新','宋','宋诗','song-poetry','','[]','詩情冷落接坰荒，鳥語鈎輈伴日長。',64,'全唐诗/poet.song.70000.json','["詩情冷落接坰荒，鳥語鈎輈伴日長。", "山館花煩蜂蜜重，溪橋雨潤燕泥香。", "鄂君被暖春回帳，犬子琴閒月到床。", "醉裏要歸何處是，無功猶解記吾鄉。"]'),
('5a97831f-5ef1-45dc-88dc-a7080a3d56fd','西崗重九','李新','宋','宋诗','song-poetry','','[]','天涯一角見重陽，蕭洒西風客斷膓。',64,'全唐诗/poet.song.70000.json','["天涯一角見重陽，蕭洒西風客斷膓。", "麻紵未更今日白，菊花還似去年黄。", "陶潛把酒重開解，宋玉臨墻乍感傷。", "借問龍山歌會者，座中誰認綠衣郎。"]'),
('a4e12441-61fc-4e3c-a40f-e3a63c45ef83','送馮夢授試禮部  其一','李新','宋','宋诗','song-poetry','','[]','殷樹葱籠繡曉暾，馬蹄東去亂冰痕。',64,'全唐诗/poet.song.70000.json','["殷樹葱籠繡曉暾，馬蹄東去亂冰痕。", "世收徵詔藏商谷，家有新功刻禹門。", "太白夜郎初辱顧，馮唐漢殿欲承恩。", "南山報喜通啼鳥，明日榮歸鶴有孫。"]'),
('4bbdda85-933b-4934-81a3-bcb0efe16442','送馮夢授試禮部  其二','李新','宋','宋诗','song-poetry','','[]','年來初識小馮君，鞭靮何妨馭晏嬰。',64,'全唐诗/poet.song.70000.json','["年來初識小馮君，鞭靮何妨馭晏嬰。", "三世卿雲涪水秀，一門巢許蜀山清。", "飄零殊幸逢公子，邂逅相看不世情。", "入手華標歸早晚，願扶藜杖出山迎。"]'),
('83eb3dea-0733-4a74-8d38-d8d4ffda5866','送錢使者三首  其一','李新','宋','宋诗','song-poetry','','[]','不須回首漢臯亭，白髪愁催却易生。',64,'全唐诗/poet.song.70000.json','["不須回首漢臯亭，白髪愁催却易生。", "好夢先依鸞仗去，此身聊伴劍雲行。", "隨輈芳草真無賴，送客黄鶹似有情。", "故國要知何處是，望湖樓下錦衣城。"]'),
('189adcaf-b04d-4b55-9e7e-e0a06974a309','送錢使者三首  其二','李新','宋','宋诗','song-poetry','','[]','玉翰飛過漢江東，蜀道三年興已窮。',64,'全唐诗/poet.song.70000.json','["玉翰飛過漢江東，蜀道三年興已窮。", "明日登山臨水去，故園啼鳥落花空。", "聞今自草延英奏，合下人推長者風。", "燕麥兔葵初亂眼，欲將修翼問歸鴻。"]'),
('7d2f32f8-f1f7-42a9-9173-8fbf33e8e141','送錢使者三首  其三','李新','宋','宋诗','song-poetry','','[]','翠羽頒書出紫皇，殘春岐路日初長。',64,'全唐诗/poet.song.70000.json','["翠羽頒書出紫皇，殘春岐路日初長。", "花容帖雨蜂兒靜，麥浪翻風燕子涼。", "八葉世家方越古，二王振鷺已成行。", "行行才業知多少，千里吳天水滿塘。"]'),
('3dc677c1-4ac4-481c-bb3f-b7d44cb0cc7f','簡任安中','李新','宋','宋诗','song-poetry','','[]','邊公春夢晝悠揚，借有新嘲不汝妨。',64,'全唐诗/poet.song.70000.json','["邊公春夢晝悠揚，借有新嘲不汝妨。", "杖屨未經桃李樹，棹歌空憶水雲鄉。", "子規啼去花應好，燕子歸來日漸長。", "稍學淵明惜名酒，掃除齋閣待君嘗。"]'),
('116cff11-db65-49f7-b4a0-1621454e4175','神泉道中寄李道明','李新','宋','宋诗','song-poetry','','[]','野鳥啼春稍覺空，馬蹄何故萬山中。',64,'全唐诗/poet.song.70000.json','["野鳥啼春稍覺空，馬蹄何故萬山中。", "樹連土雨微茫綠，花入麥秋零亂紅。", "北阮不知貧氣味，謫仙元有舊家風。", "正須洗出青青目，看取新來塞上翁。"]'),
('46955483-655c-4f89-ac6d-8a012cfeb15d','題普州東溪','李新','宋','宋诗','song-poetry','','[]','參軍龍鍾大可笑，清聖寂寞何所中。',64,'全唐诗/poet.song.70000.json','["參軍龍鍾大可笑，清聖寂寞何所中。", "往事幾隨山影轉，此生元與浪花同。", "金鑾視草人安在，曲水流觴迹已空。", "早晚北風吹得去，欲參雲漢問鴻濛。"]'),
('57dfbed0-e706-47b1-9a34-29908a6e79bd','送許東傳  其一','李新','宋','宋诗','song-poetry','','[]','碧霄已覺少微明，帝所行看召老成。',64,'全唐诗/poet.song.70000.json','["碧霄已覺少微明，帝所行看召老成。", "好夢謾依淮水去，秋風空見雪山輕。", "衣冠幾許披雲霧，父老于今識弟兄。", "黄閣他年開月旦，想公終不解忘情。"]'),
('d9ff91ef-108b-4c3f-bc15-725502ceb646','送許東傳  其二','李新','宋','宋诗','song-poetry','','[]','轉蓬孤鶴昔流人，千里樓西客此身。',64,'全唐诗/poet.song.70000.json','["轉蓬孤鶴昔流人，千里樓西客此身。", "江海相忘魚自樂，雪霜已過樹回春。", "長安索米非方朔，谷口耕雲待子真。", "收拾從來憂國泪，太平無復事沾巾。"]'),
('0484c5b1-3874-48ce-baf1-d1b3987cce07','送元播','李新','宋','宋诗','song-poetry','','[]','恩光渺渺似涪波，濕雪欺梅奈别何。',64,'全唐诗/poet.song.70000.json','["恩光渺渺似涪波，濕雪欺梅奈别何。", "歛盡寒威離兩蜀，播將春色入三河。", "輕裝舊槖黄金少，故國新豐美酒多。", "不負一生經濟術，他年元鼎解調和。"]'),
('11f15b9a-2c0f-4e1a-8815-0c99963e929c','送李才儒  其一','李新','宋','宋诗','song-poetry','','[]','未覺鄉關歲月深，轉山旗影緩愔愔。',64,'全唐诗/poet.song.70000.json','["未覺鄉關歲月深，轉山旗影緩愔愔。", "遠人願見喬卿服，支邑曾隨子賤琴。", "攄散幽陰千古恨，發明忠義一生心。", "冰清不屈二天庇，雨化寧逢三日霖。"]'),
('27dba897-c56b-4320-8f91-c12ef65dd874','送李才儒  其二','李新','宋','宋诗','song-poetry','','[]','理官食木遙遙胄，一姓而今萬頃麻。',64,'全唐诗/poet.song.70000.json','["理官食木遙遙胄，一姓而今萬頃麻。", "渾道婁公能耐事，惟餘老子未通家。", "行經閶闔雲生足，歸到方壺雪弄花。", "休丐一麾江海去，且扶堯日度清華。"]'),
('ff261f2a-0c08-4a9d-8214-9e3aa0574cd5','送邵馬勾二首  其一','李新','宋','宋诗','song-poetry','','[]','飄零愁殺病參軍，點點黄泥漬帽裙。',64,'全唐诗/poet.song.70000.json','["飄零愁殺病參軍，點點黄泥漬帽裙。", "藏火解銷秦地鐵，騎驢重數華山雲。", "兒號惟有韓司業，官冷誰憐鄭廣文。", "身世泡漚渾道得，請君一笑北邙墳。"]'),
('f8ac31af-3965-4fc0-819d-9264a6aba1f2','送邵馬勾二首  其二','李新','宋','宋诗','song-poetry','','[]','芳菊江藜泣冷煙，秋風秋雨老行鞭。',64,'全唐诗/poet.song.70000.json','["芳菊江藜泣冷煙，秋風秋雨老行鞭。", "嘗依故國横經笥，猶憶南堂乞火仙。", "月瘴稍昏斜谷路，漁竿空倚北谿船。", "有錢他日鄰枌社，待覓嵩陰一頃田。"]'),
('ef31ec7a-8f38-41ec-87d4-7d906c17f5ee','送周晉叔','李新','宋','宋诗','song-poetry','','[]','妙齡壁水興何窮，投筆幡然定遠功。',64,'全唐诗/poet.song.70000.json','["妙齡壁水興何窮，投筆幡然定遠功。", "寶仗初依金碧輅，鐵鞭閒靜海連風。", "萱堂歸去椒觴近，珠珮收來漢月空。", "明日紫騮嘶曉雪，故人端在亂山中。"]'),
('d0b7deb5-3950-4bf9-8f57-527c3fe78d00','送邵子文','李新','宋','宋诗','song-poetry','','[]','柳映平橋路带沙，行人歸思浩無涯。',64,'全唐诗/poet.song.70000.json','["柳映平橋路带沙，行人歸思浩無涯。", "臨岐蕭寺瑣蒼竹，催客杜鵑啼落花。", "千里亂山雲自暗，一谿流水日空斜。", "伊予最是多情者，爲拂前題置碧紗。"]'),
('6a83caa5-3e91-4e73-bf31-fc9d8a90ad4b','送劉漢特兼簡邵子文','李新','宋','宋诗','song-poetry','','[]','綠篠欹墻葉葉聲，夜涼風細露華清。',64,'全唐诗/poet.song.70000.json','["綠篠欹墻葉葉聲，夜涼風細露華清。", "飄零何幸逢公子，邂逅相看不世情。", "擬向伯倫求酒頌，不知東野解詩鳴。", "三峰峰下文章伯，應憶當年阮步兵。"]'),
('13115001-4bc3-4cdb-be96-45a8e9f74d99','婦嘲','李新','宋','宋诗','song-poetry','','[]','歲晚隨君色色無，嫁時我自有瓊琚。',64,'全唐诗/poet.song.70000.json','["歲晚隨君色色無，嫁時我自有瓊琚。", "借令值客休捫蝨，幸未能詩勿跨驢。", "寧與漁樵安舊隱，莫言封禪著新書。", "夜寒憎見牛衣泣，起執晨炊觸釜魚。"]'),
('b6ccd01f-037f-4ea1-a48c-fe7a4e0aaab6','藥水巖','李新','宋','宋诗','song-poetry','','[]','巖前曾考腐斤樵，洞裏仙人不可招。',64,'全唐诗/poet.song.70000.json','["巖前曾考腐斤樵，洞裏仙人不可招。", "龍睡有時慳小雨，春長無地覓靈苖。", "與攻中散平時懶，更沃文園異日消。", "調鼎和羮須玉液，預私清泚注輕瓢。"]'),
('a2226513-5df0-41f9-abaa-cbdf2d965577','陋夷','李新','宋','宋诗','song-poetry','','[]','療饑寧採故丘薇，真陋羌夷詎可依。',64,'全唐诗/poet.song.70000.json','["療饑寧採故丘薇，真陋羌夷詎可依。", "火日四山猶墮雪，鬼林六月不單衣。", "藥殘花蕚歸方冊，狨老金絲觸禍機。", "倒指瓜期今已足，早修雲翼背西飛。"]'),
('0d2bf8d8-5152-4031-b554-12065e25074b','宋隱君挽詞','李新','宋','宋诗','song-poetry','','[]','貴口輕翾意自融，鳴柯芥羽逐春風。',64,'全唐诗/poet.song.70000.json','["貴口輕翾意自融，鳴柯芥羽逐春風。", "猗歟宋氏青雲器，師我緇川白髪翁。", "沃壤可彰千載義，舊窗空負一生功。", "新阡無用栽凡木，待看奇才長碧桐。"]'),
('93261c5e-d6b6-43ff-9d79-b630ebdb4151','蒲静安挽詞','李新','宋','宋诗','song-poetry','','[]','舞鸞雛鵠已先飛，曾倚西山泣晚暉。',64,'全唐诗/poet.song.70000.json','["舞鸞雛鵠已先飛，曾倚西山泣晚暉。", "老去兒孫雄北阮，古來門戶占烏衣。", "蕭蕭華髪猶供祭，歷歷清談又解圍。", "洞口仙人招白鶴，玉翰何日與雲歸。"]');
